WATCHLIST_FILENAME = "cockpit_watchlist.json"
WATCHLIST_SEC_FILINGS_FILENAME = "watchlist_sec_filings.json"


def _latest_file(data_dir: Path, pattern: str) -> Path | None:
    files = [p for p in data_dir.glob(pattern) if p.is_file()]
    if not files:
        return None
    return max(files, key=lambda p: (p.stat().st_mtime, p.name))


def _read_json(path: Path) -> Any:
    try:
        return json.loads(path.read_text(encoding="utf-8-sig"))
    except Exception:
        return None


def _count_json_rows(path: Path) -> int:
    rows = _read_json(path)
    return len(rows) if isinstance(rows, list) else 0


def _direct_open_counts(data_dir: Path) -> dict[str, int]:
    return {
        "options": _count_json_rows(data_dir / "open_positions.json"),
        "shares": _count_json_rows(data_dir / "open_share_positions.json"),
        "futures": _count_json_rows(data_dir / "open_futures_positions.json"),
    }


def _snapshot_age_minutes(path: Path) -> float:
    modified = datetime.fromtimestamp(path.stat().st_mtime, UTC)
    return max(0.0, (datetime.now(UTC) - modified).total_seconds() / 60.0)


def _snapshot_freshness(age_minutes: float | None) -> str:
    if age_minutes is None:
        return "unknown"
    if age_minutes <= FRESH_SNAPSHOT_MINUTES:
        return "fresh"
    if age_minutes <= STALE_SNAPSHOT_MINUTES:
        return "aging"
    return "stale"


def _worst_snapshot_freshness(left: Any, right: Any) -> str:
    severity = {"unknown": 0, "fresh": 1, "aging": 2, "stale": 3}
    left_norm = str(left or "unknown").strip().lower()
    right_norm = str(right or "unknown").strip().lower()
    if left_norm not in severity:
        left_norm = "unknown"
    if right_norm not in severity:
        right_norm = "unknown"
    return left_norm if severity[left_norm] >= severity[right_norm] else right_norm


def _parse_iso_utc(value: Any) -> datetime | None:
    text = str(value or "").strip()
    if not text:
        return None
    text = text.replace("Z", "+00:00")
    try:
        dt = datetime.fromisoformat(text)
    except Exception:
        parsed = pd.to_datetime(text, errors="coerce", utc=True)
        if pd.isna(parsed):
            return None
        dt = parsed.to_pydatetime()
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=UTC)
    return dt.astimezone(UTC)


def _iso_age_minutes(value: Any) -> float | None:
    dt = _parse_iso_utc(value)
    if dt is None:
        return None
    delta_seconds = (datetime.now(UTC) - dt).total_seconds()
    if delta_seconds < -300:
        return None
    return max(0.0, delta_seconds / 60.0)


def _short_age_label(age_minutes: float | None) -> str:
    if age_minutes is None:
        return "missing"
    if age_minutes < 1:
        return "<1m"
    if age_minutes < 120:
        return f"{age_minutes:.0f}m"
    return f"{age_minutes / 60.0:.1f}h"


def _agentic_freshness(age_minutes: float | None) -> str:
    if age_minutes is None:
        return "missing"
    if age_minutes <= AGENTIC_FRESH_MINUTES:
        return "fresh"
    if age_minutes <= AGENTIC_STALE_MINUTES:
        return "aging"
    return "stale"


def _read_parquet(path: Path | None) -> pd.DataFrame:
    if path is None:
        return pd.DataFrame()
    try:
        df = pd.read_parquet(path)
    except Exception:
        return pd.DataFrame()
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "mispricing_pct" in out.columns:
        try:
            from backtest.sizing import add_directional_option_edges

            out = add_directional_option_edges(out)
        except Exception:
            pass
    age = _snapshot_age_minutes(path)
    file_freshness = _snapshot_freshness(age)
    out["_source_file"] = path.name
    if "snapshot_age_min" in out.columns:
        row_age = pd.to_numeric(out["snapshot_age_min"], errors="coerce")
        out["snapshot_age_min"] = row_age.fillna(age).clip(lower=age).round(1)
    else:
        out["snapshot_age_min"] = round(age, 1)
    if "snapshot_freshness" in out.columns:
        out["snapshot_freshness"] = out["snapshot_freshness"].apply(
            lambda value: _worst_snapshot_freshness(value, file_freshness)
        )
    else:
        out["snapshot_freshness"] = file_freshness
    return out


def _file_meta(path: Path | None) -> dict[str, Any] | None:
    if path is None or not path.exists() or not path.is_file():
        return None
    stat = path.stat()
    modified = datetime.fromtimestamp(stat.st_mtime, UTC)
    age_minutes = max(0.0, (datetime.now(UTC) - modified).total_seconds() / 60.0)
    return {
        "name": path.name,
        "path": str(path),
        "size_bytes": int(stat.st_size),
        "modified_at": modified.isoformat(),
        "age_minutes": round(age_minutes, 1),
    }


def _png_validation_error(path: Path | None) -> str | None:
    """Return a short error if a PNG is missing/corrupt, otherwise None."""
    if path is None or not path.exists() or not path.is_file():
        return "missing"
    try:
        data = path.read_bytes()
    except Exception as exc:
        return f"could not read: {exc}"
    if len(data) < 12 or not data.startswith(b"\x89PNG\r\n\x1a\n"):
        return "not a PNG"
    offset = 8
    saw_iend = False
    while offset + 8 <= len(data):
        try:
            length = struct.unpack(">I", data[offset : offset + 4])[0]
        except Exception:
            return "invalid chunk length"
        chunk_type = data[offset + 4 : offset + 8]
        offset += 8
        chunk_end = offset + length
        crc_end = chunk_end + 4
        if crc_end > len(data):
            return f"truncated {chunk_type.decode('ascii', errors='replace')} chunk"
        chunk = data[offset:chunk_end]
        expected = struct.unpack(">I", data[chunk_end:crc_end])[0]
        actual = binascii.crc32(chunk_type + chunk) & 0xFFFFFFFF
        if actual != expected:
            name = chunk_type.decode("ascii", errors="replace")
            return f"{name} CRC mismatch"
        offset = crc_end
        if chunk_type == b"IEND":
            saw_iend = True
            break
    if not saw_iend:
        return "missing IEND chunk"
    return None


def _clean_value(value: Any) -> Any:
    try:
        if value is None or pd.isna(value):
            return None
    except Exception:
        pass
    if isinstance(value, float) and not math.isfinite(value):
        return None
    if hasattr(value, "item"):
        try:
            return value.item()
        except Exception:
            pass
    return value


def _clean_watchlist_context(context: Any) -> dict[str, Any]:
    if not isinstance(context, dict):
        return {}
    cleaned: dict[str, Any] = {}
    for key in CHAIN_CONTEXT_FIELDS:
        if key not in context:
            continue
        value = context.get(key)
        if isinstance(value, list):
            items = []
            for item in value[:8]:
                clean = _clean_value(item)
                if isinstance(clean, str):
                    clean = clean[:220]
                if clean is None or isinstance(clean, (str, int, float, bool)):
                    items.append(clean)
            if items:
                cleaned[key] = items
            continue
        clean_value = _clean_value(value)
        if isinstance(clean_value, str):
            clean_value = clean_value[:700]
        if clean_value is None or isinstance(clean_value, (str, int, float, bool)):
            cleaned[key] = clean_value
    if cleaned:
        cleaned["saved_from"] = "option_chain_scan"
        cleaned["saved_context_at"] = _now_iso()
    return cleaned


def _float_value(value: Any, default: float = 0.0) -> float:
    if isinstance(value, bool):
        return default
    try:
        out = float(value)
    except Exception:
        return default
    return out if math.isfinite(out) else default


def _optional_float_value(value: Any) -> float | None:
    number = _float_value(value, default=math.nan)
    return number if math.isfinite(number) else None


def _position_identity(row: dict[str, Any]) -> tuple:
    pid = row.get("position_id")
    if pid:
        return ("id", str(pid))
    return (
        str(row.get("asset") or ""),
        str(row.get("ticker") or row.get("symbol") or row.get("ticker_or_symbol") or ""),
        str(row.get("side") or row.get("direction") or row.get("side_or_direction") or ""),
        str(row.get("strike") or row.get("contract") or row.get("strike_or_contract") or ""),
        str(row.get("expiry") or ""),
        str(row.get("entry_time") or ""),
        str(row.get("entry_price") or ""),
    )


def _dedupe_position_rows(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen = set()
    out = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        key = _position_identity(row)
        if key in seen:
            continue
        seen.add(key)
        out.append(row)
    return out


def _now_iso() -> str:
    return datetime.now(UTC).isoformat()


def _watchlist_file(data_dir: Path = DATA_DIR) -> Path:
    return Path(data_dir) / WATCHLIST_FILENAME


def _safe_id(value: Any) -> str:
    text = str(value or "").strip()
    safe = "".join(ch if ch.isalnum() or ch in {"_", "-", "=", "."} else "_" for ch in text)
    return safe[:96] or "item"


def _watchlist_entry_id(resolution: dict[str, Any], query: str) -> str:
    symbol = str(resolution.get("symbol") or query).upper()
    request = resolution.get("request") or {}
    if request:
        raw = (
            f"{symbol}_{request.get('side', '')}_{request.get('expiry', '')}_"
            f"{request.get('strike', '')}"
        )
    else:
        raw = symbol
    return _safe_id(raw)


def _watchlist_lookup_query(entry: dict[str, Any]) -> str:
    if entry.get("request"):
        return str(entry.get("query") or entry.get("symbol") or "").strip()
    return str(entry.get("symbol") or entry.get("query") or "").strip()


def _enrich_watchlist_entry(entry: dict[str, Any], data_dir: Path) -> dict[str, Any]:
    out = dict(entry)
    query = _watchlist_lookup_query(entry)
    if not query:
        return out
    try:
        report = lookup_symbol(
            query,
            data_dir,
            include_sec=False,
            queue_broker_request=False,
        )
        brief = report.get("brief") or {}
        best = brief.get("best_idea") or {}
        open_pos = brief.get("open_positions") or {}
        readiness = brief.get("paper_readiness") or {}
        swing = brief.get("swing_verdict") or {}
        alternatives = brief.get("option_alternatives") or {}
        comparison = brief.get("contract_comparison") or {}
        readiness_checks = (
            readiness.get("checks") if isinstance(readiness.get("checks"), list) else []
        )
        out.update(
            {
                "local_hits": _clean_value(report.get("total_hits")),
                "best_idea": _clean_value(best.get("label")),
                "best_status": _clean_value(best.get("trade_status")),
                "best_confidence": _clean_value(best.get("confidence")),
                "best_score": _clean_value(best.get("score")),
                "paper_readiness_status": _clean_value(readiness.get("status")),
                "paper_readiness_label": _clean_value(readiness.get("label")),
                "paper_readiness_score": _clean_value(readiness.get("score")),
                "paper_readiness_bad_count": sum(
                    1 for row in readiness_checks if row.get("level") == "bad"
                ),
                "paper_readiness_warn_count": sum(
                    1 for row in readiness_checks if row.get("level") == "warn"
                ),
                "option_alt_count": _clean_value(alternatives.get("count")),
                "option_alt_best": _clean_value(alternatives.get("best_label")),
                "option_alt_reason": _clean_value(alternatives.get("best_reason")),
                "option_alt_score": _clean_value(alternatives.get("best_score")),
                "option_alt_readiness": _clean_value(alternatives.get("best_readiness_score")),
                "option_alt_swing_fit": _clean_value(alternatives.get("best_swing_fit_score")),
                "option_alt_spread_pct": _clean_value(alternatives.get("best_spread_pct")),
                "contract_pick_label": _clean_value(comparison.get("label")),
                "contract_pick_winner": _clean_value(comparison.get("winner")),
                "contract_pick_score": _clean_value(comparison.get("edge_score")),
                "contract_pick_reasons": _clean_value(comparison.get("reasons")),
                "swing_verdict_label": _clean_value(swing.get("label")),
                "swing_verdict_score": _clean_value(swing.get("score")),
                "swing_verdict_decision": _clean_value(swing.get("decision")),
                "swing_verdict_bias": _clean_value(swing.get("bias")),
                "swing_verdict_risk_reward": _clean_value(swing.get("risk_reward")),
                "swing_verdict_playbook": _clean_value(swing.get("playbook")),
                "swing_verdict_blockers": _clean_value(swing.get("blockers")),
                "swing_verdict_reasons": _clean_value(swing.get("reasons")),
                "open_count": _clean_value(open_pos.get("count")),
                "avg_unrealized_pct": _clean_value(open_pos.get("avg_unrealized_pct")),
                "max_exit_pressure": _clean_value(open_pos.get("max_exit_pressure")),
                "warning_count": len(brief.get("risk_warnings") or []),
                "last_enriched_at": _now_iso(),
            }
        )
    except Exception as exc:
        out["enrichment_error"] = str(exc)[:180]
    return out


def _watchlist_sort_key(row: dict[str, Any]) -> tuple[int, float, float, float, str]:
    status_rank = {
        "ready": 3,
        "caution": 2,
        "blocked": 1,
    }.get(str(row.get("paper_readiness_status") or "").lower(), 0)
    return (
        status_rank,
        _float_value(row.get("paper_readiness_score"), 0.0),
        _float_value(row.get("swing_verdict_score"), 0.0),
        _float_value(row.get("option_alt_score"), 0.0),
        _float_value(row.get("max_exit_pressure"), 0.0),
        _float_value(row.get("best_score"), 0.0),
        str(row.get("updated_at") or row.get("added_at") or ""),
    )


@_memoized_report
def load_watchlist(data_dir: Path = DATA_DIR, enrich: bool = False) -> dict[str, Any]:
    rows = _read_json(_watchlist_file(data_dir))
    if not isinstance(rows, list):
        rows = []
    cleaned: list[dict[str, Any]] = []
    seen = set()
    for row in rows:
        if not isinstance(row, dict):
            continue
        item_id = str(row.get("id") or "").strip()
        if not item_id or item_id in seen:
            continue
        seen.add(item_id)
        cleaned.append(row)
    entries = (
        [_enrich_watchlist_entry(row, Path(data_dir)) for row in cleaned] if enrich else cleaned
    )
    if enrich:
        entries = sorted(entries, key=_watchlist_sort_key, reverse=True)
    return {
        "generated_at": _now_iso(),
        "count": len(entries),
        "enriched": enrich,
        "entries": entries,
        "path": str(_watchlist_file(data_dir)),
        "notes": [
            "Watchlist entries are local research targets only.",
            "Enriched watchlists read the latest local scan snapshots and open positions.",
            "Run all launches focused scans for resolved symbols; no trades are placed.",
        ],
    }


def _parse_date_yyyy_mm_dd(value: Any) -> datetime | None:
    text = str(value or "").strip()
    if not text:
        return None
    try:
        return datetime.fromisoformat(text[:10]).replace(tzinfo=UTC)
    except Exception:
        return None


def _sec_filing_priority(form: Any, signal: Any, days_old: int | None) -> tuple[int, str]:
    clean_form = str(form or "").upper().strip()
    clean_signal = str(signal or "").strip().lower()
    base = {
        "S-1": 96,
        "S-3": 94,
        "424B5": 94,
        "424B2": 90,
        "8-K": 86,
        "SC 13D": 82,
        "SC 13G": 76,
        "10-Q": 72,
        "10-K": 70,
        "4": 66,
    }.get(clean_form, 55)
    if "dilution" in clean_signal or "offering" in clean_signal:
        base = max(base, 94)
    elif "material_event" in clean_signal:
        base = max(base, 86)
    elif "ownership_change" in clean_signal:
        base = max(base, 78)
    if days_old is None:
        return max(40, base - 8), "date_unknown"
    if days_old <= 3:
        return min(100, base + 5), "fresh"
    if days_old <= 14:
        return base, "recent"
    if days_old <= 45:
        return max(35, int(base - days_old * 0.7)), "aging"
    return max(20, int(base - days_old * 0.9)), "old"


def build_watchlist_sec_filings(data_dir: Path = DATA_DIR, limit: int = 40) -> dict[str, Any]:
    """Build a no-key SEC recent-filing monitor for saved research targets."""
    limit = max(1, min(int(limit or 40), 120))
    watchlist = load_watchlist(data_dir, enrich=False)
    symbols: list[str] = []
    seen = set()
    for row in watchlist.get("entries", []):
        symbol = str(row.get("symbol") or "").upper().strip()
        if not symbol or symbol in seen:
            continue
        seen.add(symbol)
        symbols.append(symbol)

    rows: list[dict[str, Any]] = []
    errors: list[dict[str, str]] = []
    today = datetime.now(UTC)
    for symbol in symbols[:60]:
        try:
            report = recent_filings_for_symbol(symbol, limit=8)
        except Exception as exc:
            errors.append({"symbol": symbol, "error": str(exc)[:180]})
            continue
        filings = report.get("rows", []) if isinstance(report, dict) else []
        for filing in filings:
            if not isinstance(filing, dict):
                continue
            filing_date = _parse_date_yyyy_mm_dd(filing.get("filing_date"))
            days_old = (today.date() - filing_date.date()).days if filing_date else None
            priority, freshness = _sec_filing_priority(
                filing.get("form"),
                filing.get("filing_signal"),
                days_old,
            )
            rows.append(
                {
                    "priority": priority,
                    "ticker": symbol,
                    "company_name": filing.get("company_name") or report.get("company_name"),
                    "form": filing.get("form"),
                    "filing_date": filing.get("filing_date"),
                    "days_old": days_old,
                    "freshness": freshness,
                    "signal": filing.get("filing_signal"),
                    "description": filing.get("description"),
                    "url": filing.get("url"),
                }
            )

    rows = sorted(
        rows,
        key=lambda row: (
            _float_value(row.get("priority"), default=0.0),
            str(row.get("filing_date") or ""),
        ),
        reverse=True,
    )[:limit]
    signal_counts: dict[str, int] = {}
    form_counts: dict[str, int] = {}
    for row in rows:
        signal = str(row.get("signal") or "unknown")
        form = str(row.get("form") or "unknown")
        signal_counts[signal] = signal_counts.get(signal, 0) + 1
        form_counts[form] = form_counts.get(form, 0) + 1

    fresh_count = sum(_float_value(row.get("days_old"), default=9999.0) <= 14 for row in rows)
    high_impact_count = sum(
        str(row.get("signal") or "")
        in {
            "dilution_or_offering_watch",
            "material_event_review",
            "ownership_change_review",
            "fundamental_update_review",
        }
        for row in rows
    )
    payload = {
        "generated_at": _now_iso(),
        "symbols_checked": len(symbols),
        "filing_count": len(rows),
        "fresh_count": fresh_count,
        "high_impact_count": high_impact_count,
        "error_count": len(errors),
        "form_counts": form_counts,
        "signal_counts": signal_counts,
        "rows": [{k: _clean_value(v) for k, v in row.items()} for row in rows],
        "errors": errors,
        "notes": [
            "SEC Filing Monitor uses the official no-key SEC submissions API.",
            "It watches saved research targets only, so it stays focused and polite to public sources.",
            "Filings are review prompts, not automatic trade entries or exits.",
        ],
    }
    try:
        data_dir.mkdir(parents=True, exist_ok=True)
        (data_dir / WATCHLIST_SEC_FILINGS_FILENAME).write_text(
            json.dumps(payload, indent=2, sort_keys=True),
            encoding="utf-8",
        )
    except Exception:
        pass
    return payload


def _request_dte(expiry: Any) -> int | None:
    exp = pd.to_datetime(str(expiry or ""), errors="coerce", utc=True)
    if pd.isna(exp):
        return None
    return int((exp.date() - datetime.now(UTC).date()).days)


def _saved_contract_status(dte: int | None, readiness: Any) -> str:
    if dte is None:
        return "needs_expiry_check"
    if dte < 0:
        return "expired"
    if dte < MIN_SWING_OPTION_DTE:
        return "below_3m"
    ready = str(readiness or "").strip().lower()
    if ready == "ready":
        return "ready_review"
    if ready in {"caution", "blocked"}:
        return ready
    return "saved_review"


def _norm_option_side(value: Any) -> str:
    side = str(value or "").strip().lower()
    if side in {"c", "call", "calls"}:
        return "call"
    if side in {"p", "put", "puts"}:
        return "put"
    return side


def _saved_contract_quote_snapshot(
    symbol: str, request: dict[str, Any], dte: int | None
) -> dict[str, Any]:
    ticker = str(symbol or request.get("ticker") or "").upper()
    expiry = str(request.get("expiry") or "").strip()
    side = _norm_option_side(request.get("side"))
    strike = _float_value(request.get("strike"), default=math.nan)
    if not ticker or not expiry or side not in {"call", "put"} or not math.isfinite(strike):
        return {"quote_status": "invalid_request", "quote_checked_at": _now_iso()}

    try:
        blob = _fetch_option_chain(ticker, cache_age=300)
    except Exception as exc:
        return {
            "quote_status": "fetch_failed",
            "quote_error": str(exc)[:160],
            "quote_checked_at": _now_iso(),
        }
    chains = blob.get("chains") if isinstance(blob, dict) else None
    chain_df = chains.get(expiry) if isinstance(chains, dict) else None
    if not isinstance(chain_df, pd.DataFrame) or chain_df.empty:
        return {
            "quote_status": "missing_expiry",
            "chain_source": _clean_value(blob.get("source")) if isinstance(blob, dict) else None,
            "quote_quality": _clean_value(blob.get("quote_quality"))
            if isinstance(blob, dict)
            else None,
            "quote_checked_at": _now_iso(),
        }

    matches = []
    for _, raw in chain_df.iterrows():
        raw_side = _norm_option_side(raw.get("side"))
        raw_strike = _float_value(raw.get("strike"), default=math.nan)
        if raw_side == side and math.isfinite(raw_strike) and abs(raw_strike - strike) <= 0.0001:
            matches.append(raw)
    if not matches:
        return {
            "quote_status": "missing_contract",
            "chain_source": _clean_value(blob.get("source")) if isinstance(blob, dict) else None,
            "quote_quality": _clean_value(blob.get("quote_quality"))
            if isinstance(blob, dict)
            else None,
            "quote_checked_at": _now_iso(),
        }

    best = sorted(
        matches,
        key=lambda row: (
            _float_value(row.get("openInterest"), default=0.0),
            _float_value(row.get("volume"), default=0.0),
        ),
        reverse=True,
    )[0]
    mid = _option_mid(best)
    spread_pct = _option_spread_pct(best, mid)
    spot = _float_value(blob.get("spot"), default=math.nan) if isinstance(blob, dict) else math.nan
    moneyness = (
        ((strike - spot) / spot)
        if math.isfinite(strike) and math.isfinite(spot) and spot > 0
        else None
    )
    quote_quality = (
        (
            blob.get("quote_quality")
            or (
                "live_or_broker"
                if str(blob.get("source") or "") == "tradier"
                else "free_or_delayed"
            )
        )
        if isinstance(blob, dict)
        else "unknown"
    )
    quote_row = {
        "symbol": ticker,
        "side": side,
        "expiry": expiry,
        "dte": dte,
        "strike": strike,
        "bid": _clean_value(best.get("bid")),
        "ask": _clean_value(best.get("ask")),
        "mid": round(mid, 4) if math.isfinite(mid) else None,
        "premium_dollars": round(mid * 100.0, 2) if math.isfinite(mid) else None,
        "spread_pct": _clean_value(spread_pct),
        "volume": int(_float_value(best.get("volume"), default=0.0)),
        "openInterest": int(_float_value(best.get("openInterest"), default=0.0)),
        "impliedVolatility": _clean_value(best.get("impliedVolatility")),
        "delta": _clean_value(best.get("delta")),
        "moneyness_pct": _clean_value(moneyness),
    }
    quote_row["contract_quality_score"] = round(_option_chain_score(quote_row), 3)
    quote_row.update(_option_contract_readiness(quote_row, str(quote_quality)))
    return {
        "quote_status": "matched",
        "quote_checked_at": _now_iso(),
        "chain_source": _clean_value(blob.get("source")) if isinstance(blob, dict) else None,
        "quote_quality": _clean_value(quote_quality),
        "current_mid": quote_row["mid"],
        "current_bid": quote_row["bid"],
        "current_ask": quote_row["ask"],
        "current_premium_dollars": quote_row["premium_dollars"],
        "current_spread_pct": quote_row["spread_pct"],
        "current_volume": quote_row["volume"],
        "current_open_interest": quote_row["openInterest"],
        "current_iv": quote_row["impliedVolatility"],
        "current_delta": quote_row["delta"],
        "quote_readiness_label": quote_row["readiness_label"],
        "quote_readiness_score": quote_row["readiness_score"],
        "quote_flags": quote_row["risk_flags"],
        "contract_quality_score": quote_row["contract_quality_score"],
    }


def _saved_contract_review(row: dict[str, Any]) -> dict[str, Any]:
    score = 100
    reasons: list[str] = []
    dte = _float_value(row.get("dte"), default=math.nan)
    quote_status = str(row.get("quote_status") or "not_checked")
    spread = _float_value(row.get("current_spread_pct"), default=math.nan)
    quote_score = _float_value(row.get("quote_readiness_score"), default=math.nan)
    quote_label = str(row.get("quote_readiness_label") or "").lower()
    paper_status = str(row.get("paper_readiness") or row.get("status") or "").lower()
    warnings = _float_value(row.get("warning_count"), default=0.0)
    saved_grade = str(row.get("saved_contract_grade") or "").upper()

    if not math.isfinite(dte):
        score -= 25
        reasons.append("expiry needs review")
    elif dte < 0:
        score -= 100
        reasons.append("expired")
    elif dte < MIN_SWING_OPTION_DTE:
        score -= 35
        reasons.append("below 90 DTE")
    else:
        reasons.append("3m+ DTE")

    if quote_status == "matched":
        reasons.append("quote matched")
    elif quote_status == "not_checked":
        score -= 18
        reasons.append("refresh quote first")
    elif quote_status == "not_checked_limit":
        score -= 16
        reasons.append("quote refresh limit")
    else:
        score -= 35
        reasons.append(str(quote_status).replace("_", " "))

    if math.isfinite(spread):
        if spread > 0.25:
            score -= 30
            reasons.append(f"spread {spread * 100:.1f}%")
        elif spread > 0.15:
            score -= 15
            reasons.append(f"spread {spread * 100:.1f}%")
        else:
            reasons.append(f"spread {spread * 100:.1f}%")
    elif quote_status == "matched":
        score -= 12
        reasons.append("spread missing")

    if math.isfinite(quote_score):
        if quote_score < 65:
            score -= 18
            reasons.append(f"quote score {quote_score:g}")
        elif quote_score >= 80:
            reasons.append(f"quote score {quote_score:g}")
    if saved_grade in {"A", "B"}:
        reasons.append(f"saved grade {saved_grade}")
    elif saved_grade == "D":
        score -= 8
        reasons.append("saved grade D")
    if quote_label == "wait":
        score -= 20
        reasons.append("quote readiness wait")
    if "blocked" in paper_status:
        score -= 15
        reasons.append("local readiness blocked")
    if warnings >= 5:
        score -= 10
        reasons.append(f"{int(warnings)} local warning(s)")

    clean_score = max(0, min(100, int(round(score))))
    if clean_score >= 80 and quote_status == "matched":
        action = "review_now"
    elif quote_status != "matched":
        action = "refresh_quote"
    elif clean_score >= 60:
        action = "watch"
    else:
        action = "wait"
    return {
        "review_score": clean_score,
        "review_action": action,
        "review_reasons": reasons[:6],
    }


def _saved_grade_rank(value: Any) -> int:
    return {"A": 4, "B": 3, "C": 2, "D": 1}.get(str(value or "").upper(), 0)


def _saved_contract_triage(row: dict[str, Any]) -> dict[str, Any]:
    score = _float_value(row.get("review_score"), default=50.0)
    reasons: list[str] = []
    grade = str(row.get("saved_contract_grade") or "").upper()
    quote_status = str(row.get("quote_status") or "not_checked")
    review_action = str(row.get("review_action") or "")
    dte = _float_value(row.get("dte"), default=math.nan)
    spread = _float_value(row.get("current_spread_pct"), default=math.nan)
    if not math.isfinite(spread):
        spread = _float_value(row.get("saved_spread_pct"), default=math.nan)
    saved_quality = _float_value(row.get("saved_contract_quality_score"), default=math.nan)

    if grade == "A":
        score += 8
        reasons.append("A-grade chain save")
    elif grade == "B":
        score += 4
        reasons.append("B-grade chain save")
    elif grade == "D":
        score -= 10
        reasons.append("D-grade save")

    if quote_status == "matched":
        score += 6
        reasons.append("quote refreshed")
    else:
        reasons.append("needs quote refresh")

    if math.isfinite(dte):
        if dte < 0:
            score = 0
            reasons.append("expired")
        elif dte < MIN_SWING_OPTION_DTE:
            score -= 25
            reasons.append("below 90 DTE")
        elif dte >= 180:
            score += 3
            reasons.append("long-dated")
        else:
            reasons.append("3m+ swing")

    if math.isfinite(spread):
        if spread <= 0.10:
            score += 5
            reasons.append("tight spread")
        elif spread <= 0.20:
            reasons.append("acceptable spread")
        else:
            score -= 12
            reasons.append("wide spread")

    if math.isfinite(saved_quality) and saved_quality >= 80:
        score += 3
        reasons.append("strong saved quality")

    clean_score = max(0, min(100, int(round(score))))
    if math.isfinite(dte) and dte < 0:
        bucket = "expired"
        label = "Expired"
    elif quote_status != "matched":
        bucket = "refresh_quote"
        label = "Refresh Quote"
    elif review_action == "review_now" or clean_score >= 85:
        bucket = "ready_now"
        label = "Ready Review"
    elif clean_score >= 70:
        bucket = "shortlist"
        label = "Shortlist"
    elif clean_score >= 55:
        bucket = "watch"
        label = "Watch"
    else:
        bucket = "wait"
        label = "Wait"
    return {
        "triage_score": clean_score,
        "triage_bucket": bucket,
        "triage_label": label,
        "triage_reasons": reasons[:6],
    }


@_memoized_report
def build_saved_option_contracts(
    data_dir: Path = DATA_DIR,
    enrich: bool = True,
    limit: int = 80,
    refresh_quotes: bool = False,
    quote_limit: int = 20,
) -> dict[str, Any]:
    """Return saved option-request watchlist entries as a clean contract review queue."""
    limit = max(1, min(int(limit or 80), 250))
    quote_limit = max(0, min(int(quote_limit or 20), 80))
    watchlist = load_watchlist(data_dir, enrich=enrich)
    rows: list[dict[str, Any]] = []
    quote_checked_count = 0
    for entry in watchlist.get("entries", []):
        request = entry.get("request") if isinstance(entry, dict) else None
        if not isinstance(request, dict) or request.get("asset") != "option":
            continue
        chain_context = (
            entry.get("chain_context") if isinstance(entry.get("chain_context"), dict) else {}
        )
        dte = _request_dte(request.get("expiry"))
        side = str(request.get("side") or "").strip().lower()
        row = {
            "id": entry.get("id"),
            "query": entry.get("query"),
            "symbol": str(entry.get("symbol") or request.get("ticker") or "").upper(),
            "side": side,
            "side_code": "C" if side == "call" else "P" if side == "put" else None,
            "expiry": request.get("expiry"),
            "strike": _clean_value(request.get("strike")),
            "dte": dte,
            "dte_bucket": _option_dte_bucket(float(dte if dte is not None else -1)),
            "status": _saved_contract_status(dte, entry.get("paper_readiness_status")),
            "paper_readiness": _clean_value(
                entry.get("paper_readiness_label") or entry.get("paper_readiness_status")
            ),
            "paper_readiness_score": _clean_value(entry.get("paper_readiness_score")),
            "swing_verdict": _clean_value(
                entry.get("swing_verdict_label") or entry.get("swing_verdict_decision")
            ),
            "swing_verdict_score": _clean_value(entry.get("swing_verdict_score")),
            "swing_verdict_decision": _clean_value(entry.get("swing_verdict_decision")),
            "swing_verdict_bias": _clean_value(entry.get("swing_verdict_bias")),
            "swing_verdict_risk_reward": _clean_value(entry.get("swing_verdict_risk_reward")),
            "best_idea": _clean_value(entry.get("best_idea")),
            "best_status": _clean_value(entry.get("best_status")),
            "best_confidence": _clean_value(entry.get("best_confidence")),
            "local_hits": _clean_value(entry.get("local_hits")),
            "open_count": _clean_value(entry.get("open_count")),
            "warning_count": _clean_value(entry.get("warning_count")),
            "added_at": entry.get("added_at"),
            "updated_at": entry.get("updated_at"),
            "saved_context_at": _clean_value(chain_context.get("saved_context_at")),
            "saved_contract_grade": _clean_value(chain_context.get("contract_grade")),
            "saved_review_lane": _clean_value(chain_context.get("review_lane")),
            "saved_review_thesis": _clean_value(chain_context.get("review_thesis")),
            "saved_grade_reasons": _clean_value(chain_context.get("grade_reasons")),
            "saved_readiness_label": _clean_value(chain_context.get("readiness_label")),
            "saved_readiness_score": _clean_value(chain_context.get("readiness_score")),
            "saved_contract_quality_score": _clean_value(
                chain_context.get("contract_quality_score")
            ),
            "saved_chain_source": _clean_value(
                chain_context.get("chain_source") or chain_context.get("source")
            ),
            "saved_quote_quality": _clean_value(chain_context.get("quote_quality")),
            "saved_data_delay": _clean_value(chain_context.get("data_delay")),
            "saved_mid": _clean_value(chain_context.get("mid")),
            "saved_bid": _clean_value(chain_context.get("bid")),
            "saved_ask": _clean_value(chain_context.get("ask")),
            "saved_spread_pct": _clean_value(chain_context.get("spread_pct")),
            "saved_premium_dollars": _clean_value(chain_context.get("premium_dollars")),
            "saved_volume": _clean_value(chain_context.get("volume")),
            "saved_open_interest": _clean_value(chain_context.get("openInterest")),
        }
        if refresh_quotes and quote_checked_count < quote_limit:
            row.update(_saved_contract_quote_snapshot(str(row.get("symbol") or ""), request, dte))
            quote_checked_count += 1
        else:
            row["quote_status"] = "not_checked" if not refresh_quotes else "not_checked_limit"
        row.update(_saved_contract_review(row))
        row.update(_saved_contract_triage(row))
        rows.append({k: _clean_value(v) for k, v in row.items()})

    rows = sorted(
        rows,
        key=lambda row: (
            _float_value(row.get("triage_score"), default=0.0),
            _saved_grade_rank(row.get("saved_contract_grade")),
            _float_value(row.get("swing_verdict_score"), default=0.0),
            _float_value(row.get("dte"), default=-9999.0) >= MIN_SWING_OPTION_DTE,
            _float_value(row.get("paper_readiness_score"), default=0.0),
            _float_value(row.get("dte"), default=-9999.0),
            str(row.get("updated_at") or ""),
        ),
        reverse=True,
    )[:limit]
    status_counts: dict[str, int] = {}
    quote_status_counts: dict[str, int] = {}
    review_action_counts: dict[str, int] = {}
    saved_grade_counts: dict[str, int] = {}
    triage_counts: dict[str, int] = {}
    for row in rows:
        status = str(row.get("status") or "unknown")
        status_counts[status] = status_counts.get(status, 0) + 1
        quote_status = str(row.get("quote_status") or "unknown")
        quote_status_counts[quote_status] = quote_status_counts.get(quote_status, 0) + 1
        review_action = str(row.get("review_action") or "unknown")
        review_action_counts[review_action] = review_action_counts.get(review_action, 0) + 1
        saved_grade = str(row.get("saved_contract_grade") or "ungraded")
        saved_grade_counts[saved_grade] = saved_grade_counts.get(saved_grade, 0) + 1
        triage_bucket = str(row.get("triage_bucket") or "unknown")
        triage_counts[triage_bucket] = triage_counts.get(triage_bucket, 0) + 1
    return {
        "generated_at": _now_iso(),
        "count": len(rows),
        "enriched": enrich,
        "refresh_quotes": refresh_quotes,
        "quote_limit": quote_limit,
        "quote_checked_count": quote_checked_count,
        "status_counts": status_counts,
        "quote_status_counts": quote_status_counts,
        "review_action_counts": review_action_counts,
        "saved_grade_counts": saved_grade_counts,
        "triage_counts": triage_counts,
        "call_count": sum(row.get("side") == "call" for row in rows),
        "put_count": sum(row.get("side") == "put" for row in rows),
        "swing_count": sum(
            _float_value(row.get("dte"), default=-1.0) >= MIN_SWING_OPTION_DTE for row in rows
        ),
        "rows": rows,
        "notes": [
            "Saved contracts come from the local research watchlist option requests.",
            "3m+ status uses the current calendar date and Optedge's 90 DTE swing floor.",
            "Quote refresh uses the same free option-chain stack and may be delayed or incomplete.",
            "Use Chain to refresh the underlying option chain before acting; no trades are placed.",
        ],
    }


def _save_watchlist(entries: list[dict[str, Any]], data_dir: Path = DATA_DIR) -> None:
    path = _watchlist_file(data_dir)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(entries, indent=2, default=str), encoding="utf-8")


def add_watchlist_query(
    query: str, data_dir: Path = DATA_DIR, context: dict[str, Any] | None = None
) -> dict[str, Any]:
    clean = str(query or "").strip()
    if not clean:
        return {"ok": False, "error": "query is required"}
    resolution = resolve_symbol(clean)
    if not resolution.get("symbol"):
        return {
            "ok": False,
            "error": resolution.get("error") or "could not resolve symbol",
            "resolution": resolution,
        }
    current = load_watchlist(data_dir)["entries"]
    item_id = _watchlist_entry_id(resolution, clean)
    now = _now_iso()
    chain_context = _clean_watchlist_context(context)
    entry = {
        "id": item_id,
        "query": clean,
        "symbol": str(resolution.get("symbol") or "").upper(),
        "name": resolution.get("name"),
        "source": resolution.get("source"),
        "request": resolution.get("request"),
        "resolution": resolution,
        "added_at": now,
        "updated_at": now,
    }
    if chain_context:
        entry["chain_context"] = chain_context
    replaced = False
    for idx, row in enumerate(current):
        if row.get("id") == item_id:
            entry["added_at"] = row.get("added_at") or now
            if not chain_context and isinstance(row.get("chain_context"), dict):
                entry["chain_context"] = row.get("chain_context")
            current[idx] = entry
            replaced = True
            break
    if not replaced:
        current.append(entry)
    _save_watchlist(current, data_dir)
    return {"ok": True, "entry": entry, "updated_existing": replaced, **load_watchlist(data_dir)}


def add_watchlist_queries(items: Any, data_dir: Path = DATA_DIR, limit: int = 12) -> dict[str, Any]:
    if not isinstance(items, list):
        return {"ok": False, "error": "items list is required"}
    limit = max(1, min(int(limit or 12), 25))
    saved: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []
    updated_existing = 0
    for item in items[:limit]:
        if isinstance(item, dict):
            query = str(item.get("query") or "").strip()
            context = item.get("context") if isinstance(item.get("context"), dict) else None
        else:
            query = str(item or "").strip()
            context = None
        if not query:
            errors.append({"query": query, "error": "query is required"})
            continue
        result = add_watchlist_query(query, data_dir, context=context)
        if result.get("ok"):
            entry = result.get("entry") or {}
            if result.get("updated_existing"):
                updated_existing += 1
            saved.append(
                {
                    "id": entry.get("id"),
                    "query": entry.get("query"),
                    "symbol": entry.get("symbol"),
                    "updated_existing": bool(result.get("updated_existing")),
                }
            )
        else:
            errors.append(
                {
                    "query": query,
                    "error": result.get("error") or "could not save",
                }
            )
    watchlist = load_watchlist(data_dir)
    return {
        "ok": bool(saved) and not errors,
        "saved_count": len(saved),
        "error_count": len(errors),
        "updated_existing_count": updated_existing,
        "saved": saved,
        "errors": errors,
        **watchlist,
    }


def remove_watchlist_entry(entry_id: str, data_dir: Path = DATA_DIR) -> dict[str, Any]:
    clean_id = str(entry_id or "").strip()
    current = load_watchlist(data_dir)["entries"]
    remaining = [row for row in current if str(row.get("id")) != clean_id]
    removed = len(remaining) != len(current)
    _save_watchlist(remaining, data_dir)
    return {"ok": removed, "removed": removed, **load_watchlist(data_dir)}


def _scan_args_from_controls(
    mode: str = "full", bankroll: Any = None, aggressive: bool = False
) -> list[str]:
    scan_args = ["--minimal"] if str(mode or "full").strip().lower() == "quick" else []
    if aggressive:
        scan_args.append("--aggressive")
    try:
        bankroll_float = float(bankroll or 0)
    except Exception:
        bankroll_float = 0.0
    if bankroll_float > 0:
        scan_args.extend(["--bankroll", str(bankroll_float)])
    return scan_args


def _market_refresh_scan_args(
    mode: str = "full", bankroll: Any = None, aggressive: bool = False
) -> list[str]:
    """Refresh the dashboard and its inert 3m+ Robinhood review queue together."""
    scan_args = _scan_args_from_controls(mode, bankroll, aggressive)
    try:
        budget = float(bankroll or 0)
    except Exception:
        budget = 0.0
    if budget <= 0:
        budget = 500.0
    scan_args.extend(
        [
            "--robinhood-agentic-queue",
            "--robinhood-budget",
            str(budget),
            "--robinhood-min-dte",
            str(MIN_SWING_OPTION_DTE),
            "--robinhood-refresh-chain",
            "--robinhood-chain-preset",
            "swing",
            "--robinhood-max-candidates",
            "10",
            "--robinhood-max-orders",
            "1",
        ]
    )
    return scan_args


def run_watchlist_scans(
    data_dir: Path = DATA_DIR,
    mode: str = "full",
    bankroll: Any = None,
    aggressive: bool = False,
    launch: bool = True,
) -> dict[str, Any]:
    entries = load_watchlist(data_dir)["entries"]
    scan_args = _scan_args_from_controls(mode, bankroll, aggressive)
    jobs = []
    for entry in entries[:25]:
        query = str(entry.get("query") or entry.get("symbol") or "").strip()
        if not query:
            continue
        jobs.append(
            create_job(
                query,
                data_dir,
                launch=launch,
                extra_scan_args=scan_args,
                scan_mode=str(mode or "full"),
            )
        )
    return {
        "ok": True,
        "count": len(jobs),
        "jobs": jobs,
        "scan_args": scan_args,
        "launched": launch,
    }


def warm_symbol_caches(data_dir: Path = DATA_DIR, timeout: float = 8.0) -> dict[str, Any]:
    """Warm free symbol-search caches used by company-name autocomplete."""
    cache_path = Path(data_dir) / "sec_company_tickers.json"
    nasdaq_path = Path(data_dir) / "nasdaq_symbol_directory.json"
    rows = load_sec_company_tickers(cache_path=cache_path, timeout=timeout, fetch_if_stale=True)
    nasdaq_rows = load_nasdaq_symbol_directory(
        cache_path=nasdaq_path,
        timeout=timeout,
        fetch_if_stale=True,
    )
    meta = sec_company_cache_meta(cache_path)
    nasdaq_meta = nasdaq_symbol_cache_meta(nasdaq_path)
    sec_ok = bool(rows) and meta.get("status") in {"fresh", "stale"}
    nasdaq_ok = bool(nasdaq_rows) and nasdaq_meta.get("status") in {"fresh", "stale"}
    ok = sec_ok or nasdaq_ok
    return {
        "ok": ok,
        "generated_at": datetime.now(UTC).isoformat(),
        "row_count": len(rows),
        "nasdaq_row_count": len(nasdaq_rows),
        "cache": meta,
        "nasdaq_cache": nasdaq_meta,
        "message": (
            f"Symbol search caches ready: SEC {len(rows)} row(s), Nasdaq {len(nasdaq_rows)} row(s)."
            if ok
            else "Symbol search caches could not be warmed right now."
        ),
    }


def warm_sec_ticker_cache(data_dir: Path = DATA_DIR, timeout: float = 8.0) -> dict[str, Any]:
    """Backward-compatible wrapper for the broader symbol-cache warmer."""
    return warm_symbol_caches(data_dir, timeout=timeout)


def _is_refreshable_market_warning(label: Any) -> bool:
    clean = str(label or "").strip().lower()
    return (
        clean in {"dashboard is old", "dashboard missing"}
        or clean.endswith("snapshot old")
        or clean.endswith("snapshot missing")
    )


def _position_label(row: dict[str, Any]) -> str:
    symbol = str(row.get("ticker") or row.get("symbol") or "-").upper()
    side = str(row.get("side") or row.get("direction") or "").upper()
    strike = row.get("strike")
    expiry = str(row.get("expiry") or "")
    contract = str(row.get("contract") or "")
    if strike not in (None, "", "-") and expiry:
        try:
            strike_txt = f"{float(strike):g}"
        except Exception:
            strike_txt = str(strike)
        return f"{symbol} {side[:1]} {strike_txt} {expiry[-5:]}"
    if contract:
        return f"{symbol} {side} {contract}".strip()
    return f"{symbol} {side}".strip()


def _position_age_days(row: dict[str, Any]) -> float:
    if row.get("age_days") is not None:
        return _float_value(row.get("age_days"))
    entry = row.get("entry_time")
    if not entry:
        return 0.0
    try:
        ts = pd.to_datetime(entry, errors="coerce", utc=True)
        if pd.isna(ts):
            return 0.0
        return max(0.0, float((pd.Timestamp.now(tz="UTC") - ts).total_seconds() / 86400.0))
    except Exception:
        return 0.0


def _position_pnl_pct(row: dict[str, Any]) -> float:
    for col in ("unrealized_pct", "current_pnl_pct", "pnl_pct"):
        if row.get(col) is not None:
            return _float_value(row.get(col))
    current = row.get("current_mid", row.get("current_price"))
    if current is None:
        current = row.get("last_price")
    entry = _float_value(row.get("entry_price"))
    cur = _float_value(current)
    return (cur - entry) / entry if entry > 0 and cur > 0 else 0.0


def _position_is_expired(row: dict[str, Any], asset: str, now: datetime | None = None) -> bool:
    if str(asset or "").strip().lower() != "option":
        return False
    expiry_value = row.get("expiry") or row.get("expiration_date")
    expiry = _parse_iso_utc(expiry_value)
    if expiry is None:
        return False
    asof = now or datetime.now(UTC)
    if isinstance(expiry_value, str) and "T" not in expiry_value:
        return asof.date() > expiry.date()
    return asof >= expiry


def _normalize_position(row: dict[str, Any], asset: str) -> dict[str, Any]:
    out = dict(row)
    out.setdefault("asset", asset)
    tracking_scope = (
        _local_option_tracking_scope(out)
        if str(asset or "").strip().lower() == "option"
        else "research_lifecycle"
    )
    symbol = out.get("ticker") or out.get("symbol") or "-"
    current_price = out.get("current_mid", out.get("current_price", out.get("last_price")))
    pnl_pct = _position_pnl_pct(out)
    exit_pressure = _float_value(out.get("latest_exit_pressure"), default=0.0)
    reprice_failed = _float_value(out.get("reprice_failed_count"), default=0.0)
    is_expired = _position_is_expired(out, asset)
    attention = not is_expired and (exit_pressure >= 60 or reprice_failed >= 2 or pnl_pct <= -0.30)
    return {
        "asset": out.get("asset"),
        "position_label": _position_label(out),
        "ticker_or_symbol": str(symbol).upper(),
        "side_or_direction": out.get("side") or out.get("direction") or out.get("asset"),
        "strike_or_contract": out.get("strike", out.get("contract")),
        "expiry": out.get("expiry"),
        "lifecycle_state": "expired" if is_expired else "active",
        "is_expired": is_expired,
        "tracking_scope": tracking_scope,
        "trade_status": out.get("trade_status") or "Open",
        "entry_time": out.get("entry_time"),
        "age_days": round(_position_age_days(out), 2),
        "entry_price": _clean_value(out.get("entry_price")),
        "current_price": _clean_value(current_price),
        "pnl_pct": pnl_pct,
        "pnl_dollars": _clean_value(out.get("pnl_dollars")),
        "confidence": _clean_value(out.get("confidence")),
        "latest_exit_pressure": _clean_value(out.get("latest_exit_pressure")),
        "latest_exit_action": out.get("latest_exit_action"),
        "stop_price": _clean_value(out.get("stop_price")),
        "target_price": _clean_value(out.get("target_price")),
        "reprice_failed_count": _clean_value(out.get("reprice_failed_count")),
        "research_guard_status": out.get("research_guard_status"),
        "attention": attention,
    }


def _position_sort_key(row: dict[str, Any]) -> tuple:
    return (
        1 if row.get("attention") else 0,
        _float_value(row.get("latest_exit_pressure")),
        abs(_float_value(row.get("pnl_pct"))),
        _float_value(row.get("age_days")),
    )


def _opportunity_score(row: pd.Series) -> float:
    for col in ("rank_score", "fused_score", "futures_score", "value_score"):
        if col in row:
            score = _float_value(row.get(col), default=math.nan)
            if math.isfinite(score):
                return score
    return _float_value(row.get("confidence"), default=0.0) / 100.0


def _fetch_option_chain(
    ticker: str,
    cache_age: int = 600,
    include_diagnostics: bool = False,
) -> dict[str, Any]:
    import chain_provider

    return chain_provider.fetch_chain(
        ticker,
        cache_age=cache_age,
        include_diagnostics=include_diagnostics,
    )


def _option_mid(row: pd.Series) -> float:
    bid = _float_value(row.get("bid"), default=math.nan)
    ask = _float_value(row.get("ask"), default=math.nan)
    last = _float_value(row.get("lastPrice"), default=math.nan)
    if math.isfinite(bid) and math.isfinite(ask) and bid > 0 and ask >= bid:
        return (bid + ask) / 2.0
    if math.isfinite(last) and last > 0:
        return last
    return float("nan")


def _option_spread_pct(row: pd.Series, mid: float) -> float | None:
    bid = _float_value(row.get("bid"), default=math.nan)
    ask = _float_value(row.get("ask"), default=math.nan)
    if not (math.isfinite(bid) and math.isfinite(ask) and math.isfinite(mid)):
        return None
    if bid < 0 or ask <= 0 or ask < bid or mid <= 0:
        return None
    return (ask - bid) / mid


def _option_chain_trade_refs(
    row: dict[str, Any],
    spot: float,
    max_premium: float,
    execution_profile: str = SWING_EXECUTION_PROFILE.name,
) -> dict[str, Any]:
    """Build conservative one-contract review references for chain candidates."""
    side = str(row.get("side") or "").strip().lower()
    strike = _float_value(row.get("strike"), default=math.nan)
    mid = _float_value(row.get("mid"), default=math.nan)
    premium = _float_value(row.get("premium_dollars"), default=math.nan)
    if not math.isfinite(premium) and math.isfinite(mid):
        premium = mid * 100.0
    budget = max_premium if max_premium > 0 else 500.0

    out: dict[str, Any] = {
        "breakeven_price": None,
        "breakeven_move_pct": None,
        "breakeven_direction": "",
        "budget_usage_pct": None,
        "contracts_for_budget": 0,
        "stop_price_reference": None,
        "target_price_reference": None,
        "risk_dollars_reference": None,
        "reward_dollars_reference": None,
        "reward_risk_reference": None,
        "budget_fit": "unknown",
    }
    if math.isfinite(premium) and premium > 0 and budget > 0:
        usage = premium / budget
        out["budget_usage_pct"] = round(usage, 4)
        out["contracts_for_budget"] = int(max(0, math.floor(budget / premium)))
        if usage <= 1.0:
            out["budget_fit"] = "inside_budget"
        elif usage <= 1.25:
            out["budget_fit"] = "stretch"
        else:
            out["budget_fit"] = "over_budget"

    if math.isfinite(mid) and mid > 0:
        if execution_profile == LEAPS_SWING_PROFILE.name:
            stop = max(0.01, mid * (1.0 - LEAPS_SWING_PROFILE.stop_loss_fraction))
            target = mid * (1.0 + LEAPS_SWING_PROFILE.target_gain_fraction)
        else:
            stop = max(0.01, mid * 0.50)
            target = mid * 2.00
        risk = max(0.0, (mid - stop) * 100.0)
        reward = max(0.0, (target - mid) * 100.0)
        out["stop_price_reference"] = round(stop, 2)
        out["target_price_reference"] = round(target, 2)
        out["risk_dollars_reference"] = round(risk, 2)
        out["reward_dollars_reference"] = round(reward, 2)
        out["reward_risk_reference"] = round(reward / risk, 2) if risk > 0 else None

    if math.isfinite(strike) and math.isfinite(mid) and mid > 0:
        if side.startswith("call"):
            breakeven = strike + mid
            out["breakeven_direction"] = "up"
            if math.isfinite(spot) and spot > 0:
                out["breakeven_move_pct"] = round((breakeven - spot) / spot, 4)
        elif side.startswith("put"):
            breakeven = max(0.0, strike - mid)
            out["breakeven_direction"] = "down"
            if math.isfinite(spot) and spot > 0:
                out["breakeven_move_pct"] = round((spot - breakeven) / spot, 4)
        else:
            breakeven = float("nan")
        if math.isfinite(breakeven):
            out["breakeven_price"] = round(breakeven, 4)

    return out


def _option_chain_score(row: dict[str, Any]) -> float:
    oi = _float_value(row.get("openInterest"), default=0.0)
    volume = _float_value(row.get("volume"), default=0.0)
    spread = _float_value(row.get("spread_pct"), default=0.50)
    premium = _float_value(row.get("premium_dollars"), default=0.0)
    moneyness = abs(_float_value(row.get("moneyness_pct"), default=0.0))
    return (
        math.log1p(max(0.0, oi))
        + 0.65 * math.log1p(max(0.0, volume))
        - 8.0 * max(0.0, spread)
        - 0.04 * moneyness
        - 0.0002 * max(0.0, premium)
    )


def _option_dte_bucket(dte: float) -> str:
    if dte < 30:
        return "0-29d"
    if dte < MIN_SWING_OPTION_DTE:
        return "30-89d"
    if dte < 180:
        return "90-179d"
    if dte < 365:
        return "180-364d"
    return "365d+"


def _option_contract_readiness(row: dict[str, Any], quote_quality: str) -> dict[str, Any]:
    score = 100
    flags: list[str] = []
    dte = _float_value(row.get("dte"), default=math.nan)
    spread = _float_value(row.get("spread_pct"), default=math.nan)
    oi = _float_value(row.get("openInterest"), default=0.0)
    volume = _float_value(row.get("volume"), default=0.0)
    premium = _float_value(row.get("premium_dollars"), default=math.nan)
    moneyness = abs(_float_value(row.get("moneyness_pct"), default=0.0))
    quote_norm = str(quote_quality or "").lower()

    if not math.isfinite(dte) or dte < MIN_SWING_OPTION_DTE:
        score -= 35
        flags.append("below 90 DTE")
    elif dte > 900:
        score -= 8
        flags.append("very far expiry")
    if math.isfinite(spread):
        if spread > 0.30:
            score -= 35
            flags.append("very wide spread")
        elif spread > 0.20:
            score -= 22
            flags.append("wide spread")
        elif spread > 0.12:
            score -= 8
            flags.append("spread check")
    else:
        score -= 14
        flags.append("missing spread")
    if oi < 25:
        score -= 18
        flags.append("thin open interest")
    elif oi < 100:
        score -= 8
        flags.append("light open interest")
    if volume <= 0:
        score -= 8
        flags.append("no volume today")
    if not math.isfinite(premium) or premium <= 0:
        score -= 30
        flags.append("invalid premium")
    elif premium > 1000:
        score -= 8
        flags.append("large premium")
    if moneyness > 0.35:
        score -= 8
        flags.append("far from spot")
    if quote_norm in {"", "unknown"}:
        score -= 8
        flags.append("unknown quote source")
    elif "free" in quote_norm or "delayed" in quote_norm:
        score -= 6
        flags.append("verify live quote")

    return _readiness(score, flags)


def _option_chain_swing_fit(row: dict[str, Any], max_premium: float) -> dict[str, Any]:
    """Score whether a chain row is usable for 3m+ swing review."""
    score = 100
    reasons: list[str] = []
    warnings: list[str] = []
    dte = _float_value(row.get("dte"), default=math.nan)
    spread = _float_value(row.get("spread_pct"), default=math.nan)
    oi = _float_value(row.get("openInterest"), default=0.0)
    volume = _float_value(row.get("volume"), default=0.0)
    premium = _float_value(row.get("premium_dollars"), default=math.nan)
    budget_usage = _float_value(row.get("budget_usage_pct"), default=math.nan)
    breakeven_move = _float_value(row.get("breakeven_move_pct"), default=math.nan)
    delta = abs(_float_value(row.get("delta"), default=math.nan))
    quote_norm = str(row.get("quote_quality") or "").lower()
    budget = max_premium if max_premium > 0 else 500.0

    if not math.isfinite(dte):
        score -= 24
        warnings.append("unknown DTE")
    elif dte < MIN_SWING_OPTION_DTE:
        score -= 40
        warnings.append("below 3m swing minimum")
    elif dte < 180:
        reasons.append("3m+ runway")
    elif dte <= 540:
        reasons.append("long swing runway")
    elif dte <= 900:
        score -= 4
        reasons.append("LEAPS-style runway")
    else:
        score -= 12
        warnings.append("very far-dated")

    if math.isfinite(spread):
        if spread <= 0.08:
            reasons.append("tight spread")
        elif spread <= 0.15:
            reasons.append("acceptable spread")
        elif spread <= 0.25:
            score -= 14
            warnings.append("spread needs live check")
        else:
            score -= 32
            warnings.append("spread too wide")
    else:
        score -= 18
        warnings.append("missing spread")

    if oi >= 500:
        reasons.append("deep open interest")
        liquidity_label = "deep"
    elif oi >= 100:
        reasons.append("usable open interest")
        liquidity_label = "usable"
    elif oi >= 25:
        score -= 8
        warnings.append("light open interest")
        liquidity_label = "light"
    else:
        score -= 24
        warnings.append("thin open interest")
        liquidity_label = "thin"
    if volume > 0:
        reasons.append("traded today")
    else:
        score -= 6
        warnings.append("no same-day volume")

    if not math.isfinite(premium) or premium <= 0:
        score -= 35
        warnings.append("invalid premium")
    elif premium <= budget:
        if math.isfinite(budget_usage) and budget_usage <= 0.50:
            reasons.append("small budget usage")
        else:
            reasons.append("inside premium budget")
    elif premium <= budget * 1.25:
        score -= 12
        warnings.append("premium near budget cap")
    else:
        score -= 28
        warnings.append("premium above budget cap")

    breakeven_label = "unknown"
    if math.isfinite(breakeven_move):
        move_abs = abs(breakeven_move)
        if move_abs <= 0.08:
            breakeven_label = "light"
            reasons.append("light break-even move")
        elif move_abs <= 0.15:
            breakeven_label = "moderate"
            score -= 5
            reasons.append("moderate break-even move")
        elif move_abs <= 0.25:
            breakeven_label = "heavy"
            score -= 14
            warnings.append("heavy break-even move")
        else:
            breakeven_label = "speculative"
            score -= 28
            warnings.append("speculative break-even move")
    else:
        score -= 8
        warnings.append("unknown break-even")

    if math.isfinite(delta):
        if 0.25 <= delta <= 0.65:
            reasons.append("swing delta zone")
        elif delta < 0.15:
            score -= 10
            warnings.append("low-delta lottery profile")
        elif delta > 0.85:
            score -= 4
            warnings.append("stock-like high delta")

    if quote_norm in {"", "unknown"}:
        score -= 8
        warnings.append("unknown quote source")
    elif "free" in quote_norm or "delayed" in quote_norm:
        score -= 4
        warnings.append("verify delayed quote")

    clean_score = max(0, min(100, int(round(score))))
    if clean_score >= 85 and len(warnings) <= 1:
        label = "clean_swing"
    elif clean_score >= 70:
        label = "reviewable_swing"
    elif clean_score >= 55:
        label = "speculative_swing"
    else:
        label = "avoid"

    return {
        "swing_fit_score": clean_score,
        "swing_fit_label": label,
        "swing_fit_reasons": reasons[:6],
        "swing_fit_warnings": warnings[:6],
        "breakeven_move_label": breakeven_label,
        "liquidity_label": liquidity_label,
    }


def _option_contract_grade(row: dict[str, Any], max_premium: float) -> dict[str, Any]:
    readiness = _float_value(row.get("readiness_score"), default=0.0)
    spread = _float_value(row.get("spread_pct"), default=math.nan)
    oi = _float_value(row.get("openInterest"), default=0.0)
    volume = _float_value(row.get("volume"), default=0.0)
    premium = _float_value(row.get("premium_dollars"), default=math.nan)
    dte = _float_value(row.get("dte"), default=math.nan)
    side = str(row.get("side") or "").lower()
    budget = max_premium if max_premium > 0 else 500.0
    reasons: list[str] = []

    tight_spread = math.isfinite(spread) and spread <= 0.12
    acceptable_spread = math.isfinite(spread) and spread <= 0.20
    liquid = oi >= 100
    tradable_oi = oi >= 25
    under_budget = math.isfinite(premium) and premium <= budget
    swing_dte = math.isfinite(dte) and dte >= MIN_SWING_OPTION_DTE
    long_dated = math.isfinite(dte) and dte >= 180

    if tight_spread:
        reasons.append("tight spread")
    elif acceptable_spread:
        reasons.append("acceptable spread")
    elif math.isfinite(spread):
        reasons.append("spread needs work")
    if liquid:
        reasons.append("100+ OI")
    elif tradable_oi:
        reasons.append("25+ OI")
    else:
        reasons.append("thin OI")
    if volume > 0:
        reasons.append("traded today")
    if under_budget:
        reasons.append("inside premium budget")
    elif math.isfinite(premium):
        reasons.append("above premium budget")
    if long_dated:
        reasons.append("long-dated swing")
    elif swing_dte:
        reasons.append("3m+ swing")

    if readiness >= 80 and tight_spread and liquid and under_budget and swing_dte:
        grade = "A"
        lane = "primary_review"
    elif readiness >= 70 and acceptable_spread and tradable_oi and under_budget and swing_dte:
        grade = "B"
        lane = "secondary_review"
    elif readiness >= 65 and swing_dte:
        grade = "C"
        lane = "long_dated_review" if long_dated else "secondary_review"
    else:
        grade = "D"
        lane = "wait"

    side_text = (
        "call" if side.startswith("call") else "put" if side.startswith("put") else "contract"
    )
    dte_text = f"{int(dte)} DTE" if math.isfinite(dte) else "unknown DTE"
    premium_text = f"${premium:.0f} premium" if math.isfinite(premium) else "unknown premium"
    spread_text = f"{spread * 100:.1f}% spread" if math.isfinite(spread) else "unknown spread"
    break_even_move = _float_value(row.get("breakeven_move_pct"), default=math.nan)
    break_even_text = (
        f"{break_even_move * 100:.1f}% break-even move"
        if math.isfinite(break_even_move)
        else "unknown break-even"
    )
    budget_fit = str(row.get("budget_fit") or "").replace("_", " ")
    thesis = (
        f"{grade}-grade {dte_text} {side_text}: {premium_text}, "
        f"{spread_text}, {break_even_text}, OI {int(oi)}. "
        f"{budget_fit or 'budget fit unknown'}. "
        f"{'; '.join(reasons[:4]) if reasons else 'Review exact quote before acting.'}"
    )
    return {
        "contract_grade": grade,
        "review_lane": lane,
        "review_thesis": thesis,
        "grade_reasons": reasons[:6],
    }


def _option_chain_factor_breakdown(row: dict[str, Any], max_premium: float) -> list[dict[str, Any]]:
    budget = max_premium if max_premium > 0 else 500.0
    dte = _float_value(row.get("dte"), default=math.nan)
    spread = _float_value(row.get("spread_pct"), default=math.nan)
    oi = _float_value(row.get("openInterest"), default=0.0)
    volume = _float_value(row.get("volume"), default=0.0)
    premium = _float_value(row.get("premium_dollars"), default=math.nan)
    budget_usage = _float_value(row.get("budget_usage_pct"), default=math.nan)
    breakeven_move = abs(_float_value(row.get("breakeven_move_pct"), default=math.nan))
    swing_fit = _float_value(row.get("swing_fit_score"), default=0.0)
    quality = _float_value(row.get("contract_quality_score"), default=0.0)
    factors: list[dict[str, Any]] = []

    def add(factor: str, score: float, detail: str) -> None:
        if not math.isfinite(score):
            return
        factors.append(
            {
                "factor": factor,
                "score": int(round(_clamp(score, 0.0, 100.0))),
                "detail": detail[:160],
            }
        )

    if math.isfinite(dte):
        if dte < MIN_SWING_OPTION_DTE:
            runway_score = 35.0
        elif dte < 180:
            runway_score = 82.0
        elif dte <= 540:
            runway_score = 94.0
        elif dte <= 900:
            runway_score = 80.0
        else:
            runway_score = 55.0
        add(
            "Runway",
            runway_score,
            f"{int(dte)} DTE, {row.get('dte_bucket') or _option_dte_bucket(dte)}",
        )

    liquidity_score = min(
        100.0, 28.0 + 12.0 * math.log1p(max(0.0, oi)) + 4.0 * math.log1p(max(0.0, volume))
    )
    add("Liquidity", liquidity_score, f"OI {int(oi):,}, volume {int(volume):,}")

    if math.isfinite(spread):
        if spread <= 0.08:
            spread_score = 96.0
        elif spread <= 0.12:
            spread_score = 86.0
        elif spread <= 0.20:
            spread_score = 68.0
        elif spread <= 0.30:
            spread_score = 45.0
        else:
            spread_score = 18.0
        add("Spread", spread_score, f"{spread * 100:.1f}% bid/ask spread")

    if math.isfinite(premium):
        if math.isfinite(budget_usage):
            usage_text = f"{budget_usage * 100:.0f}% of ${budget:,.0f} cap"
        else:
            usage_text = f"${premium:,.0f} premium vs ${budget:,.0f} cap"
        if premium <= budget * 0.50:
            budget_score = 96.0
        elif premium <= budget:
            budget_score = 84.0
        elif premium <= budget * 1.25:
            budget_score = 58.0
        else:
            budget_score = 24.0
        add("Budget", budget_score, usage_text)

    if math.isfinite(breakeven_move):
        if breakeven_move <= 0.08:
            breakeven_score = 92.0
        elif breakeven_move <= 0.15:
            breakeven_score = 76.0
        elif breakeven_move <= 0.25:
            breakeven_score = 50.0
        else:
            breakeven_score = 20.0
        label = str(row.get("breakeven_move_label") or "").replace("_", " ") or "break-even"
        add("Break-even", breakeven_score, f"{breakeven_move * 100:.1f}% move, {label}")

    add(
        "Swing fit",
        swing_fit,
        f"{str(row.get('swing_fit_label') or 'unscored').replace('_', ' ')} / {int(round(swing_fit))}",
    )
    if math.isfinite(quality):
        add("Quality", min(100.0, max(0.0, 50.0 + quality * 5.0)), f"quality score {quality:.1f}")

    return sorted(
        factors,
        key=lambda item: _float_value(item.get("score"), default=0.0),
        reverse=True,
    )


def _chain_preset_config(preset: str) -> tuple[str, dict[str, Any]]:
    preset_norm = str(preset or "custom").strip().lower().replace("-", "_")
    if preset_norm in {"long", "broad_long_dated"}:
        preset_norm = "long_dated"
    elif preset_norm in {"leap", "true_leaps"}:
        preset_norm = "leaps"
    if preset_norm not in CHAIN_PRESETS:
        preset_norm = "custom"
    return preset_norm, CHAIN_PRESETS[preset_norm]


def _leaps_swing_scan_fields(
    row: dict[str, Any],
    *,
    quote_age_seconds: float | None,
    account_budget: float | None,
) -> dict[str, Any]:
    """Flatten the pure LEAPS assessment into stable scan/review fields."""
    assessment = score_leaps_swing_candidate(
        row,
        quote_age_seconds=quote_age_seconds,
        account_budget=account_budget,
    )
    holding = assessment.get("holding_policy") or {}
    management = assessment.get("management_references") or {}
    return {
        "execution_profile": LEAPS_SWING_PROFILE.name,
        "strategy_evidence_lane": LEAPS_EVIDENCE_LANE,
        "profile_policy_version": assessment.get("policy_version"),
        "leaps_swing_status": assessment.get("status"),
        "leaps_execution_ready": bool(assessment.get("execution_ready")),
        "leaps_quality_score": assessment.get("quality_score"),
        "leaps_hard_blockers": list(assessment.get("hard_blockers") or []),
        "leaps_data_blockers": list(assessment.get("data_blockers") or []),
        "leaps_score_breakdown": dict(assessment.get("score_breakdown") or {}),
        "quote_age_seconds": quote_age_seconds,
        "review_sessions": list(holding.get("review_sessions") or []),
        "planned_hold_sessions": holding.get("planned_hold_sessions"),
        "default_hold_sessions": LEAPS_SWING_PROFILE.default_hold_sessions,
        "max_hold_sessions": holding.get("max_hold_sessions"),
        "contract_dte_is_not_hold_time": bool(holding.get("contract_dte_is_not_hold_time")),
        "stop_loss_fraction": management.get("stop_loss_fraction"),
        "target_gain_fraction": management.get("target_gain_fraction"),
        "breakeven_review_trigger_fraction": management.get("breakeven_review_trigger_fraction"),
        "manual_management_only": bool(management.get("manual_management_only")),
    }


def _row_profile_execution_ready(row: dict[str, Any]) -> bool:
    """Keep profile-specific research rows out of review/execution lanes."""
    if str(row.get("execution_profile") or "") != LEAPS_SWING_PROFILE.name:
        return True
    return bool(row.get("leaps_execution_ready"))


def _chain_contract_label(row: dict[str, Any] | None) -> str | None:
    if not row:
        return None
    side = str(row.get("side") or "").upper()[:1]
    strike = _short_number(row.get("strike"))
    expiry = str(row.get("expiry") or "").strip()
    premium = _float_value(row.get("premium_dollars"), default=math.nan)
    premium_text = f" ${premium:.0f}" if math.isfinite(premium) else ""
    return " ".join(part for part in (side, strike, expiry + premium_text) if part)


def _option_grade_rank(value: Any) -> int:
    return {"A": 4, "B": 3, "C": 2, "D": 1}.get(str(value or "").upper(), 0)


def _option_contract_rank_tuple(row: dict[str, Any], budget: float) -> tuple[Any, ...]:
    premium = _float_value(row.get("premium_dollars"), default=math.inf)
    spread = _float_value(row.get("spread_pct"), default=9.0)
    return (
        premium <= budget,
        _option_grade_rank(row.get("contract_grade")),
        str(row.get("review_lane") or "") == "primary_review",
        _float_value(row.get("swing_fit_score"), default=0.0),
        _float_value(row.get("contract_quality_score"), default=0.0),
        _float_value(row.get("openInterest"), default=0.0),
        -spread,
    )


def _option_chain_scan_summary(rows: list[dict[str, Any]], max_premium: float) -> dict[str, Any]:
    if not rows:
        return {
            "best_call": None,
            "best_put": None,
            "best_reviewable": None,
            "best_ready": None,
            "best_budget": None,
            "best_liquid": None,
            "best_long_dated": None,
            "grade_counts": {},
            "primary_review_count": 0,
            "median_spread_pct": None,
            "under_budget_count": 0,
            "liquid_count": 0,
            "swing_count": 0,
            "long_dated_count": 0,
            "ready_count": 0,
            "review_count": 0,
            "wait_count": 0,
            "swing_fit_counts": {},
            "clean_swing_count": 0,
            "reviewable_swing_count": 0,
            "best_swing_fit": None,
            "profile_status_counts": {},
            "leaps_execution_ready_count": 0,
            "leaps_research_only_count": 0,
            "leaps_blocked_count": 0,
            "best_leaps_quality": None,
        }
    spreads = sorted(
        _float_value(row.get("spread_pct"), default=math.nan)
        for row in rows
        if math.isfinite(_float_value(row.get("spread_pct"), default=math.nan))
    )
    mid_idx = len(spreads) // 2
    median_spread = None
    if spreads:
        median_spread = (
            spreads[mid_idx]
            if len(spreads) % 2
            else (spreads[mid_idx - 1] + spreads[mid_idx]) / 2.0
        )
    best_call = next(
        (row for row in rows if str(row.get("side") or "").lower().startswith("call")), None
    )
    best_put = next(
        (row for row in rows if str(row.get("side") or "").lower().startswith("put")), None
    )
    best_reviewable = next(
        (row for row in rows if str(row.get("readiness_label") or "") in {"ready", "review"}),
        None,
    )
    budget = max_premium if max_premium > 0 else 500.0
    best_ready = next(
        (row for row in rows if str(row.get("readiness_label") or "") == "ready"), None
    )
    best_budget = next(
        (
            row
            for row in rows
            if _float_value(row.get("premium_dollars"), default=math.inf) <= budget
        ),
        None,
    )
    best_liquid = next(
        (
            row
            for row in rows
            if _float_value(row.get("openInterest"), default=0.0) >= 100
            and _float_value(row.get("spread_pct"), default=1.0) <= 0.15
        ),
        None,
    )
    best_long_dated = next(
        (row for row in rows if _float_value(row.get("dte"), default=0.0) >= 180), None
    )
    grade_counts: dict[str, int] = {}
    swing_fit_counts: dict[str, int] = {}
    profile_status_counts: dict[str, int] = {}
    for row in rows:
        grade = str(row.get("contract_grade") or "ungraded")
        grade_counts[grade] = grade_counts.get(grade, 0) + 1
        fit = str(row.get("swing_fit_label") or "unscored")
        swing_fit_counts[fit] = swing_fit_counts.get(fit, 0) + 1
        profile_status = str(row.get("leaps_swing_status") or "").strip()
        if profile_status:
            profile_status_counts[profile_status] = profile_status_counts.get(profile_status, 0) + 1
    leaps_rows = [
        row for row in rows if str(row.get("execution_profile") or "") == LEAPS_SWING_PROFILE.name
    ]
    best_leaps = (
        max(
            leaps_rows,
            key=lambda row: _float_value(row.get("leaps_quality_score"), default=-1.0),
        )
        if leaps_rows
        else None
    )
    return {
        "best_call": _chain_contract_label(best_call),
        "best_put": _chain_contract_label(best_put),
        "best_reviewable": _chain_contract_label(best_reviewable),
        "best_ready": _chain_contract_label(best_ready),
        "best_budget": _chain_contract_label(best_budget),
        "best_liquid": _chain_contract_label(best_liquid),
        "best_long_dated": _chain_contract_label(best_long_dated),
        "grade_counts": grade_counts,
        "primary_review_count": sum(
            str(row.get("review_lane") or "") == "primary_review" for row in rows
        ),
        "median_spread_pct": _clean_value(median_spread),
        "under_budget_count": sum(
            _float_value(row.get("premium_dollars"), default=math.inf) <= budget for row in rows
        ),
        "liquid_count": sum(
            _float_value(row.get("openInterest"), default=0.0) >= 100
            and _float_value(row.get("spread_pct"), default=1.0) <= 0.15
            for row in rows
        ),
        "swing_count": sum(
            MIN_SWING_OPTION_DTE <= _float_value(row.get("dte"), default=-1.0) <= 180
            for row in rows
        ),
        "long_dated_count": sum(_float_value(row.get("dte"), default=0.0) >= 180 for row in rows),
        "ready_count": sum(str(row.get("readiness_label") or "") == "ready" for row in rows),
        "review_count": sum(str(row.get("readiness_label") or "") == "review" for row in rows),
        "wait_count": sum(str(row.get("readiness_label") or "") == "wait" for row in rows),
        "swing_fit_counts": swing_fit_counts,
        "clean_swing_count": swing_fit_counts.get("clean_swing", 0),
        "reviewable_swing_count": swing_fit_counts.get("reviewable_swing", 0),
        "best_swing_fit": _chain_contract_label(
            max(
                rows,
                key=lambda row: _float_value(row.get("swing_fit_score"), default=-1.0),
            )
        ),
        "profile_status_counts": profile_status_counts,
        "leaps_execution_ready_count": profile_status_counts.get("execution_ready", 0),
        "leaps_research_only_count": profile_status_counts.get("research_only", 0),
        "leaps_blocked_count": profile_status_counts.get("blocked", 0),
        "best_leaps_quality": _chain_contract_label(best_leaps),
    }


def _option_chain_expiry_summary(
    rows: list[dict[str, Any]], max_premium: float = 0.0
) -> list[dict[str, Any]]:
    by_expiry: dict[str, list[dict[str, Any]]] = {}
    for row in rows:
        by_expiry.setdefault(str(row.get("expiry") or ""), []).append(row)

    summaries: list[dict[str, Any]] = []
    budget = max_premium if max_premium > 0 else 500.0
    for expiry, items in by_expiry.items():
        if not expiry:
            continue
        spreads = sorted(
            _float_value(row.get("spread_pct"), default=math.nan)
            for row in items
            if math.isfinite(_float_value(row.get("spread_pct"), default=math.nan))
        )
        mid_idx = len(spreads) // 2
        median_spread = None
        if spreads:
            median_spread = (
                spreads[mid_idx]
                if len(spreads) % 2
                else (spreads[mid_idx - 1] + spreads[mid_idx]) / 2.0
            )
        dte_values = [_float_value(row.get("dte"), default=math.nan) for row in items]
        dte_values = [value for value in dte_values if math.isfinite(value)]
        dte = int(min(dte_values)) if dte_values else None
        best_call = next((row for row in items if str(row.get("side") or "") == "call"), None)
        best_put = next((row for row in items if str(row.get("side") or "") == "put"), None)
        under_budget = [
            row
            for row in items
            if _float_value(row.get("premium_dollars"), default=math.inf) <= budget
        ]
        best_budget = max(
            under_budget or items, key=lambda row: _option_contract_rank_tuple(row, budget)
        )
        best_budget_premium = _float_value(best_budget.get("premium_dollars"), default=math.nan)
        summaries.append(
            {
                "expiry": expiry,
                "dte": dte,
                "dte_bucket": _option_dte_bucket(float(dte or 0)),
                "contracts": len(items),
                "calls": sum(str(row.get("side") or "") == "call" for row in items),
                "puts": sum(str(row.get("side") or "") == "put" for row in items),
                "median_spread_pct": _clean_value(median_spread),
                "under_budget_count": len(under_budget),
                "reviewable_count": sum(
                    str(row.get("readiness_label") or "") in {"ready", "review"} for row in items
                ),
                "primary_review_count": sum(
                    str(row.get("review_lane") or "") == "primary_review" for row in items
                ),
                "clean_swing_count": sum(
                    str(row.get("swing_fit_label") or "") == "clean_swing" for row in items
                ),
                "liquid_count": sum(
                    _float_value(row.get("openInterest"), default=0.0) >= 100
                    and _float_value(row.get("spread_pct"), default=1.0) <= 0.15
                    for row in items
                ),
                "best_call": _chain_contract_label(best_call),
                "best_put": _chain_contract_label(best_put),
                "best_budget": _chain_contract_label(best_budget),
                "best_budget_grade": _clean_value(best_budget.get("contract_grade")),
                "best_budget_fit": _clean_value(best_budget.get("budget_fit")),
                "best_budget_premium": _clean_value(
                    round(best_budget_premium, 2) if math.isfinite(best_budget_premium) else None
                ),
                "best_budget_spread_pct": _clean_value(best_budget.get("spread_pct")),
                "best_budget_score": _clean_value(
                    best_budget.get("swing_fit_score") or best_budget.get("contract_quality_score")
                ),
            }
        )
    return sorted(
        summaries,
        key=lambda row: (
            _float_value(row.get("under_budget_count"), default=0.0) > 0,
            _float_value(row.get("primary_review_count"), default=0.0),
            _float_value(row.get("clean_swing_count"), default=0.0),
            _option_grade_rank(row.get("best_budget_grade")),
            -_float_value(row.get("best_budget_spread_pct"), default=9.0),
            -_float_value(row.get("dte"), default=9999.0),
        ),
        reverse=True,
    )[:12]


def _option_chain_trade_plan(
    primary: dict[str, Any],
    status: str,
    risk_notes: list[str],
) -> dict[str, Any]:
    side = str(primary.get("side") or "").strip().lower()
    mid = _float_value(primary.get("mid"), default=math.nan)
    premium = _float_value(primary.get("premium_dollars"), default=math.nan)
    contracts_for_budget = int(_float_value(primary.get("contracts_for_budget"), default=0.0))
    quantity = 1 if contracts_for_budget >= 1 and math.isfinite(mid) and mid > 0 else 0
    action = (
        "review_contract"
        if status in {"primary_review", "secondary_review"}
        and quantity > 0
        and _row_profile_execution_ready(primary)
        else "watch_only"
    )
    contract = str(primary.get("contract_query") or "").strip()
    side_label = (
        "call" if side.startswith("call") else "put" if side.startswith("put") else "option"
    )
    entry_text = f"{mid:.2f}" if math.isfinite(mid) else "unknown"
    premium_text = f"${premium:.0f}" if math.isfinite(premium) else "unknown premium"
    checklist = [
        "Refresh live bid/ask before any paper/manual entry.",
        "Skip if spread widens beyond the selected filter.",
        "Confirm no same-symbol duplicate exposure.",
        "Check current news and earnings timing.",
    ]
    if risk_notes:
        checklist.append("Resolve listed risk notes before acting.")
    summary = (
        f"{quantity} contract {side_label} review at reference entry {entry_text}; "
        f"premium reference {premium_text}."
        if quantity > 0
        else "No budget-safe contract quantity under the current premium limit."
    )
    return {
        "action": action,
        "contract": contract,
        "side": side_label,
        "quantity": quantity,
        "entry_price_reference": _clean_value(mid),
        "premium_dollars_reference": _clean_value(premium),
        "max_loss_dollars_reference": _clean_value(premium),
        "stop_price_reference": _clean_value(primary.get("stop_price_reference")),
        "target_price_reference": _clean_value(primary.get("target_price_reference")),
        "stop_loss_dollars_reference": _clean_value(primary.get("risk_dollars_reference")),
        "target_gain_dollars_reference": _clean_value(primary.get("reward_dollars_reference")),
        "reward_risk_reference": _clean_value(primary.get("reward_risk_reference")),
        "breakeven_price": _clean_value(primary.get("breakeven_price")),
        "breakeven_move_pct": _clean_value(primary.get("breakeven_move_pct")),
        "budget_fit": _clean_value(primary.get("budget_fit")),
        "budget_usage_pct": _clean_value(primary.get("budget_usage_pct")),
        "contracts_for_budget": contracts_for_budget,
        "summary": summary,
        "checklist": checklist,
    }


def _open_exposure_for_symbol(data_dir: Path, symbol: str) -> dict[str, Any]:
    clean = str(symbol or "").strip().upper()
    if not clean:
        return {
            "symbol": clean,
            "has_open": False,
            "open_count": 0,
            "asset_counts": {},
            "labels": [],
        }
    try:
        report = build_positions(data_dir, asset="all", query=clean, status="all", limit=500)
    except Exception:
        return {
            "symbol": clean,
            "has_open": False,
            "open_count": 0,
            "asset_counts": {},
            "labels": [],
        }
    rows = [
        row
        for row in (report.get("rows") or [])
        if str(row.get("ticker_or_symbol") or "").upper() == clean
    ]
    asset_counts: dict[str, int] = {}
    labels: list[str] = []
    attention_count = 0
    for row in rows:
        asset = str(row.get("asset") or "unknown")
        asset_counts[asset] = asset_counts.get(asset, 0) + 1
        if row.get("attention"):
            attention_count += 1
        label = str(row.get("position_label") or "").strip()
        if label and label not in labels:
            labels.append(label)
    return {
        "symbol": clean,
        "has_open": bool(rows),
        "open_count": len(rows),
        "asset_counts": asset_counts,
        "attention_count": attention_count,
        "labels": labels[:5],
        "summary": (
            f"{len(rows)} open {clean} position(s)" if rows else f"No open {clean} positions found"
        ),
    }


def _chain_open_exposure_fields(exposure: dict[str, Any] | None) -> dict[str, Any]:
    exposure = exposure if isinstance(exposure, dict) else {}
    asset_counts = (
        exposure.get("asset_counts") if isinstance(exposure.get("asset_counts"), dict) else {}
    )
    return {
        "open_exposure_count": int(_float_value(exposure.get("open_count"), default=0.0)),
        "open_exposure_assets": ", ".join(
            f"{asset}:{count}" for asset, count in sorted(asset_counts.items())
        ),
        "open_exposure_summary": _clean_value(exposure.get("summary")),
        "open_exposure_attention_count": int(
            _float_value(exposure.get("attention_count"), default=0.0)
        ),
    }


def _add_open_exposure_warning(
    row: dict[str, Any], exposure: dict[str, Any] | None
) -> dict[str, Any]:
    out = dict(row)
    fields = _chain_open_exposure_fields(exposure)
    out.update(fields)
    if fields["open_exposure_count"] <= 0:
        return out
    warning = f"open exposure: {fields['open_exposure_summary']}"
    raw_flags = out.get("risk_flags")
    if isinstance(raw_flags, list):
        flags = [str(flag) for flag in raw_flags if str(flag).strip()]
    elif raw_flags:
        flags = [str(raw_flags)]
    else:
        flags = []
    if warning not in flags:
        flags.append(warning)
    out["risk_flags"] = flags
    return out


def _option_chain_decision_pack(
    rows: list[dict[str, Any]],
    quote_quality: str,
    source: str,
    exposure: dict[str, Any] | None = None,
) -> dict[str, Any]:
    if not rows:
        return {
            "status": "empty",
            "label": "No match",
            "primary": None,
            "alternatives": [],
            "risk_notes": ["No contracts matched the current filters."],
            "next_step": "Loosen filters or scan a different ticker.",
            "saveable_count": 0,
            "trade_plan": None,
            "open_exposure": exposure or {},
        }
    saveable = [
        row
        for row in rows
        if str(row.get("contract_grade") or "").upper() in {"A", "B"}
        and str(row.get("review_lane") or "") != "wait"
        and _row_profile_execution_ready(row)
    ]
    reviewable = [
        row
        for row in rows
        if str(row.get("readiness_label") or "") in {"ready", "review"}
        and _row_profile_execution_ready(row)
    ]
    primary = (saveable or reviewable or rows)[0]
    alternatives: list[dict[str, Any]] = []
    seen: set[str] = {str(primary.get("contract_query") or "")}
    for row in rows:
        query = str(row.get("contract_query") or "")
        if not query or query in seen:
            continue
        alternatives.append(row)
        seen.add(query)
        if len(alternatives) >= 3:
            break

    grade = str(primary.get("contract_grade") or "D").upper()
    lane = str(primary.get("review_lane") or "review")
    readiness = str(primary.get("readiness_label") or "review")
    risk_notes: list[str] = []
    exposure = exposure if isinstance(exposure, dict) else {}
    if exposure.get("has_open"):
        risk_notes.append(
            f"Duplicate exposure check: {exposure.get('summary')}; review open positions before adding."
        )
    if str(quote_quality or "").lower() != "live_or_broker":
        risk_notes.append("Quote may be free/delayed; refresh before acting.")
    spread = _float_value(primary.get("spread_pct"), default=math.nan)
    if math.isfinite(spread) and spread > 0.15:
        risk_notes.append(f"Spread is wide at {spread * 100:.1f}%.")
    oi = _float_value(primary.get("openInterest"), default=0.0)
    if oi < 100:
        risk_notes.append("Open interest is light.")
    budget_fit = str(primary.get("budget_fit") or "").lower()
    budget_usage = _float_value(primary.get("budget_usage_pct"), default=math.nan)
    if budget_fit == "over_budget":
        risk_notes.append("One contract is above the selected premium budget.")
    elif budget_fit == "stretch":
        risk_notes.append("One contract is near the selected premium budget.")
    elif math.isfinite(budget_usage) and budget_usage > 0.75:
        risk_notes.append(
            f"One contract uses {budget_usage * 100:.0f}% of the selected premium budget."
        )
    dte = _float_value(primary.get("dte"), default=0.0)
    if dte < MIN_SWING_OPTION_DTE:
        risk_notes.append(f"DTE is below the {MIN_SWING_OPTION_DTE}d swing minimum.")
    if grade not in {"A", "B"}:
        risk_notes.append("No A/B contract passed the current filters.")
    swing_label = str(primary.get("swing_fit_label") or "").lower()
    if swing_label in {"speculative_swing", "avoid"}:
        risk_notes.append(f"Swing fit is {swing_label.replace('_', ' ')}.")
    swing_warnings = primary.get("swing_fit_warnings")
    if isinstance(swing_warnings, list):
        risk_notes.extend(str(flag) for flag in swing_warnings[:3] if flag)
    row_flags = primary.get("risk_flags")
    if isinstance(row_flags, list):
        risk_notes.extend(str(flag) for flag in row_flags[:3] if flag)
    if str(primary.get("execution_profile") or "") == LEAPS_SWING_PROFILE.name:
        profile_blockers = list(primary.get("leaps_hard_blockers") or [])
        profile_blockers.extend(primary.get("leaps_data_blockers") or [])
        risk_notes.extend(f"LEAPS gate: {item}" for item in profile_blockers[:4])
    risk_notes = list(dict.fromkeys(risk_notes))[:6]

    profile_status = str(primary.get("leaps_swing_status") or "")
    if str(
        primary.get("execution_profile") or ""
    ) == LEAPS_SWING_PROFILE.name and not _row_profile_execution_ready(primary):
        status = "research_only" if profile_status == "research_only" else "blocked"
        label = "LEAPS research only" if status == "research_only" else "LEAPS blocked"
        next_step = (
            "Keep this as research. A fresh broker-live quote plus complete delta, "
            "confidence, and positive after-cost edge must pass before manual review."
        )
    elif saveable and grade == "A":
        status = "primary_review"
        label = "Best contract"
        next_step = "Save this contract, then refresh quotes before any paper/manual review."
    elif saveable:
        status = "secondary_review"
        label = "Reviewable contract"
        next_step = "Save for watchlist review; require a cleaner quote before acting."
    else:
        status = "watch_only"
        label = "Watch only"
        next_step = "Do not force this chain; wait for better liquidity, spread, or DTE."
    trade_plan = _option_chain_trade_plan(primary, status, risk_notes)

    return {
        "status": status,
        "label": label,
        "source": source,
        "quote_quality": quote_quality,
        "primary": {k: _clean_value(v) for k, v in primary.items()},
        "alternatives": [{k: _clean_value(v) for k, v in row.items()} for row in alternatives],
        "risk_notes": risk_notes,
        "next_step": next_step,
        "saveable_count": len(saveable),
        "trade_plan": trade_plan,
        "primary_grade": grade,
        "primary_lane": lane,
        "primary_readiness": readiness,
        "open_exposure": {k: _clean_value(v) for k, v in exposure.items()},
    }


def _chain_quote_provenance(
    provider_payload: dict[str, Any],
    provider_row: pd.Series | dict[str, Any] | None = None,
) -> tuple[str, str]:
    """Preserve provider-attributed quote time without inventing one.

    Row-level quote provenance wins because providers may timestamp individual
    contracts. Payload-level provenance is used only when it explicitly
    describes the returned quote set. Processing/export times are intentionally
    absent from this lookup.
    """

    def field(source: Any, key: str) -> str:
        value = _clean_value(source.get(key))
        return "" if value is None else str(value).strip()

    sources: list[tuple[Any, str]] = []
    if provider_row is not None:
        sources.append((provider_row, "provider_row"))
    sources.append((provider_payload, "provider_payload"))
    payload_basis = field(provider_payload, "source_quote_time_basis")
    payload_quote_at = field(provider_payload, "source_quote_at")
    for source, label in sources:
        direct = field(source, "source_quote_at")
        if direct:
            basis = field(source, "source_quote_time_basis")
            if not basis and direct == payload_quote_at:
                basis = payload_basis
            return direct, basis
        for key in (
            "quote_updated_at",
            "quote_timestamp",
            "quote_at",
            "quote_asof",
            "provider_response_received_at",
        ):
            value = field(source, key)
            if value:
                basis = field(source, "source_quote_time_basis") or (
                    "provider_response_received_at"
                    if key == "provider_response_received_at"
                    else f"{label}.{key}"
                )
                return value, basis
    return "", payload_basis


def build_option_chain_scan(
    query: str,
    data_dir: Path = DATA_DIR,
    side: str = "all",
    min_dte: int = MIN_SWING_OPTION_DTE,
    max_dte: int = 900,
    max_spread_pct: float = 0.25,
    max_premium: float = 0.0,
    min_open_interest: int = 0,
    limit: int = 80,
    preset: str = "custom",
) -> dict[str, Any]:
    """Inspect a ticker's current option chain using the existing free chain stack."""
    clean = str(query or "").strip()
    if not clean:
        return {"ok": False, "error": "ticker or company name is required", "rows": []}
    resolution = resolve_symbol(clean)
    ticker = str(resolution.get("symbol") or "").upper()
    if not ticker:
        return {
            "ok": False,
            "error": resolution.get("error") or "could not resolve ticker",
            "rows": [],
        }
    if ticker.endswith("=F") or ticker.startswith("^"):
        return {
            "ok": False,
            "error": f"{ticker} is not an equity or ETF option-chain symbol",
            "rows": [],
        }

    preset_norm, preset_cfg = _chain_preset_config(preset)
    if preset_norm != "custom":
        side = str(preset_cfg.get("side", side))
        min_dte = int(preset_cfg.get("min_dte", min_dte))
        max_dte = int(preset_cfg.get("max_dte", max_dte))
        max_spread_pct = float(preset_cfg.get("max_spread_pct", max_spread_pct))
        max_premium = float(preset_cfg.get("max_premium", max_premium))
        min_open_interest = int(preset_cfg.get("min_open_interest", min_open_interest))
    execution_profile = (
        LEAPS_SWING_PROFILE.name
        if preset_norm == "leaps"
        else str(preset_cfg.get("execution_profile") or SWING_EXECUTION_PROFILE.name)
    )

    side_norm = str(side or "all").strip().lower()
    if side_norm in {"c", "calls"}:
        side_norm = "call"
    elif side_norm in {"p", "puts"}:
        side_norm = "put"
    if side_norm not in {"all", "call", "put"}:
        side_norm = "all"

    try:
        blob = _fetch_option_chain_for_provider_status(ticker)
    except Exception as exc:
        return {
            "ok": False,
            "error": f"option-chain fetch failed: {exc}",
            "symbol": ticker,
            "rows": [],
        }
    if not blob or not blob.get("chains"):
        return {"ok": False, "error": "no option-chain data returned", "symbol": ticker, "rows": []}

    scan_generated_at = datetime.now(UTC).isoformat()
    spot = _float_value(blob.get("spot"), default=math.nan)
    source = str(blob.get("source") or "unknown")
    quote_quality = blob.get("quote_quality") or (
        "live_or_broker" if source == "tradier" else "free_or_delayed"
    )
    source_attempts = (
        blob.get("source_attempts") if isinstance(blob.get("source_attempts"), list) else []
    )
    open_exposure = _open_exposure_for_symbol(data_dir, ticker)
    today = datetime.now(UTC).date()
    rows: list[dict[str, Any]] = []
    rejection_examples: list[dict[str, Any]] = []
    rejected = 0
    rejection_reason_counts: dict[str, int] = {}
    total_contracts = 0

    for expiry, chain_df in (blob.get("chains") or {}).items():
        if not isinstance(chain_df, pd.DataFrame) or chain_df.empty:
            continue
        exp_ts = pd.to_datetime(str(expiry), errors="coerce", utc=True)
        if pd.isna(exp_ts):
            continue
        dte = int((exp_ts.date() - today).days)
        for _, raw in chain_df.iterrows():
            total_contracts += 1
            contract_side = str(raw.get("side") or "").strip().lower()
            if contract_side in {"c"}:
                contract_side = "call"
            elif contract_side in {"p"}:
                contract_side = "put"
            strike = _float_value(raw.get("strike"), default=math.nan)
            mid = _option_mid(raw)
            spread_pct = _option_spread_pct(raw, mid)
            oi = int(_float_value(raw.get("openInterest"), default=0.0))
            volume = int(_float_value(raw.get("volume"), default=0.0))
            premium = mid * 100.0 if math.isfinite(mid) else float("nan")
            source_quote_at, source_quote_time_basis = _chain_quote_provenance(blob, raw)
            moneyness = (
                ((strike - spot) / spot)
                if math.isfinite(strike) and math.isfinite(spot) and spot > 0
                else None
            )

            if side_norm != "all" and contract_side != side_norm:
                reasons = [f"side is not {side_norm}"]
            else:
                reasons = []
            if dte < min_dte or dte > max_dte:
                reasons.append("outside DTE range")
            if not math.isfinite(strike) or not math.isfinite(mid) or mid <= 0:
                reasons.append("missing strike or mid")
            if max_premium > 0 and (not math.isfinite(premium) or premium > max_premium):
                reasons.append("premium above budget")
            if spread_pct is not None and max_spread_pct > 0 and spread_pct > max_spread_pct:
                reasons.append("spread above filter")
            if oi < min_open_interest:
                reasons.append("open interest below filter")
            if reasons:
                rejected += 1
                unique_reasons = list(dict.fromkeys(reasons))
                for reason in unique_reasons:
                    rejection_reason_counts[reason] = rejection_reason_counts.get(reason, 0) + 1
                if len(rejection_examples) < 25:
                    rejection_examples.append(
                        {
                            "side": contract_side or "-",
                            "expiry": str(expiry),
                            "dte": dte,
                            "strike": _clean_value(strike),
                            "mid": _clean_value(round(mid, 4) if math.isfinite(mid) else None),
                            "premium_dollars": _clean_value(
                                round(premium, 2) if math.isfinite(premium) else None
                            ),
                            "spread_pct": _clean_value(spread_pct),
                            "openInterest": oi,
                            "volume": volume,
                            "reason": "; ".join(unique_reasons),
                            "reasons": unique_reasons,
                        }
                    )
                continue

            row = {
                "generated_at": scan_generated_at,
                "source_quote_at": source_quote_at,
                "source_quote_time_basis": source_quote_time_basis,
                "symbol": ticker,
                "side": contract_side,
                "underlying_type": (
                    "index"
                    if is_known_index_option_symbol(ticker)
                    else SWING_EXECUTION_OPTION_UNDERLYING_TYPE
                ),
                "expiry": str(expiry),
                "chain_source": source,
                "quote_quality": quote_quality,
                "data_delay": _clean_value(blob.get("data_delay")),
                "dte": dte,
                "dte_bucket": _option_dte_bucket(float(dte)),
                "strike": strike,
                "bid": _clean_value(raw.get("bid")),
                "ask": _clean_value(raw.get("ask")),
                "mid": round(mid, 4),
                "premium_dollars": round(premium, 2),
                "spread_pct": _clean_value(spread_pct),
                "volume": volume,
                "openInterest": oi,
                "impliedVolatility": _clean_value(raw.get("impliedVolatility")),
                "delta": _clean_value(raw.get("delta")),
                "moneyness_pct": _clean_value(moneyness),
                "confidence": _clean_value(raw.get("confidence")),
                "after_cost_edge_pct": _clean_value(
                    raw.get("after_cost_edge_pct")
                    if raw.get("after_cost_edge_pct") is not None
                    else raw.get("net_edge_pct")
                ),
                "execution_profile": execution_profile,
                "strategy_evidence_lane": (
                    LEAPS_EVIDENCE_LANE if execution_profile == LEAPS_SWING_PROFILE.name else ""
                ),
            }
            row["contract_query"] = (
                f"{ticker} {expiry} {'C' if contract_side == 'call' else 'P'} {strike:g}"
                if math.isfinite(strike)
                else ""
            )
            row.update(
                _option_chain_trade_refs(
                    row,
                    spot,
                    max_premium,
                    execution_profile=execution_profile,
                )
            )
            row.update(_option_chain_swing_fit(row, max_premium))
            row["contract_quality_score"] = round(_option_chain_score(row), 3)
            row.update(_option_contract_readiness(row, str(quote_quality)))
            row.update(_option_contract_grade(row, max_premium))
            if execution_profile == LEAPS_SWING_PROFILE.name:
                quote_age_minutes = _iso_age_minutes(source_quote_at)
                quote_age_seconds = (
                    quote_age_minutes * 60.0 if quote_age_minutes is not None else None
                )
                row.update(
                    _leaps_swing_scan_fields(
                        row,
                        quote_age_seconds=quote_age_seconds,
                        account_budget=max_premium if max_premium > 0 else None,
                    )
                )
                if not row["leaps_execution_ready"]:
                    row["review_lane"] = (
                        "leaps_research_only"
                        if row["leaps_swing_status"] == "research_only"
                        else "leaps_blocked"
                    )
                    row["readiness_label"] = "wait"
                    profile_flags = [f"LEAPS {row['leaps_swing_status'].replace('_', ' ')}"]
                    profile_flags.extend(row.get("leaps_hard_blockers") or [])
                    profile_flags.extend(row.get("leaps_data_blockers") or [])
                    row["risk_flags"] = list(
                        dict.fromkeys(list(row.get("risk_flags") or []) + profile_flags)
                    )[:10]
            row["chain_factor_breakdown"] = _option_chain_factor_breakdown(row, max_premium)
            row["chain_factor_summary"] = _swing_factor_summary(row["chain_factor_breakdown"])
            rows.append(row)

    rows = sorted(
        rows,
        key=lambda r: (
            {"execution_ready": 2, "research_only": 1, "blocked": 0}.get(
                str(r.get("leaps_swing_status") or ""),
                2,
            ),
            _float_value(r.get("leaps_quality_score"), default=-1.0),
            _float_value(r.get("swing_fit_score"), default=-999.0),
            _float_value(r.get("contract_quality_score"), default=-999.0),
            -abs(_float_value(r.get("moneyness_pct"), default=99.0)),
            -_float_value(r.get("dte"), default=9999.0),
        ),
        reverse=True,
    )
    limited = [{k: _clean_value(v) for k, v in row.items()} for row in rows[:limit]]
    summary = _option_chain_scan_summary(rows, max_premium)
    expiry_summary = _option_chain_expiry_summary(rows, max_premium)
    decision = _option_chain_decision_pack(rows, str(quote_quality), source, open_exposure)
    rejection_reason_counts = dict(
        sorted(rejection_reason_counts.items(), key=lambda item: (-item[1], item[0]))
    )
    top_rejection_reasons = _top_reason_rows(rejection_reason_counts)
    source_quote_at, source_quote_time_basis = _chain_quote_provenance(blob)
    return {
        "ok": True,
        "generated_at": scan_generated_at,
        "source_quote_at": source_quote_at,
        "source_quote_time_basis": source_quote_time_basis,
        "query": clean,
        "symbol": ticker,
        "resolution": resolution,
        "source": source,
        "quote_quality": quote_quality,
        "data_delay": _clean_value(blob.get("data_delay")),
        "source_attempts": [
            {k: _clean_value(v) for k, v in row.items()} for row in source_attempts
        ],
        "open_exposure": open_exposure,
        "providers_checked": len(source_attempts),
        "spot": _clean_value(spot),
        "total_expirations": len(blob.get("expirations") or []),
        "total_contracts": total_contracts,
        "filtered_count": len(rows),
        "rejected_count": rejected,
        "rejection_reason_counts": rejection_reason_counts,
        "top_rejection_reasons": top_rejection_reasons,
        "rejection_examples": rejection_examples,
        "preset": preset_norm,
        "preset_label": preset_cfg.get("label"),
        "preset_description": preset_cfg.get("description"),
        "execution_profile": execution_profile,
        "strategy_evidence_lane": (
            LEAPS_EVIDENCE_LANE if execution_profile == LEAPS_SWING_PROFILE.name else ""
        ),
        "profile_policy_version": (
            LEAPS_SWING_PROFILE.policy_version
            if execution_profile == LEAPS_SWING_PROFILE.name
            else SWING_EXECUTION_PROFILE.strategy_version
        ),
        "scan_summary": summary,
        "decision": decision,
        "expiry_summary": expiry_summary,
        "filters": {
            "side": side_norm,
            "min_dte": min_dte,
            "max_dte": max_dte,
            "max_spread_pct": max_spread_pct,
            "max_premium": max_premium,
            "min_open_interest": min_open_interest,
        },
        "summary": summary,
        "rows": limited,
        "notes": [
            "Option-chain scan uses Optedge's existing provider stack.",
            "Free/keyless sources may be delayed, incomplete, or blocked for some tickers.",
            "This view inspects contracts only; it does not place trades.",
        ]
        + (
            [
                "LEAPS means 365-900 contract DTE; it does not mean a one-year hold.",
                "The manual LEAPS swing policy reviews at 3/5/10 sessions and caps the hold at 20 sessions.",
                "Free/delayed quotes remain research-only and cannot enter an execution lane.",
            ]
            if execution_profile == LEAPS_SWING_PROFILE.name
            else []
        ),
    }


def _chain_candidate_exclusion(row: dict[str, Any] | None) -> str | None:
    if not isinstance(row, dict):
        return None
    warnings = [
        str(item or "").strip().lower()
        for item in (row.get("warnings") or row.get("risk_flags") or [])
        if str(item or "").strip()
    ]
    flags = {
        str(item or "").strip().lower()
        for item in (row.get("market_structure_risk_flags") or row.get("risk_flags") or [])
        if str(item or "").strip()
    }
    if (
        bool(row.get("active_halt"))
        or "active_halt" in flags
        or any("active trading halt" in item for item in warnings)
    ):
        return "active trading halt"
    review_action = str(row.get("review_action") or "").strip().lower()
    readiness = str(row.get("readiness_label") or "").strip().lower()
    trade_status = str(row.get("trade_status") or "").strip().lower()
    if review_action == "wait" or readiness == "wait" or trade_status == "wait":
        return "wait-lane setup"
    return None


def _chain_candidate_fit(
    source: str,
    score: Any = None,
    row: dict[str, Any] | None = None,
    manual: bool = False,
) -> dict[str, Any]:
    score_val = _float_value(score, default=math.nan)
    asset = str(row.get("asset") or "").strip().lower() if isinstance(row, dict) else ""
    review_action = (
        str(row.get("review_action") or "").strip().lower() if isinstance(row, dict) else ""
    )
    source_norm = str(source or "").strip().lower()
    if manual:
        priority = 92.0
        fit = "manual typed symbol"
        label = "Manual chain scan"
    elif review_action == "review_now" or (math.isfinite(score_val) and score_val >= 85):
        priority = 88.0
        fit = "high-conviction swing candidate"
        label = "High priority"
    elif review_action == "shortlist" or (math.isfinite(score_val) and score_val >= 70):
        priority = 74.0
        fit = "shortlisted swing candidate"
        label = "Shortlist"
    elif review_action == "watch" or (math.isfinite(score_val) and score_val >= 55):
        priority = 58.0
        fit = "watchlist swing candidate"
        label = "Watch"
    else:
        priority = 46.0
        fit = "exploratory chain candidate"
        label = "Explore"

    if asset == "option":
        overlay = "existing option thesis -> refresh chain"
    elif asset == "share":
        overlay = "share swing -> 3m+ options overlay"
    elif asset == "value":
        overlay = "value setup -> 3m+ options overlay"
    elif "climate-gated" in source_norm:
        overlay = "climate-gated setup -> 3m+ chain"
    elif "watchlist" in source_norm:
        overlay = "watchlist symbol -> 3m+ chain"
    else:
        overlay = "symbol -> 3m+ chain"

    warning_count = (
        _float_value(row.get("warning_count"), default=0.0) if isinstance(row, dict) else 0.0
    )
    if warning_count > 0 and not manual:
        priority -= min(12.0, warning_count * 3.0)
        fit += " with warnings"
    return {
        "chain_fit_label": fit,
        "chain_candidate_label": f"{label}: {overlay}",
        "chain_priority": _clean_value(round(_clamp(priority, 0.0, 100.0), 1)),
    }


def _bulk_chain_symbol_selection(data_dir: Path, query: str = "", limit: int = 8) -> dict[str, Any]:
    limit = max(1, min(int(limit or 8), 20))
    rows: list[dict[str, Any]] = []
    excluded: list[dict[str, Any]] = []
    seen: set[str] = set()
    blocked_auto: dict[str, str] = {}

    def add(
        symbol: Any,
        source: str,
        score: Any = None,
        reason: str = "",
        row: dict[str, Any] | None = None,
        manual: bool = False,
    ) -> None:
        clean = str(symbol or "").strip().upper()
        if not clean or clean in seen:
            return
        if clean.endswith("=F") or clean.startswith("^"):
            return
        candidate = {
            "symbol": clean,
            "source": source,
            "score": _clean_value(score),
            "reason": reason or source,
            "asset": _clean_value(row.get("asset")) if isinstance(row, dict) else None,
            "lane": _clean_value(row.get("lane")) if isinstance(row, dict) else None,
            "review_action": _clean_value(row.get("review_action"))
            if isinstance(row, dict)
            else None,
            "readiness_label": _clean_value(row.get("readiness_label"))
            if isinstance(row, dict)
            else None,
            "warning_count": _clean_value(row.get("warning_count"))
            if isinstance(row, dict)
            else None,
            "market_structure_risk_score": (
                _clean_value(row.get("market_structure_risk_score"))
                if isinstance(row, dict)
                else None
            ),
        }
        candidate.update(_chain_candidate_fit(source, score, row, manual=manual))
        if clean in blocked_auto and not manual:
            skipped = dict(candidate)
            skipped["reason_excluded"] = blocked_auto[clean]
            excluded.append(skipped)
            return
        reason_excluded = None if manual else _chain_candidate_exclusion(row)
        if reason_excluded:
            skipped = dict(candidate)
            skipped["reason_excluded"] = reason_excluded
            excluded.append(skipped)
            if "halt" in reason_excluded:
                blocked_auto[clean] = reason_excluded
            return
        seen.add(clean)
        rows.append(candidate)

    raw_query = str(query or "").strip()
    if raw_query:
        for token in re.split(r"[,;\s]+", raw_query):
            token = token.strip()
            if not token:
                continue
            resolution = resolve_symbol(token)
            add(resolution.get("symbol") or token, "typed shortlist", 1.0, token, manual=True)
        return {"candidates": rows[:limit], "excluded_candidates": excluded}

    try:
        gated = build_climate_gated_setups(
            data_dir, per_asset=6, limit=max(limit, 10), include_held=False
        )
        for row in gated.get("rows", []):
            asset = str(row.get("asset") or "")
            if asset not in {"option", "share", "value"}:
                continue
            reasons = (
                row.get("climate_gate_reasons")
                if isinstance(row.get("climate_gate_reasons"), list)
                else []
            )
            reason = "; ".join(str(item) for item in reasons[:3] if item) or row.get("setup") or ""
            add(
                row.get("ticker_or_symbol"),
                f"climate-gated {asset} setup",
                row.get("climate_gate_score") or row.get("score"),
                reason,
                row,
            )
            if len(rows) >= limit:
                return {"candidates": rows, "excluded_candidates": excluded}
    except Exception:
        pass

    try:
        scout = build_swing_scout(
            data_dir,
            limit=max(limit * 2, 12),
            asset="all",
            min_score=55,
            include_wait=False,
        )
        for row in scout.get("rows", []):
            asset = str(row.get("asset") or "")
            if asset not in {"option", "share", "value"}:
                continue
            reasons = row.get("reasons") if isinstance(row.get("reasons"), list) else []
            reason = (
                "; ".join(str(item) for item in reasons[:3] if item)
                or row.get("lane")
                or row.get("setup")
                or ""
            )
            add(
                row.get("ticker_or_symbol"),
                f"swing scout {asset}",
                row.get("swing_scout_score"),
                reason,
                row,
            )
            if len(rows) >= limit:
                return {"candidates": rows, "excluded_candidates": excluded}
    except Exception:
        pass

    setups = build_best_setups(data_dir, per_asset=6, limit=24)
    for row in setups.get("rows", []):
        asset = str(row.get("asset") or "")
        if asset not in {"option", "share", "value"}:
            continue
        add(
            row.get("ticker_or_symbol"),
            f"best {asset} setup",
            row.get("score"),
            row.get("reason_selected") or row.get("setup") or "",
            row,
        )
        if len(rows) >= limit:
            return {"candidates": rows, "excluded_candidates": excluded}

    # The action-oriented views can legitimately contain fewer than ten rows
    # when validation is blocked.  Fill the research universe from the latest
    # ranked snapshots so a ten-ticker chain comparison still covers ten
    # distinct underlyings without weakening any execution gate.
    for asset_name in ("option", "share", "value"):
        spec = OPPORTUNITY_SPECS.get(asset_name) or {}
        frame = _read_parquet(_latest_file(data_dir, str(spec.get("pattern") or "")))
        symbol_col = str(spec.get("symbol_col") or "ticker")
        if frame.empty or symbol_col not in frame.columns:
            continue
        for _, raw in frame.head(max(limit * 8, 80)).iterrows():
            item = {str(key): value for key, value in raw.to_dict().items()}
            item.setdefault("asset", asset_name)
            reason = str(
                item.get("reason_selected")
                or item.get("signal")
                or item.get("reasoning")
                or f"latest ranked {asset_name} idea"
            )
            add(
                item.get(symbol_col),
                f"latest ranked {asset_name}",
                _opportunity_score(raw),
                reason,
                item,
            )
            if len(rows) >= limit:
                return {"candidates": rows, "excluded_candidates": excluded}

    for item in load_watchlist(data_dir).get("entries", []):
        add(item.get("symbol"), "research watchlist", 0.75, item.get("query") or "")
        if len(rows) >= limit:
            return {"candidates": rows, "excluded_candidates": excluded}

    return {"candidates": rows[:limit], "excluded_candidates": excluded}


def _bulk_chain_symbol_candidates(
    data_dir: Path, query: str = "", limit: int = 8
) -> list[dict[str, Any]]:
    """Compatibility wrapper for callers that only need the accepted queue."""
    return _bulk_chain_symbol_selection(data_dir, query=query, limit=limit)["candidates"]


def _chain_grade_rank(row: dict[str, Any]) -> int:
    return _option_grade_rank(row.get("contract_grade"))


def build_option_chain_batch(
    data_dir: Path = DATA_DIR,
    query: str = "",
    side: str = "all",
    min_dte: int = MIN_SWING_OPTION_DTE,
    max_dte: int = 900,
    max_spread_pct: float = 0.25,
    max_premium: float = 500.0,
    min_open_interest: int = 0,
    preset: str = "swing",
    symbols_limit: int = 6,
    contracts_per_symbol: int = 4,
    limit: int = 18,
) -> dict[str, Any]:
    """Scan option chains for a compact shortlist of symbols using free/provider-stack data."""
    symbols_limit = max(1, min(int(symbols_limit or 6), 20))
    contracts_per_symbol = max(1, min(int(contracts_per_symbol or 4), 12))
    limit = max(1, min(int(limit or 18), 80))
    selection = _bulk_chain_symbol_selection(data_dir, query=query, limit=symbols_limit)
    candidates = selection["candidates"]
    excluded_candidates = selection["excluded_candidates"]

    rows: list[dict[str, Any]] = []
    symbol_summaries: list[dict[str, Any]] = []
    errors: list[dict[str, Any]] = []
    grade_counts: dict[str, int] = {}
    source_counts: dict[str, int] = {}

    for idx, candidate in enumerate(candidates, start=1):
        symbol = str(candidate.get("symbol") or "").strip().upper()
        if not symbol:
            continue
        report = build_option_chain_scan(
            symbol,
            data_dir,
            side=side,
            min_dte=min_dte,
            max_dte=max_dte,
            max_spread_pct=max_spread_pct,
            max_premium=max_premium,
            min_open_interest=min_open_interest,
            limit=contracts_per_symbol,
            preset=preset,
        )
        summary = {
            "symbol": symbol,
            "candidate_source": candidate.get("source"),
            "candidate_score": candidate.get("score"),
            "candidate_reason": candidate.get("reason"),
            "ok": bool(report.get("ok")),
            "source": _clean_value(report.get("source")),
            "quote_quality": _clean_value(report.get("quote_quality")),
            "data_delay": _clean_value(report.get("data_delay")),
            "source_quote_at": _clean_value(report.get("source_quote_at")),
            "source_quote_time_basis": _clean_value(report.get("source_quote_time_basis")),
            "total_contracts": _clean_value(report.get("total_contracts")),
            "filtered_count": _clean_value(report.get("filtered_count")),
            "rejected_count": _clean_value(report.get("rejected_count")),
            "top_rejects": "; ".join(
                f"{row.get('reason')} ({row.get('count')})"
                for row in (report.get("top_rejection_reasons") or [])[:3]
                if row.get("reason")
            ),
            "grades": _clean_value((report.get("scan_summary") or {}).get("grade_counts")),
            "best_reviewable": _clean_value(
                (report.get("scan_summary") or {}).get("best_reviewable")
            ),
        }
        exposure_fields = _chain_open_exposure_fields(report.get("open_exposure"))
        summary.update(exposure_fields)
        symbol_summaries.append(summary)
        if not report.get("ok"):
            errors.append(
                {
                    "symbol": symbol,
                    "candidate_source": candidate.get("source"),
                    "error": report.get("error") or "chain scan failed",
                }
            )
            continue
        source = str(report.get("source") or "unknown")
        source_counts[source] = source_counts.get(source, 0) + 1
        for rank, row in enumerate(report.get("rows", [])[:contracts_per_symbol], start=1):
            item = _add_open_exposure_warning(row, report.get("open_exposure"))
            item["candidate_rank"] = idx
            item["candidate_source"] = candidate.get("source")
            item["candidate_score"] = candidate.get("score")
            item["candidate_reason"] = candidate.get("reason")
            item["symbol_contract_rank"] = rank
            item["batch_source"] = source
            item["batch_quote_quality"] = _clean_value(report.get("quote_quality"))
            item["batch_data_delay"] = _clean_value(report.get("data_delay"))
            if not item.get("source_quote_at"):
                item["source_quote_at"] = _clean_value(report.get("source_quote_at"))
            if not item.get("source_quote_time_basis"):
                item["source_quote_time_basis"] = _clean_value(
                    report.get("source_quote_time_basis")
                )
            rows.append(item)
            grade = str(item.get("contract_grade") or "ungraded")
            grade_counts[grade] = grade_counts.get(grade, 0) + 1

    rows = sorted(
        rows,
        key=lambda row: (
            _chain_grade_rank(row),
            str(row.get("review_lane") or "") == "primary_review",
            _float_value(row.get("contract_quality_score"), default=0.0),
            _float_value(row.get("openInterest"), default=0.0),
            -_float_value(row.get("spread_pct"), default=9.0),
        ),
        reverse=True,
    )[:limit]
    return {
        "ok": True,
        "generated_at": datetime.now(UTC).isoformat(),
        "query": str(query or "").strip(),
        "preset": _chain_preset_config(preset)[0],
        "candidate_count": len(candidates),
        "candidate_skipped_count": len(excluded_candidates),
        "symbols_scanned": len(symbol_summaries),
        "successful_scans": sum(1 for row in symbol_summaries if row.get("ok")),
        "error_count": len(errors),
        "row_count": len(rows),
        "open_exposure_count": sum(
            int(_float_value(row.get("open_exposure_count"), default=0.0))
            for row in symbol_summaries
        ),
        "open_exposure_symbols": [
            row.get("symbol")
            for row in symbol_summaries
            if _float_value(row.get("open_exposure_count"), default=0.0) > 0
        ],
        "grade_counts": grade_counts,
        "source_counts": source_counts,
        "candidates": candidates,
        "excluded_candidates": excluded_candidates,
        "symbol_summaries": symbol_summaries,
        "errors": errors,
        "rows": [{k: _clean_value(v) for k, v in row.items()} for row in rows],
        "notes": [
            "Bulk chain scan ranks contracts across a small shortlist so free sources are not hammered.",
            "Blank symbol input uses climate-gated setups, swing scout winners, latest best setups, ranked snapshot fallbacks, and the research watchlist.",
            "Free/keyless chain quotes may be delayed or incomplete; verify before any manual paper entry.",
        ],
    }


def _shortlist_cell(value: Any) -> Any:
    value = _clean_value(value)
    if isinstance(value, list):
        cleaned = []
        for item in value:
            clean_item = _clean_value(item)
            if clean_item is None or clean_item == "":
                continue
            if isinstance(clean_item, (dict, list)):
                cleaned.append(json.dumps(clean_item, sort_keys=True))
            else:
                cleaned.append(str(clean_item))
        return "; ".join(cleaned)
    if isinstance(value, dict):
        return json.dumps(value, sort_keys=True)
    return value


def write_option_chain_shortlist(
    report: dict[str, Any], data_dir: Path = DATA_DIR
) -> dict[str, Any]:
    """Write the latest 3m+ option-chain shortlist as portable review artifacts."""
    if not isinstance(report, dict):
        return {"ok": False, "error": "chain shortlist report is required"}
    rows = report.get("rows")
    if not isinstance(rows, list) or not rows:
        return {"ok": False, "error": "no chain shortlist rows to export"}

    generated_at = datetime.now(UTC).isoformat()
    source_generated_at = str(report.get("generated_at") or "")
    normalized: list[dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        item = {col: _shortlist_cell(row.get(col)) for col in CHAIN_SHORTLIST_COLUMNS}
        item["generated_at"] = item.get("generated_at") or source_generated_at
        if not item.get("quote_quality"):
            item["quote_quality"] = _shortlist_cell(row.get("batch_quote_quality"))
        if not item.get("data_delay"):
            item["data_delay"] = _shortlist_cell(row.get("batch_data_delay"))
        if not item.get("chain_source"):
            item["chain_source"] = _shortlist_cell(row.get("batch_source"))
        normalized.append(item)

    if not normalized:
        return {"ok": False, "error": "no valid chain shortlist rows to export"}

    data_dir = Path(data_dir)
    data_dir.mkdir(parents=True, exist_ok=True)
    csv_path = data_dir / "option_chain_shortlist.csv"
    json_path = data_dir / "option_chain_shortlist.json"
    quality_summary = _chain_shortlist_quality_summary(pd.DataFrame(normalized))
    pd.DataFrame(normalized, columns=CHAIN_SHORTLIST_COLUMNS).to_csv(csv_path, index=False)
    payload = {
        "ok": True,
        "generated_at": generated_at,
        "source_generated_at": source_generated_at,
        "count": len(normalized),
        "preset": report.get("preset"),
        "query": report.get("query"),
        "candidate_count": report.get("candidate_count"),
        "symbols_scanned": report.get("symbols_scanned"),
        "successful_scans": report.get("successful_scans"),
        "grade_counts": report.get("grade_counts") or {},
        "source_counts": report.get("source_counts") or {},
        "quality_summary": quality_summary,
        "provider_summary": {
            "source_counts": report.get("source_counts") or {},
            "symbols_scanned": report.get("symbols_scanned"),
            "successful_scans": report.get("successful_scans"),
            "error_count": report.get("error_count"),
            "open_exposure_count": report.get("open_exposure_count"),
            "open_exposure_symbols": report.get("open_exposure_symbols") or [],
        },
        "notes": [
            "External review shortlist only; no trades are placed.",
            "Rows come from Optedge's free/provider option-chain batch scan.",
            "Free/keyless option-chain quotes may be delayed or incomplete.",
        ],
        "rows": normalized,
    }
    json_path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")
    return {
        "ok": True,
        "count": len(normalized),
        "csv_path": str(csv_path),
        "json_path": str(json_path),
        "artifacts": {
            "csv": "/artifact/option-chain-shortlist",
            "json": "/artifact/option-chain-shortlist-json",
        },
        "quality_summary": quality_summary,
        "notes": payload["notes"],
    }


def _is_actionable(row: pd.Series) -> bool:
    status = str(row.get("trade_status") or "").strip().lower()
    if status in {"watch", "skip", "blocked"}:
        return False
    asset = str(row.get("asset") or "").lower()
    if asset == "option":
        if str(row.get("swing_fit_label") or "").strip().lower() == "avoid":
            return False
        return _float_value(row.get("suggested_contracts")) > 0
    if asset == "futures":
        return _float_value(row.get("suggested_contracts")) > 0
    if asset == "share":
        return _float_value(row.get("suggested_dollars")) > 0
    return True


def _opportunity_records(df: pd.DataFrame, asset: str, limit: int) -> list[dict[str, Any]]:
    if df.empty:
        return []
    spec = OPPORTUNITY_SPECS[asset]
    cols = [c for c in spec["columns"] if c in df.columns]
    if "asset" not in cols:
        cols.insert(0, "asset")
    records: list[dict[str, Any]] = []
    for _, row in df[cols].head(limit).iterrows():
        records.append({str(k): _clean_value(v) for k, v in row.to_dict().items()})
    return records


def _short_number(value: Any) -> str:
    number = _float_value(value, default=math.nan)
    if math.isfinite(number):
        return f"{number:g}"
    return str(value or "").strip()


def _setup_symbol(row: pd.Series, asset: str, spec: dict[str, Any]) -> str:
    symbol_col = str(spec.get("symbol_col") or "ticker")
    return str(row.get(symbol_col) or row.get("ticker") or row.get("symbol") or "").strip().upper()


def _setup_label(row: pd.Series, asset: str, symbol: str) -> str:
    if asset == "option":
        side_raw = str(row.get("side") or "").strip().lower()
        side = (
            "C"
            if side_raw.startswith("c")
            else "P"
            if side_raw.startswith("p")
            else side_raw.upper()
        )
        strike = _short_number(row.get("strike"))
        expiry = str(row.get("expiry") or "").strip()
        return " ".join(part for part in (symbol, side, strike, expiry) if part)
    if asset == "futures":
        direction = str(row.get("direction") or "").strip().upper()
        name = str(row.get("name") or row.get("contract") or "").strip()
        return " ".join(part for part in (symbol, direction or None, name or None) if part)
    if asset == "value":
        bucket = str(row.get("value_bucket") or "value").strip()
        return f"{symbol} {bucket}".strip()
    return f"{symbol} share".strip()


def _setup_entry_price(row: pd.Series, asset: str) -> Any:
    for col in ("mid", "entry_price", "spot", "price", "last"):
        if col in row and _clean_value(row.get(col)) is not None:
            return _clean_value(row.get(col))
    return None


def _setup_size(row: pd.Series, asset: str) -> str:
    if asset in {"option", "futures"}:
        contracts = _float_value(row.get("suggested_contracts"), default=0.0)
        if contracts > 0:
            return f"{contracts:g} contract(s)"
        return "-"
    if asset == "share":
        dollars = _float_value(row.get("suggested_dollars"), default=0.0)
        if dollars > 0:
            return f"${dollars:,.0f}"
    return "-"


def _setup_quality(row: pd.Series, asset: str) -> str:
    pieces: list[str] = []
    if asset == "option":
        spread = _float_value(row.get("spread_pct"), default=math.nan)
        buyer_edge = _float_value(row.get("buyer_edge_pct"), default=math.nan)
        if math.isfinite(spread):
            pieces.append(f"spread {spread * 100:.1f}%")
        if math.isfinite(buyer_edge):
            pieces.append(f"buyer edge {buyer_edge * 100:+.1f}%")
        source = str(row.get("chain_source") or row.get("quote_quality") or "").strip()
        if source:
            pieces.append(source)
    elif asset == "futures":
        hv20 = _float_value(row.get("hv20"), default=math.nan)
        if math.isfinite(hv20):
            pieces.append(f"HV20 {hv20:.2f}")
        if row.get("using_micro") is not None:
            pieces.append("micro" if bool(row.get("using_micro")) else "full")
    elif asset == "share":
        ev = _float_value(row.get("ev_pct"), default=math.nan)
        if math.isfinite(ev):
            pieces.append(f"EV {ev * 100:.1f}%")
    elif asset == "value":
        pe = _float_value(row.get("pe"), default=math.nan)
        if math.isfinite(pe):
            pieces.append(f"P/E {pe:.1f}")
        fcf = _float_value(row.get("fcf_yield"), default=math.nan)
        if math.isfinite(fcf):
            pieces.append(f"FCF {fcf * 100:.1f}%")
    return " | ".join(pieces[:3]) or "-"


def _setup_reason(row: pd.Series, asset: str) -> str:
    confidence = _float_value(row.get("confidence"), default=math.nan)
    score = _opportunity_score(row)
    parts = [f"score {score:.2f}"]
    if math.isfinite(confidence) and confidence > 0:
        parts.append(f"conf {confidence:.0f}")
    if asset == "option":
        edge = _float_value(row.get("buyer_edge_pct"), default=math.nan)
        edge_label = "buyer edge"
        if not math.isfinite(edge):
            edge = _float_value(row.get("net_edge_pct"), default=math.nan)
            edge_label = "pricing anomaly"
        if math.isfinite(edge):
            parts.append(f"{edge_label} {edge * 100:.1f}%")
    elif asset == "futures":
        fut_score = _float_value(row.get("futures_score"), default=math.nan)
        if math.isfinite(fut_score):
            parts.append(f"futures {fut_score:.2f}")
    elif asset == "value":
        bucket = str(row.get("value_bucket") or "").strip()
        if bucket:
            parts.append(bucket)
    return ", ".join(parts)


def _readiness(score: int, flags: list[str]) -> dict[str, Any]:
    clean_score = max(0, min(100, int(score)))
    if clean_score >= 80 and not flags:
        label = "ready"
        next_step = "Review exact quote and thesis."
    elif clean_score >= 65:
        label = "review"
        next_step = "Check flagged items before acting."
    else:
        label = "wait"
        next_step = "Do not act until flags improve."
    return {
        "readiness_score": clean_score,
        "readiness_label": label,
        "risk_flags": flags[:5],
        "next_step": next_step,
    }


def _setup_readiness(row: pd.Series, asset: str) -> dict[str, Any]:
    score = 100
    flags: list[str] = []
    confidence = _float_value(row.get("confidence"), default=math.nan)
    status = str(row.get("trade_status") or "").strip().lower()
    freshness = str(row.get("snapshot_freshness") or "").strip().lower()
    stop = _float_value(row.get("stop_price"), default=math.nan)
    target = _float_value(row.get("target_price"), default=math.nan)

    if status in {"watch", "skip", "blocked"}:
        score -= 35
        flags.append(f"status {status}")
    if math.isfinite(confidence):
        if confidence < 55:
            score -= 25
            flags.append("low confidence")
        elif confidence < 70:
            score -= 10
            flags.append("medium confidence")
    elif asset != "value":
        score -= 10
        flags.append("missing confidence")
    if freshness == "stale":
        score -= 20
        flags.append("stale snapshot")
    elif freshness == "aging":
        score -= 8
        flags.append("aging snapshot")

    if asset in {"option", "share", "futures"}:
        if not math.isfinite(stop) or stop <= 0:
            score -= 15
            flags.append("missing stop")
        if not math.isfinite(target) or target <= 0:
            score -= 10
            flags.append("missing target")

    if asset == "option":
        dte = _float_value(row.get("dte"), default=math.nan)
        spread = _float_value(row.get("spread_pct"), default=math.nan)
        buyer_edge = _float_value(row.get("buyer_edge_pct"), default=math.nan)
        contracts = _float_value(row.get("suggested_contracts"), default=0.0)
        quote_quality = str(row.get("quote_quality") or row.get("chain_source") or "").lower()
        swing_label = str(row.get("swing_fit_label") or "").strip().lower()
        swing_score = _float_value(row.get("swing_fit_score"), default=math.nan)
        if not math.isfinite(dte) or dte < MIN_SWING_OPTION_DTE:
            score -= 45
            flags.append("below 90 DTE")
        if math.isfinite(spread):
            if spread > 0.25:
                score -= 30
                flags.append("very wide spread")
            elif spread > 0.15:
                score -= 12
                flags.append("wide spread")
        else:
            score -= 8
            flags.append("missing spread")
        if contracts <= 0:
            score -= 40
            flags.append("no contract size")
        if math.isfinite(buyer_edge) and buyer_edge < 0:
            score -= 35
            flags.append("negative buyer edge after spread")
        if swing_label == "avoid":
            score -= 45
            flags.append("avoid swing fit")
        elif swing_label == "speculative_swing":
            score -= 14
            flags.append("speculative swing fit")
        elif swing_label == "clean_swing" and math.isfinite(swing_score) and swing_score >= 85:
            score += 6
        elif swing_label == "reviewable_swing":
            score += 2
        if quote_quality in {"", "unknown"}:
            score -= 8
            flags.append("unknown quote source")
        elif "delayed" in quote_quality or "free" in quote_quality:
            score -= 6
            flags.append("verify live quote")
    elif asset == "share":
        dollars = _float_value(row.get("suggested_dollars"), default=0.0)
        if dollars <= 0:
            score -= 30
            flags.append("no share size")
    elif asset == "futures":
        contracts = _float_value(row.get("suggested_contracts"), default=0.0)
        risk = _float_value(row.get("risk_dollars"), default=math.nan)
        reward = _float_value(row.get("reward_dollars"), default=math.nan)
        if contracts <= 0:
            score -= 35
            flags.append("no contract size")
        if math.isfinite(risk) and math.isfinite(reward) and risk > 0 and reward / risk < 1.5:
            score -= 12
            flags.append("weak reward/risk")
    elif asset == "value":
        if not str(row.get("value_bucket") or "").strip():
            score -= 10
            flags.append("missing value bucket")

    return _readiness(score, flags)


def _setup_gate(record: dict[str, Any]) -> dict[str, Any]:
    """Turn readiness/flags into one compact decision gate for the cockpit."""
    asset = str(record.get("asset") or "").strip().lower()
    readiness = str(record.get("readiness_label") or "").strip().lower()
    trade_status = str(record.get("trade_status") or "").strip().lower()
    freshness = str(record.get("snapshot_freshness") or "").strip().lower()
    flags = [
        str(flag).strip().lower() for flag in (record.get("risk_flags") or []) if str(flag).strip()
    ]
    blockers: list[str] = []
    checks: list[str] = []
    needs_quote = False

    if trade_status in {"skip", "blocked"}:
        blockers.append(f"trade status is {trade_status}")
    elif trade_status == "watch":
        checks.append("trade status is Watch")
    if readiness == "wait":
        blockers.append("readiness is wait")
    elif readiness == "review":
        checks.append("readiness requires review")
    elif readiness == "ready":
        checks.append("readiness is ready")
    if freshness == "stale":
        blockers.append("snapshot is stale")
    elif freshness == "aging":
        checks.append("snapshot is aging")

    severe_flag_terms = (
        "below 90 dte",
        "no contract size",
        "no share size",
        "very wide spread",
        "avoid swing fit",
        "status skip",
        "status blocked",
    )
    quote_flag_terms = (
        "verify live quote",
        "unknown quote source",
        "missing spread",
        "wide spread",
        "missing stop",
        "missing target",
        "aging snapshot",
    )
    for flag in flags:
        if any(term in flag for term in severe_flag_terms):
            blockers.append(flag)
        elif any(term in flag for term in quote_flag_terms):
            checks.append(flag)
            if asset == "option" and (
                "quote" in flag or "spread" in flag or "stop" in flag or "target" in flag
            ):
                needs_quote = True
        elif flag:
            checks.append(flag)

    if asset == "option":
        quote_quality = str(record.get("quality") or "").lower()
        if "free" in quote_quality or "delayed" in quote_quality or "cboe" in quote_quality:
            checks.append("verify live option quote before action")
            needs_quote = True

    if blockers:
        status = "avoid"
        label = "Avoid for now"
        next_step = "Skip this setup until the blocking issue clears."
        reasons = blockers[:4]
    elif needs_quote:
        status = "quote_check"
        label = "Needs live quote"
        next_step = "Refresh chain/quote and confirm spread before paper review."
        reasons = checks[:4] or ["live quote required before action"]
    elif checks and readiness != "ready":
        status = "review"
        label = "Review first"
        next_step = "Open research and clear the review items before acting."
        reasons = checks[:4]
    else:
        status = "ready"
        label = "Ready to research"
        next_step = "Open research; if thesis and live quote agree, consider paper tracking."
        reasons = checks[:4] or ["local readiness is clean"]

    return {
        "setup_gate_status": status,
        "setup_gate_label": label,
        "setup_gate_reasons": reasons,
        "setup_gate_next_step": next_step,
    }


def _setup_gate_priority(record: dict[str, Any]) -> tuple[int, float]:
    status = str(record.get("setup_gate_status") or "").strip().lower()
    priority = {
        "ready": 4,
        "quote_check": 3,
        "review": 2,
        "avoid": 0,
    }.get(status, 1)
    return priority, _float_value(record.get("score"), default=0.0)


def _planner_candidate(row: pd.Series, record: dict[str, Any], asset: str) -> dict[str, Any] | None:
    """Normalize one immutable idea for safe planner prefill without asset fallback."""
    if asset not in {"option", "share"}:
        return None
    symbol = str(record.get("ticker_or_symbol") or "").strip().upper()
    entry = _optional_float_value(record.get("entry_price"))
    stop = _optional_float_value(record.get("stop_price"))
    target = _optional_float_value(record.get("target_price"))
    blockers: list[str] = []
    if not symbol:
        blockers.append("missing symbol")
    if entry is None or entry <= 0:
        blockers.append("missing positive entry")
    if stop is None or stop <= 0:
        blockers.append("missing positive stop")
    if target is None or target <= 0:
        blockers.append("missing positive target")

    if asset == "option":
        max_units = _clean_value(record.get("suggested_contracts"))
    else:
        suggested_dollars = _optional_float_value(record.get("suggested_dollars"))
        max_units = (
            max(1, int(suggested_dollars // entry))
            if suggested_dollars is not None
            and suggested_dollars > 0
            and entry is not None
            and entry > 0
            else None
        )
    artifact_age = _optional_float_value(row.get("artifact_age_minutes"))
    if artifact_age is None:
        artifact_age = _optional_float_value(record.get("snapshot_age_min"))
    artifact_at = _clean_value(row.get("artifact_generated_at"))
    if artifact_at is None:
        artifact_at = _clean_value(row.get("generated_at"))
    if artifact_at is None:
        artifact_at = _clean_value(row.get("_source_mtime"))
    artifact_basis = _clean_value(row.get("artifact_time_basis"))
    if artifact_basis is None:
        artifact_basis = (
            "generated_at" if _clean_value(row.get("generated_at")) else "file_mtime_age"
        )
    candidate: dict[str, Any] = {
        "asset": asset,
        "symbol": symbol,
        "direction": "long",
        "entry_price": entry,
        "stop_price": stop,
        "target_price": target,
        "max_units": max_units,
        "identity_label": record.get("setup"),
        "source_file": record.get("source_file"),
        "source_generated_at": _clean_value(row.get("generated_at")),
        "source_artifact_at": artifact_at,
        "source_artifact_time_basis": artifact_basis,
        "source_artifact_age_minutes": artifact_age,
        "source_quote_at": _clean_value(row.get("source_quote_at")),
        "source_quote_time_basis": _clean_value(row.get("source_quote_time_basis")),
        "quote_quality": _clean_value(row.get("quote_quality")),
        "data_delay": _clean_value(row.get("data_delay")),
        "bid": _clean_value(row.get("bid")),
        "ask": _clean_value(row.get("ask")),
        "mid": _clean_value(row.get("mid")),
        "spread_pct": _clean_value(row.get("spread_pct")),
        "source_price_session": _clean_value(row.get("source_price_session")),
        "source_price_basis": _clean_value(row.get("source_price_basis")),
    }
    if asset == "option":
        side = str(row.get("side") or record.get("action") or "").strip().lower()
        strike = _optional_float_value(row.get("strike"))
        expiry = str(row.get("expiry") or record.get("expiry") or "").strip()
        underlying_type = str(row.get("underlying_type") or "").strip().lower()
        if side not in {"call", "put"}:
            blockers.append("missing call/put identity")
        if strike is None or strike <= 0:
            blockers.append("missing positive strike")
        if not expiry:
            blockers.append("missing expiry")
        if underlying_type != SWING_EXECUTION_OPTION_UNDERLYING_TYPE:
            blockers.append("missing explicit equity underlying type")
        candidate.update(
            {
                "option_type": side or None,
                "strike": strike,
                "expiry": expiry or None,
                "underlying_type": underlying_type or None,
                "contract_multiplier": 100,
                "contract": record.get("contract") or row.get("contract_query"),
            }
        )
    else:
        candidate.update(
            {
                "underlying_type": "equity",
                "contract_multiplier": 1,
            }
        )

    identity = {
        key: candidate.get(key)
        for key in (
            "asset",
            "symbol",
            "direction",
            "option_type",
            "strike",
            "expiry",
            "underlying_type",
            "contract_multiplier",
            "entry_price",
            "stop_price",
            "target_price",
            "max_units",
            "source_file",
            "source_generated_at",
            "source_artifact_at",
            "source_artifact_time_basis",
            # Age is deliberately excluded: the same immutable artifact must
            # keep the same identity while the wall clock advances.
            "source_quote_at",
            "source_price_session",
            "source_price_basis",
            "bid",
            "ask",
            "mid",
        )
    }
    fingerprint = hashlib.sha256(
        json.dumps(identity, sort_keys=True, separators=(",", ":"), default=str).encode("utf-8")
    ).hexdigest()[:24]
    candidate.update(
        {
            "candidate_fingerprint": fingerprint,
            "plan_ready": not blockers,
            "blockers": blockers,
        }
    )
    return candidate


def _best_setup_record(row: pd.Series, asset: str, source_file: str | None) -> dict[str, Any]:
    spec = OPPORTUNITY_SPECS[asset]
    symbol = _setup_symbol(row, asset, spec)
    score = _opportunity_score(row)
    row_source = str(row.get("_source_file") or source_file or "").strip() or None
    entry_price = _setup_entry_price(row, asset)
    stop_price = _clean_value(row.get("stop_price"))
    target_price = _clean_value(row.get("target_price"))
    if asset == "share":
        entry_number = _optional_float_value(entry_price)
        stop_fraction = _optional_float_value(row.get("stop_pct"))
        target_fraction = _optional_float_value(row.get("target_pct"))
        if entry_number is not None and entry_number > 0:
            if stop_price is None and stop_fraction is not None:
                normalized_stop = stop_fraction if stop_fraction < 0 else -stop_fraction
                stop_price = round(entry_number * (1.0 + normalized_stop), 4)
            if target_price is None and target_fraction is not None and target_fraction > 0:
                target_price = round(entry_number * (1.0 + target_fraction), 4)
    readiness_row = row.copy()
    readiness_row["stop_price"] = stop_price
    readiness_row["target_price"] = target_price
    readiness = _setup_readiness(readiness_row, asset)
    record = {
        "asset": asset,
        "ticker_or_symbol": symbol,
        "setup": _setup_label(row, asset, symbol),
        "action": _clean_value(
            row.get("side") or row.get("direction") or ("buy" if asset != "value" else "review")
        ),
        "score": round(score, 4),
        "confidence": _clean_value(row.get("confidence")),
        "trade_status": _clean_value(
            row.get("trade_status") or ("Trade" if bool(row.get("actionable")) else "Review")
        ),
        "entry_price": entry_price,
        "stop_price": stop_price,
        "target_price": target_price,
        "size": _setup_size(row, asset),
        "suggested_contracts": _clean_value(row.get("suggested_contracts")),
        "suggested_dollars": _clean_value(row.get("suggested_dollars")),
        "spread_pct": _clean_value(row.get("spread_pct")),
        "risk_dollars": _clean_value(row.get("risk_dollars")),
        "reward_dollars": _clean_value(row.get("reward_dollars")),
        "dte": _clean_value(row.get("dte")),
        "expiry": _clean_value(row.get("expiry")),
        "quality": _setup_quality(row, asset),
        "source_file": row_source,
        "snapshot_freshness": _clean_value(row.get("snapshot_freshness")),
        "snapshot_age_min": _clean_value(row.get("snapshot_age_min")),
        "reason_selected": _setup_reason(row, asset),
        "research_guard_status": _clean_value(row.get("research_guard_status")),
        "_sort_score": score,
    }
    for key in (
        "next_earnings_date",
        "earnings_date",
        "days_to_earnings",
        "earnings_score",
        "whisper_score",
        "whisper_gap_pct",
        "next_catalyst_date",
        "days_to_catalyst",
        "catalyst_type",
    ):
        if key in row:
            record[key] = _clean_value(row.get(key))
    if asset == "option":
        for key in (
            "contract",
            "swing_fit_score",
            "swing_fit_label",
            "swing_fit_reasons",
            "swing_fit_warnings",
            "breakeven_move_label",
            "liquidity_label",
        ):
            if key in row:
                record[key] = _clean_value(row.get(key))
    record.update(readiness)
    record.update(_setup_gate(record))
    candidate = _planner_candidate(row, record, asset)
    if candidate is not None:
        record["planner_candidate"] = candidate
    return record


DASHBOARD_HANDOFF_SCHEMA = "optedge_dashboard_handoff_v1"
DASHBOARD_SNAPSHOT_TAG_RE = re.compile(r"_(\d{8}_\d{6})\.[^.]+$")
DASHBOARD_HANDOFF_LANES = (
    ("option_call", "option", "Top calls", "top_options", "call"),
    ("option_put", "option", "Top puts", "top_options", "put"),
    ("share", "share", "Top shares", "top_shares", None),
    ("value", "value", "Top value", "top_value", None),
    ("futures", "futures", "Top futures", "top_futures", None),
)


def _dashboard_snapshot_tag(path: Path | None) -> str | None:
    if path is None:
        return None
    match = DASHBOARD_SNAPSHOT_TAG_RE.search(path.name)
    return match.group(1) if match else None


def _dashboard_snapshot_at(tag: str | None) -> str | None:
    if not tag:
        return None
    try:
        return datetime.strptime(tag, "%Y%m%d_%H%M%S").replace(tzinfo=UTC).isoformat()
    except ValueError:
        return None


def _dashboard_source_mode(path: Path | None) -> str:
    if path is None:
        return "missing"
    try:
        with path.open("r", encoding="utf-8", errors="replace") as handle:
            header = handle.read(32_768)
    except OSError:
        return "unreadable"
    return "demo_hybrid" if "DEMO/HYBRID MODE" in header else "live_or_provider"


def _handoff_option_key(record: dict[str, Any]) -> str:
    planner = record.get("planner_candidate")
    planner = planner if isinstance(planner, dict) else {}
    return _agentic_contract_key(
        {
            "symbol": planner.get("symbol") or record.get("ticker_or_symbol"),
            "option_side": planner.get("option_type") or record.get("action"),
            "strike": planner.get("strike"),
            "expiry": planner.get("expiry") or record.get("expiry"),
        }
    )


def _dashboard_handoff_lineage(
    data_dir: Path,
    option_records: list[dict[str, Any]],
) -> dict[str, Any]:
    queue = _read_json(data_dir / "robinhood_agentic_queue.json")
    cycle = _read_json(data_dir / "robinhood_agentic_cycle.json")
    queue = queue if isinstance(queue, dict) else {}
    cycle = cycle if isinstance(cycle, dict) else {}
    orders = queue.get("orders") if isinstance(queue.get("orders"), list) else []
    finalist = dict(orders[0]) if orders and isinstance(orders[0], dict) else {}
    finalist_key = _agentic_contract_key(finalist) if finalist else ""
    dashboard_by_key = {
        _handoff_option_key(record): record
        for record in option_records
        if _handoff_option_key(record).strip("|")
    }
    matched = dashboard_by_key.get(finalist_key)
    lane = None
    if finalist_key:
        for lane_name in ("manual_review_candidates", "review_only_entry_candidates"):
            rows = cycle.get(lane_name) if isinstance(cycle.get(lane_name), list) else []
            if any(
                isinstance(row, dict) and _agentic_contract_key(row) == finalist_key
                for row in rows
            ):
                lane = lane_name
                break
    queue_age = _iso_age_minutes(queue.get("generated_at"))
    queue_freshness = _agentic_freshness(queue_age)
    chain_source = str(finalist.get("chain_source") or "").strip().lower()
    origin = (
        "dashboard_top_options"
        if matched is not None
        else "swing_chain_enrichment"
        if finalist and chain_source
        else "unresolved"
        if finalist
        else "missing"
    )
    identity_label = None
    if finalist:
        side = _agentic_option_side(finalist.get("option_side") or finalist.get("side"))
        side_code = "C" if side == "call" else "P" if side == "put" else side.upper()
        identity_label = " ".join(
            str(value)
            for value in (
                finalist.get("symbol") or finalist.get("ticker_or_symbol"),
                finalist.get("expiry"),
                side_code,
                _agentic_strike_key(finalist.get("strike")),
            )
            if str(value or "").strip()
        )
    if not finalist:
        detail = "No 3m+ option finalist is bound to the latest local review queue."
    elif matched is not None:
        detail = "The Robinhood finalist is the same exact contract shown in the generated dashboard."
    else:
        detail = (
            "The Robinhood finalist came from the 3m+ chain-enrichment stage because the generated "
            "dashboard shortlist did not contain this exact swing contract."
        )
    return {
        "queue_generated_at": _clean_value(queue.get("generated_at")),
        "queue_age_minutes": round(queue_age, 1) if queue_age is not None else None,
        "queue_freshness": queue_freshness,
        "queue_candidate_count": len(orders),
        "cycle_lane": lane,
        "origin": origin,
        "matches_dashboard_contract": matched is not None,
        "dashboard_rank": matched.get("dashboard_rank") if matched else None,
        "dashboard_lane": matched.get("dashboard_lane") if matched else None,
        "identity_label": identity_label,
        "symbol": _clean_value(finalist.get("symbol") or finalist.get("ticker_or_symbol")),
        "option_side": _clean_value(finalist.get("option_side") or finalist.get("side")),
        "strike": _clean_value(finalist.get("strike")),
        "expiry": _clean_value(finalist.get("expiry")),
        "dte": _clean_value(finalist.get("dte")),
        "chain_source": _clean_value(finalist.get("chain_source")),
        "quote_quality": _clean_value(finalist.get("quote_quality")),
        "detail": detail,
        "read_check_available": bool(
            finalist and queue_freshness in {"fresh", "aging"} and lane is not None
        ),
        "does_not_place_orders": True,
    }


@_memoized_report
def build_dashboard_handoff(data_dir: Path = DATA_DIR) -> dict[str, Any]:
    """Bind the cockpit to the exact candidate files rendered by one dashboard scan."""
    data_dir = Path(data_dir)
    dashboard_path = _latest_file(data_dir, "dashboard_*.html")
    dashboard_meta = _file_meta(dashboard_path)
    snapshot_tag = _dashboard_snapshot_tag(dashboard_path)
    snapshot_at = _dashboard_snapshot_at(snapshot_tag)
    source_mode = _dashboard_source_mode(dashboard_path)
    if dashboard_path is None or snapshot_tag is None:
        return {
            "schema": DASHBOARD_HANDOFF_SCHEMA,
            "status": "missing",
            "tone": "bad",
            "label": "Dashboard snapshot missing",
            "snapshot_tag": snapshot_tag,
            "dashboard": dashboard_meta,
            "source_mode": source_mode,
            "count": 0,
            "by_asset": {},
            "lanes": [],
            "source_alignment": [],
            "option_lineage": _dashboard_handoff_lineage(data_dir, []),
            "blockers": ["No timestamped generated dashboard is available for cockpit handoff."],
            "warnings": [],
            "notes": ["No candidate is promoted when dashboard lineage cannot be proven."],
        }

    by_asset: dict[str, list[dict[str, Any]]] = {
        "option": [],
        "share": [],
        "value": [],
        "futures": [],
    }
    lanes: list[dict[str, Any]] = []
    source_alignment: list[dict[str, Any]] = []
    all_records: list[dict[str, Any]] = []
    duplicate_keys: set[str] = set()
    seen_keys: set[str] = set()
    missing_identity_count = 0

    for lane_key, asset, label, prefix, side in DASHBOARD_HANDOFF_LANES:
        exact_path = data_dir / f"{prefix}_{snapshot_tag}.parquet"
        latest_path = _latest_file(data_dir, f"{prefix}_*.parquet")
        frame = _read_parquet(exact_path if exact_path.exists() else None)
        if asset == "option" and side is not None and not frame.empty:
            side_values = frame.get("side", pd.Series("", index=frame.index)).astype(str).str.lower()
            frame = frame[side_values == side].copy()
        records: list[dict[str, Any]] = []
        for dashboard_rank, (_, row) in enumerate(frame.iterrows(), start=1):
            record = _best_setup_record(row, asset, exact_path.name)
            record.update(
                {
                    "dashboard_rank": dashboard_rank,
                    "dashboard_lane": lane_key,
                    "dashboard_lane_label": label,
                    "dashboard_snapshot_tag": snapshot_tag,
                    "dashboard_source_mode": source_mode,
                }
            )
            clean = {key: value for key, value in record.items() if not key.startswith("_")}
            if asset == "option":
                identity_key = _handoff_option_key(clean)
            else:
                identity_key = f"{asset}|{str(clean.get('ticker_or_symbol') or '').upper()}"
            if not identity_key.strip("|"):
                missing_identity_count += 1
            elif identity_key in seen_keys:
                duplicate_keys.add(identity_key)
            else:
                seen_keys.add(identity_key)
            clean["dashboard_identity_key"] = identity_key or None
            records.append(clean)
            by_asset[asset].append(clean)
            all_records.append(clean)
        ignored_mixed_snapshot = (
            latest_path.name
            if latest_path is not None
            and _dashboard_snapshot_tag(latest_path) != snapshot_tag
            and not exact_path.exists()
            else None
        )
        source_alignment.append(
            {
                "lane": lane_key,
                "asset": asset,
                "snapshot_tag": snapshot_tag,
                "source_file": exact_path.name if exact_path.exists() else None,
                "status": "exact" if exact_path.exists() else "empty_for_snapshot",
                "row_count": len(records),
                "ignored_mixed_snapshot_file": ignored_mixed_snapshot,
            }
        )
        display_records = [
            {
                key: record.get(key)
                for key in (
                    "asset",
                    "ticker_or_symbol",
                    "setup",
                    "dashboard_rank",
                    "dashboard_lane",
                    "dashboard_source_mode",
                    "reason_selected",
                    "trade_status",
                    "setup_gate_status",
                    "setup_gate_label",
                    "setup_gate_reasons",
                    "setup_gate_next_step",
                    "readiness_label",
                    "dte",
                    "spread_pct",
                    "quality",
                )
            }
            for record in records
        ]
        lanes.append(
            {
                "key": lane_key,
                "asset": asset,
                "label": label,
                "side": side,
                "source_file": exact_path.name if exact_path.exists() else None,
                "count": len(records),
                "rows": display_records,
            }
        )

    warnings: list[str] = []
    if source_mode == "demo_hybrid":
        warnings.append(
            "This dashboard is demo/hybrid; synthetic option or sentiment inputs remain visible but cannot authorize Robinhood review."
        )
    if duplicate_keys:
        warnings.append(f"{len(duplicate_keys)} duplicate dashboard candidate identity key(s) detected.")
    if missing_identity_count:
        warnings.append(f"{missing_identity_count} dashboard candidate row(s) lack a stable identity.")
    lineage = _dashboard_handoff_lineage(data_dir, by_asset["option"])
    snapshot_age = _iso_age_minutes(snapshot_at)
    stale = snapshot_age is None or snapshot_age > STALE_SNAPSHOT_MINUTES
    if stale:
        warnings.append("The generated dashboard snapshot is stale for a new trading decision.")
    status = "synchronized_demo" if source_mode == "demo_hybrid" else "synchronized"
    tone = "warn" if warnings else "good"
    label = "Exact scan linked"
    if source_mode == "demo_hybrid":
        label = "Demo scan linked; broker blocked"
    elif stale:
        label = "Exact scan linked; refresh required"
    return {
        "schema": DASHBOARD_HANDOFF_SCHEMA,
        "status": status,
        "tone": tone,
        "label": label,
        "generated_at": datetime.now(UTC).isoformat(),
        "snapshot_tag": snapshot_tag,
        "snapshot_at": snapshot_at,
        "snapshot_age_minutes": round(snapshot_age, 1) if snapshot_age is not None else None,
        "dashboard": {
            **(dashboard_meta or {}),
            "url": "/artifact/latest-dashboard",
        },
        "source_mode": source_mode,
        "count": len(all_records),
        "option_count": len(by_asset["option"]),
        "by_asset": by_asset,
        "lanes": lanes,
        "source_alignment": source_alignment,
        "option_lineage": lineage,
        "quality": {
            "candidate_count": len(all_records),
            "stable_identity_count": len(seen_keys),
            "duplicate_identity_count": len(duplicate_keys),
            "missing_identity_count": missing_identity_count,
            "mixed_snapshot_rows_used": 0,
        },
        "blockers": [],
        "warnings": warnings,
        "notes": [
            "Every row is loaded from the exact top_* timestamp rendered by the latest generated dashboard.",
            "Older per-asset files are ignored when the current dashboard has no candidates in that lane.",
            "The Robinhood finalist is a separate 3m+ exact-contract stage and is never substituted silently.",
        ],
    }


@_memoized_report
def build_best_setups(
    data_dir: Path = DATA_DIR,
    per_asset: int = 3,
    limit: int = 12,
) -> dict[str, Any]:
    """Build a compact decision surface from the latest local opportunity snapshots."""
    per_asset = max(1, min(int(per_asset or 3), 10))
    limit = max(1, min(int(limit or 12), 40))
    rows: list[dict[str, Any]] = []
    by_asset: dict[str, list[dict[str, Any]]] = {}
    summaries: list[dict[str, Any]] = []
    sources: dict[str, str | None] = {}

    for asset_name, spec in OPPORTUNITY_SPECS.items():
        path = _latest_file(data_dir, spec["pattern"])
        source_file = path.name if path else None
        sources[asset_name] = source_file
        df = _read_parquet(path)
        chain_shortlist_rows = 0
        if asset_name == "option":
            chain_df = _load_option_chain_shortlist(data_dir)
            if not chain_df.empty:
                if "artifact_age_minutes" in chain_df.columns:
                    chain_age = pd.to_numeric(chain_df["artifact_age_minutes"], errors="coerce")
                    chain_df["snapshot_age_min"] = chain_age
                    chain_df["snapshot_freshness"] = chain_age.map(
                        lambda value: _snapshot_freshness(None if pd.isna(value) else float(value))
                    )
                chain_shortlist_rows = int(len(chain_df))
                sources["option_chain_shortlist"] = (
                    str(chain_df["_source_file"].iloc[0])
                    if "_source_file" in chain_df.columns
                    else "option_chain_shortlist"
                )
                df = (
                    pd.concat([df, chain_df], ignore_index=True, sort=False)
                    if not df.empty
                    else chain_df
                )
        if df.empty:
            by_asset[asset_name] = []
            summaries.append(
                {
                    "asset": asset_name,
                    "source_file": source_file,
                    "rows": 0,
                    "actionable_rows": 0,
                    "selected": 0,
                    "chain_shortlist_rows": chain_shortlist_rows,
                    "status": "missing",
                }
            )
            continue

        out = df.copy()
        out["asset"] = asset_name
        out["actionable"] = out.apply(_is_actionable, axis=1)
        out["_opportunity_score"] = out.apply(_opportunity_score, axis=1)
        actionable = out[out["actionable"]].copy()
        if asset_name == "option" and "dte" in actionable.columns:
            actionable = actionable[
                pd.to_numeric(actionable["dte"], errors="coerce").fillna(MIN_SWING_OPTION_DTE)
                >= MIN_SWING_OPTION_DTE
            ]
        candidates = actionable if not actionable.empty else out.copy()
        candidates = candidates.sort_values("_opportunity_score", ascending=False, kind="mergesort")

        asset_records = [
            _best_setup_record(row, asset_name, source_file)
            for _, row in candidates.head(per_asset).iterrows()
        ]
        by_asset[asset_name] = [
            {k: v for k, v in record.items() if not k.startswith("_")} for record in asset_records
        ]
        rows.extend(asset_records)
        summaries.append(
            {
                "asset": asset_name,
                "source_file": source_file,
                "rows": int(len(out)),
                "actionable_rows": int(len(actionable)),
                "selected": int(len(asset_records)),
                "chain_shortlist_rows": chain_shortlist_rows,
                "status": "actionable" if len(actionable) else "review_only",
                "snapshot_freshness": _clean_value(out["snapshot_freshness"].iloc[0])
                if "snapshot_freshness" in out.columns
                else None,
                "snapshot_age_min": _clean_value(out["snapshot_age_min"].iloc[0])
                if "snapshot_age_min" in out.columns
                else None,
            }
        )

    rows = sorted(rows, key=lambda row: _float_value(row.get("_sort_score")), reverse=True)[:limit]
    clean_rows = [{k: v for k, v in row.items() if not k.startswith("_")} for row in rows]
    decision_row = None
    if clean_rows:
        decision_row = sorted(clean_rows, key=_setup_gate_priority, reverse=True)[0]
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "count": len(clean_rows),
        "rows": clean_rows,
        "decision_row": decision_row,
        "by_asset": by_asset,
        "asset_summaries": summaries,
        "sources": sources,
        "notes": [
            "Best setups read the latest local top_* snapshots and apply Optedge sizing/status filters.",
            "Options include chain-source and spread quality when available.",
            "Saved 3m+ chain shortlist rows are included as option review candidates when present.",
            "This is a research shortlist only; no orders are placed.",
        ],
    }


COMPARISON_BOARD_LIMIT = 3


def _comparison_value(*values: Any) -> Any:
    """Return the first nonblank scalar without treating NaN as provenance."""
    for value in values:
        clean = _clean_value(value)
        if clean is None:
            continue
        if isinstance(clean, str) and not clean.strip():
            continue
        return clean
    return None


def _comparison_exact_identity(record: dict[str, Any]) -> dict[str, Any]:
    planner = record.get("planner_candidate")
    planner = planner if isinstance(planner, dict) else {}
    asset = str(record.get("asset") or planner.get("asset") or "").strip().lower()
    symbol = str(planner.get("symbol") or record.get("ticker_or_symbol") or "").strip().upper()
    direction = str(planner.get("direction") or record.get("action") or "long").strip().lower()
    if direction in {"buy", "bull", "bullish"}:
        direction = "long"
    elif direction in {"sell", "bear", "bearish"}:
        direction = "short"
    identity: dict[str, Any] = {
        "asset": asset,
        "symbol": symbol,
        "direction": direction,
        "label": _comparison_value(planner.get("identity_label"), record.get("setup"), symbol),
    }
    if asset == "option":
        identity.update(
            {
                "option_type": _agentic_option_side(
                    planner.get("option_type") or record.get("action")
                ),
                "strike": _optional_float_value(planner.get("strike")),
                "expiry": _agentic_expiry_key(planner.get("expiry") or record.get("expiry")),
                "underlying_type": str(planner.get("underlying_type") or "").strip().lower()
                or None,
                "contract": _comparison_value(
                    planner.get("contract"), record.get("contract"), record.get("setup")
                ),
            }
        )
    elif asset == "futures":
        identity["contract"] = _comparison_value(
            record.get("setup"), record.get("ticker_or_symbol")
        )
    return identity


def _comparison_manual_match(
    identity: dict[str, Any],
    broker: dict[str, Any],
) -> dict[str, Any]:
    rows = broker.get("manual_review_candidates")
    rows = rows if isinstance(rows, list) else []
    if identity.get("asset") != "option":
        return {}
    wanted = _agentic_contract_key(identity)
    for raw in rows:
        if isinstance(raw, dict) and _agentic_contract_key(raw) == wanted:
            return raw
    return {}


def _comparison_source_state(
    record: dict[str, Any],
    broker_match: dict[str, Any],
) -> dict[str, Any]:
    planner = record.get("planner_candidate")
    planner = planner if isinstance(planner, dict) else {}
    asset = str(record.get("asset") or planner.get("asset") or "").strip().lower()
    artifact_at = _comparison_value(
        planner.get("source_artifact_at"),
        planner.get("source_generated_at"),
    )
    artifact_age = _optional_float_value(
        _comparison_value(
            planner.get("source_artifact_age_minutes"),
            record.get("snapshot_age_min"),
        )
    )
    if artifact_age is None and artifact_at is not None:
        artifact_age = _iso_age_minutes(artifact_at)
    artifact_basis = _comparison_value(
        planner.get("source_artifact_time_basis"),
        "generated_at" if artifact_at else "file_mtime_age" if artifact_age is not None else None,
    )
    source_file = _comparison_value(planner.get("source_file"), record.get("source_file"))

    quote_at = _comparison_value(
        broker_match.get("source_quote_at"),
        broker_match.get("quote_updated_at"),
        planner.get("source_quote_at"),
    )
    quote_basis = _comparison_value(
        broker_match.get("source_quote_time_basis"),
        planner.get("source_quote_time_basis"),
    )
    quote_quality = _comparison_value(
        broker_match.get("quote_quality"),
        planner.get("quote_quality"),
    )
    data_delay = _comparison_value(
        broker_match.get("data_delay"),
        planner.get("data_delay"),
    )
    quote_age = _iso_age_minutes(quote_at)
    provenance_row = {
        "source_quote_at": quote_at,
        "source_quote_time_basis": quote_basis,
        "quote_quality": quote_quality,
        "data_delay": data_delay,
    }
    source_blockers: list[str] = []
    artifact_present = bool(source_file and artifact_age is not None)
    artifact_fresh = bool(
        artifact_present and artifact_age is not None and artifact_age <= STALE_SNAPSHOT_MINUTES
    )
    if not artifact_present:
        source_blockers.append("artifact provenance or age is missing")
    elif not artifact_fresh:
        source_blockers.append(f"source artifact is stale ({_short_age_label(artifact_age)} old)")

    quote_reasons = manual_review_quote_provenance_reasons(provenance_row)
    if quote_at is None or quote_age is None:
        quote_reasons.append("source quote timestamp is missing or invalid")
    elif quote_age > AGENTIC_FRESH_MINUTES:
        quote_reasons.append(
            f"source quote is stale for planning ({_short_age_label(quote_age)} old)"
        )
    source_quote_required = asset == "option"
    if source_quote_required:
        for reason in quote_reasons:
            if reason not in source_blockers:
                source_blockers.append(reason)
    # A share shortlist is a bar-data research artifact, not an execution quote.
    # Its exact artifact can enter local sizing while the mandatory connected
    # Robinhood equity quote remains the only execution quote. Options still
    # require contract-level source quote provenance before planner loading.
    source_gate_pass = artifact_fresh and (not source_quote_required or not quote_reasons)
    if source_gate_pass and artifact_age is not None and artifact_age <= FRESH_SNAPSHOT_MINUTES:
        source_score = 4
        source_status = "fresh"
    elif source_gate_pass:
        source_score = 3
        source_status = "aging"
    elif (
        artifact_fresh
        and quote_at is not None
        and quote_age is not None
        and quote_age <= STALE_SNAPSHOT_MINUTES
    ):
        source_score = 2
        source_status = "quote_stale"
    elif artifact_fresh:
        source_score = 1
        source_status = "quote_unproven"
    else:
        source_score = 0
        source_status = "artifact_stale_or_missing"
    return {
        "source_file": source_file,
        "artifact_at": artifact_at,
        "artifact_time_basis": artifact_basis,
        "artifact_age_minutes": round(artifact_age, 1) if artifact_age is not None else None,
        "artifact_freshness": _snapshot_freshness(artifact_age),
        "quote_at": quote_at,
        "quote_time_basis": quote_basis,
        "quote_age_minutes": round(quote_age, 1) if quote_age is not None else None,
        "quote_quality": quote_quality,
        "data_delay": data_delay,
        "source_status": source_status,
        "source_score": source_score,
        "source_gate_pass": source_gate_pass,
        "blockers": source_blockers,
        "warnings": list(
            dict.fromkeys(
                [
                    *research_quote_provenance_warnings(provenance_row),
                    *(
                        [
                            "share execution bid/ask will be validated from Robinhood during manual review"
                        ]
                        if asset == "share" and quote_reasons
                        else []
                    ),
                ]
            )
        ),
    }


def _comparison_edge_state(asset: str, edge: dict[str, Any]) -> dict[str, Any]:
    rows = edge.get("asset_rows")
    rows = rows if isinstance(rows, list) else []
    lane = next(
        (
            row
            for row in rows
            if isinstance(row, dict) and str(row.get("asset") or "").strip().lower() == asset
        ),
        {},
    )
    attestation = edge.get("source_attestation")
    attestation = attestation if isinstance(attestation, dict) else {}
    attestation_ok = attestation.get("met") is not False
    eligible = bool(lane.get("live_capital_eligible") is True and attestation_ok)
    blocker = (
        None
        if eligible
        else _comparison_value(
            lane.get("primary_blocker"),
            edge.get("primary_blocker"),
            f"{asset.title()} Edge Lab lane is unavailable",
        )
    )
    return {
        "eligible": eligible,
        "score": 1 if eligible else 0,
        "lane": _comparison_value(lane.get("evidence_lane"), "missing"),
        "status": _comparison_value(lane.get("status"), edge.get("status"), "unavailable"),
        "primary_blocker": blocker,
    }


def _comparison_overlap_state(
    identity: dict[str, Any],
    broker: dict[str, Any],
) -> dict[str, Any]:
    rows: list[dict[str, Any]] = []
    for key in ("broker_reconciliation_rows", "paper_positions"):
        values = broker.get(key)
        if isinstance(values, list):
            rows.extend(row for row in values if isinstance(row, dict))
    symbol = str(identity.get("symbol") or "").strip().upper()
    exact_contract = False
    same_direction = False
    underlying_count = 0
    wanted_contract = _agentic_contract_key(identity) if identity.get("asset") == "option" else ""
    wanted_direction = _agentic_direction_key(identity)
    for row in rows:
        row_status = str(row.get("status") or row.get("trade_status") or "").strip().lower()
        if any(token in row_status for token in ("expired", "closed", "cancelled", "canceled")):
            continue
        row_symbol = (
            str(row.get("symbol") or row.get("ticker") or row.get("ticker_or_symbol") or "")
            .strip()
            .upper()
        )
        if not symbol or row_symbol != symbol:
            continue
        underlying_count += 1
        if identity.get("asset") == "option" and _agentic_contract_key(row) == wanted_contract:
            exact_contract = True
        if _agentic_direction_key(row) == wanted_direction:
            same_direction = True
    blockers: list[str] = []
    if exact_contract:
        blockers.append("exact contract already exists in broker/local paper exposure")
    elif same_direction:
        blockers.append("same-underlying directional exposure already exists")
    return {
        "label": (
            "exact contract overlap"
            if exact_contract
            else "directional overlap"
            if same_direction
            else f"{underlying_count} same-underlying position(s)"
            if underlying_count
            else "none"
        ),
        "underlying_count": underlying_count,
        "exact_contract": exact_contract,
        "same_direction": same_direction,
        "blockers": blockers,
    }


def _comparison_economics(
    record: dict[str, Any],
    broker_match: dict[str, Any],
) -> dict[str, Any]:
    planner = record.get("planner_candidate")
    planner = planner if isinstance(planner, dict) else {}
    asset = str(record.get("asset") or planner.get("asset") or "").strip().lower()
    entry = _optional_float_value(
        _comparison_value(
            planner.get("entry_price"),
            record.get("entry_price"),
            broker_match.get("reference_entry_price"),
            broker_match.get("source_ask"),
            broker_match.get("max_limit_price"),
        )
    )
    stop = _optional_float_value(
        _comparison_value(
            planner.get("stop_price"),
            record.get("stop_price"),
            broker_match.get("stop_price_reference"),
        )
    )
    target = _optional_float_value(
        _comparison_value(
            planner.get("target_price"),
            record.get("target_price"),
            broker_match.get("target_price_reference"),
        )
    )
    spread = _optional_float_value(
        _comparison_value(
            broker_match.get("source_spread_pct"),
            broker_match.get("spread_pct"),
            planner.get("spread_pct"),
            record.get("spread_pct"),
        )
    )
    bid = _optional_float_value(
        _comparison_value(
            broker_match.get("source_bid"), broker_match.get("bid"), planner.get("bid")
        )
    )
    ask = _optional_float_value(
        _comparison_value(
            broker_match.get("source_ask"), broker_match.get("ask"), planner.get("ask")
        )
    )
    valid_bid_ask = bool(bid is not None and bid > 0 and ask is not None and ask >= bid)
    if valid_bid_ask and bid is not None and ask is not None:
        quote_mid = (ask + bid) / 2.0
        spread = max(0.0, ask - bid) / quote_mid if quote_mid > 0 else None
    multiplier = _optional_float_value(planner.get("contract_multiplier")) or (
        100.0 if asset == "option" else 1.0
    )
    units = (
        _optional_float_value(planner.get("max_units"))
        or _optional_float_value(record.get("suggested_contracts"))
        or 1.0
    )
    units = max(1.0, float(units))
    slippage_fraction = max(0.005, (spread or 0.0) / 2.0)
    adjusted_entry = entry * (1.0 + slippage_fraction) if entry is not None else None
    stop_risk = None
    reward = None
    adjusted_rr = None
    if adjusted_entry is not None and stop is not None and target is not None:
        risk_per_unit = adjusted_entry - stop
        reward_per_unit = target - adjusted_entry
        if risk_per_unit > 0 and reward_per_unit > 0:
            stop_risk = risk_per_unit * multiplier * units
            reward = reward_per_unit * multiplier * units
            adjusted_rr = reward / stop_risk
    if asset == "option" and adjusted_entry is not None:
        max_loss = adjusted_entry * multiplier * units
    elif asset == "share" and adjusted_entry is not None:
        max_loss = adjusted_entry * units
    else:
        max_loss = _optional_float_value(record.get("risk_dollars")) or stop_risk

    execution_blockers: list[str] = []
    max_spread = (
        SWING_EXECUTION_PROFILE.max_option_spread_pct
        if asset == "option"
        else EQUITY_REVIEW_MAX_SPREAD_PCT
        if asset == "share"
        else None
    )
    if asset == "option" and not valid_bid_ask:
        execution_blockers.append("source bid/ask is missing or invalid")
        execution_score = 0
    elif spread is not None and spread < 0:
        execution_blockers.append("bid/ask spread is invalid")
        execution_score = 0
    elif asset == "option" and spread is None:
        execution_blockers.append("bid/ask spread is missing")
        execution_score = 0
    elif max_spread is not None and spread is not None and spread > max_spread:
        execution_blockers.append(f"spread {spread:.1%} exceeds the {max_spread:.1%} review limit")
        execution_score = 0
    elif spread is None:
        execution_score = 1
    elif max_spread is None or spread <= max_spread * 0.50:
        execution_score = 3
    else:
        execution_score = 2

    economics_blockers: list[str] = []
    if adjusted_rr is None:
        economics_blockers.append("stop/target geometry does not produce positive reward-to-risk")
        rr_score = 0
    elif adjusted_rr >= 2.0:
        rr_score = 3
    elif adjusted_rr >= 1.5:
        rr_score = 2
    elif adjusted_rr >= 1.0:
        rr_score = 1
    else:
        rr_score = 0
        economics_blockers.append(f"slippage-adjusted reward/risk is only {adjusted_rr:.2f}x")
    return {
        "entry_price": round(entry, 4) if entry is not None else None,
        "stop_price": round(stop, 4) if stop is not None else None,
        "target_price": round(target, 4) if target is not None else None,
        "bid": round(bid, 4) if bid is not None else None,
        "ask": round(ask, 4) if ask is not None else None,
        "spread_pct": round(spread, 6) if spread is not None else None,
        "slippage_fraction": round(slippage_fraction, 6),
        "slippage_adjusted_entry": round(adjusted_entry, 4) if adjusted_entry is not None else None,
        "stop_risk_dollars": round(stop_risk, 2) if stop_risk is not None else None,
        "reward_dollars": round(reward, 2) if reward is not None else None,
        "max_loss_dollars": round(max_loss, 2) if max_loss is not None else None,
        "slippage_adjusted_rr": round(adjusted_rr, 3) if adjusted_rr is not None else None,
        "execution_score": execution_score,
        "rr_score": rr_score,
        "execution_blockers": execution_blockers,
        "economics_blockers": economics_blockers,
    }


def _comparison_catalyst_regime(
    record: dict[str, Any],
    command: dict[str, Any],
) -> dict[str, Any]:
    earnings_days = _days_until_date(
        record.get("next_earnings_date") or record.get("earnings_date"),
        record.get("days_to_earnings"),
    )
    catalyst_days = _days_until_date(
        record.get("next_catalyst_date"), record.get("days_to_catalyst")
    )
    whisper_gap = _float_value(record.get("whisper_gap_pct"), default=math.nan)
    event_risk, event_action = _event_risk_level(earnings_days, catalyst_days, whisper_gap)
    climate_score = _float_value(command.get("climate_score"), default=math.nan)
    if not math.isfinite(climate_score):
        regime_status, regime_score = "unknown", 0
    elif climate_score >= 60:
        regime_status, regime_score = "supportive", 2
    elif climate_score >= 45:
        regime_status, regime_score = "mixed", 1
    else:
        regime_status, regime_score = "defensive", 0
    event_score = {"clear": 2, "watch": 1, "medium": 0, "high": -1}.get(event_risk, 0)
    blockers = []
    if event_risk == "high":
        blockers.append(f"near-term catalyst gate: {event_action.replace('_', ' ')}")
    return {
        "event_risk": event_risk,
        "event_action": event_action,
        "next_earnings_date": _clean_value(
            record.get("next_earnings_date") or record.get("earnings_date")
        ),
        "next_catalyst_date": _clean_value(record.get("next_catalyst_date")),
        "regime_status": regime_status,
        "regime_label": _comparison_value(command.get("climate_label"), "unknown"),
        "regime_score": regime_score,
        "score": max(0, event_score + regime_score),
        "blockers": blockers,
    }


def _candidate_comparison_row(
    record: dict[str, Any],
    *,
    command: dict[str, Any],
    edge: dict[str, Any],
    broker: dict[str, Any],
) -> dict[str, Any]:
    identity = _comparison_exact_identity(record)
    asset = str(identity.get("asset") or "")
    planner = record.get("planner_candidate")
    planner = planner if isinstance(planner, dict) else None
    broker_match = _comparison_manual_match(identity, broker)
    source = _comparison_source_state(record, broker_match)
    edge_state = _comparison_edge_state(asset, edge)
    overlap = _comparison_overlap_state(identity, broker)
    economics = _comparison_economics(record, broker_match)
    catalyst = _comparison_catalyst_regime(record, command)
    guard = command.get("validation_guardrail")
    guard = guard if isinstance(guard, dict) else {}
    validation_level = str(guard.get("level") or "missing").strip().lower()
    validation_clear = validation_level == "ok"
    validation_blockers: list[str] = []
    source_mode = str(record.get("dashboard_source_mode") or "").strip().lower()
    if source_mode == "demo_hybrid":
        validation_blockers.append(
            "dashboard row uses demo/hybrid inputs and cannot authorize Robinhood review"
        )
    if not validation_clear:
        validation_blockers.append(
            str(guard.get("detail") or "validation guardrail is not cleared")
        )
    setup_status = str(record.get("setup_gate_status") or "review").strip().lower()
    if setup_status == "avoid":
        validation_blockers.append(
            str((record.get("setup_gate_reasons") or ["setup gate says avoid"])[0])
        )
    validation_blockers.extend(overlap["blockers"])
    candidate_blockers = (
        [str(value) for value in (planner.get("blockers") or []) if str(value).strip()]
        if planner is not None
        else [f"{asset or 'unknown'} candidate is not supported by the planner"]
    )
    blockers = (
        source["blockers"]
        + ([] if edge_state["eligible"] else [str(edge_state["primary_blocker"])])
        + validation_blockers
        + candidate_blockers
        + economics["execution_blockers"]
        + economics["economics_blockers"]
        + catalyst["blockers"]
    )
    blockers = list(dict.fromkeys(value for value in blockers if value))
    planner_load_allowed = bool(
        planner is not None
        and planner.get("plan_ready") is True
        and asset in {"option", "share"}
        and source["source_gate_pass"]
        and edge_state["eligible"]
        and validation_clear
        and source_mode != "demo_hybrid"
        and setup_status != "avoid"
        and not overlap["blockers"]
        and not economics["execution_blockers"]
        and not economics["economics_blockers"]
        and not catalyst["blockers"]
    )
    validation_score = (
        2 if validation_clear and not overlap["blockers"] else 1 if validation_clear else 0
    )
    ranking_vector = [
        int(source["source_score"]),
        int(edge_state["score"]),
        int(validation_score),
        int(economics["execution_score"]),
        int(economics["rr_score"]),
        int(catalyst["score"]),
    ]
    identity_text = (
        f"{identity.get('symbol')} {identity.get('expiry')} "
        f"{identity.get('option_type')} {identity.get('strike'):g}"
        if asset == "option" and identity.get("strike") is not None
        else str(identity.get("label") or identity.get("symbol") or "Unknown candidate")
    )
    candidate_id = hashlib.sha256(
        json.dumps(identity, sort_keys=True, separators=(",", ":"), default=str).encode("utf-8")
    ).hexdigest()[:18]
    why = (
        f"Source {source['source_status']}; Edge {edge_state['status']} in "
        f"{edge_state['lane']}; validation {validation_level}; overlap {overlap['label']}; "
        f"execution {'clear' if not economics['execution_blockers'] else 'blocked'}; "
        f"slippage-adjusted R/R "
        f"{economics['slippage_adjusted_rr'] if economics['slippage_adjusted_rr'] is not None else 'missing'}x; "
        f"catalyst {catalyst['event_risk']} / regime {catalyst['regime_status']}."
    )
    return {
        "candidate_id": candidate_id,
        "kind": "candidate",
        "asset": asset,
        "symbol": identity.get("symbol"),
        "identity": identity,
        "identity_label": identity_text,
        "ranking_vector": ranking_vector,
        "ranking_dimensions": {
            "source_quote": ranking_vector[0],
            "edge": ranking_vector[1],
            "validation_portfolio": ranking_vector[2],
            "execution": ranking_vector[3],
            "slippage_rr": ranking_vector[4],
            "catalyst_regime": ranking_vector[5],
        },
        "artifact_at": source["artifact_at"],
        "artifact_time_basis": source["artifact_time_basis"],
        "artifact_age_minutes": source["artifact_age_minutes"],
        "artifact_freshness": source["artifact_freshness"],
        "source_file": source["source_file"],
        "dashboard_rank": _clean_value(record.get("dashboard_rank")),
        "dashboard_lane": _clean_value(record.get("dashboard_lane")),
        "dashboard_source_mode": _clean_value(record.get("dashboard_source_mode")),
        "quote_at": source["quote_at"],
        "quote_time_basis": source["quote_time_basis"],
        "quote_age_minutes": source["quote_age_minutes"],
        "quote_quality": source["quote_quality"],
        "source_status": source["source_status"],
        "spread_pct": economics["spread_pct"],
        "bid": economics["bid"],
        "ask": economics["ask"],
        "entry_price": economics["entry_price"],
        "stop_price": economics["stop_price"],
        "target_price": economics["target_price"],
        "max_loss_dollars": economics["max_loss_dollars"],
        "slippage_fraction": economics["slippage_fraction"],
        "slippage_adjusted_rr": economics["slippage_adjusted_rr"],
        "edge_eligible": edge_state["eligible"],
        "edge_lane": edge_state["lane"],
        "edge_status": edge_state["status"],
        "validation_level": validation_level,
        "overlap": overlap["label"],
        "overlap_count": overlap["underlying_count"],
        "event_risk": catalyst["event_risk"],
        "regime_support": catalyst["regime_status"],
        "primary_blocker": blockers[0] if blockers else None,
        "blockers": blockers,
        "warnings": list(dict.fromkeys(source["warnings"])),
        "why": why,
        "planner_load_allowed": planner_load_allowed,
        "planner_candidate": planner if planner_load_allowed else None,
        "raw_cross_asset_score_used": False,
        "recommended": False,
    }


def build_candidate_comparison(
    best_setups: dict[str, Any],
    *,
    command: dict[str, Any],
    edge: dict[str, Any],
    broker: dict[str, Any],
    limit: int = COMPARISON_BOARD_LIMIT,
) -> dict[str, Any]:
    """Compare asset lanes with shared gates instead of incomparable raw scores."""
    by_asset = best_setups.get("by_asset")
    by_asset = by_asset if isinstance(by_asset, dict) else {}
    candidates: list[dict[str, Any]] = []
    for asset in ("option", "share", "futures"):
        rows = by_asset.get(asset)
        if not isinstance(rows, list):
            continue
        for record in rows:
            if isinstance(record, dict):
                candidates.append(
                    _candidate_comparison_row(
                        record,
                        command=command,
                        edge=edge,
                        broker=broker,
                    )
                )
    candidates.sort(
        key=lambda row: (
            tuple(row.get("ranking_vector") or []),
            str(row.get("candidate_id") or ""),
        ),
        reverse=True,
    )
    top = candidates[: max(1, min(int(limit or COMPARISON_BOARD_LIMIT), COMPARISON_BOARD_LIMIT))]
    winner = next((row for row in top if row.get("planner_load_allowed") is True), None)
    if winner is not None:
        winner["recommended"] = True
        baseline_reason = "An exact candidate clears the comparison gates; no trade remains the risk-free baseline."
        winner_id = winner["candidate_id"]
    else:
        baseline_reason = (
            f"No candidate clears every planner gate. First blocker: {top[0].get('primary_blocker')}"
            if top
            else "No exact swing candidate is available in the current snapshot."
        )
        winner_id = "no_trade"
    baseline = {
        "candidate_id": "no_trade",
        "kind": "baseline",
        "asset": "cash",
        "symbol": None,
        "identity": {"asset": "cash", "label": "No trade / hold cash"},
        "identity_label": "No trade / hold cash",
        "ranking_vector": None,
        "artifact_age_minutes": 0,
        "quote_age_minutes": 0,
        "spread_pct": 0,
        "entry_price": None,
        "stop_price": None,
        "target_price": None,
        "max_loss_dollars": 0,
        "slippage_adjusted_rr": None,
        "edge_eligible": True,
        "edge_lane": "not_applicable",
        "overlap": "none",
        "primary_blocker": None if winner is None else baseline_reason,
        "blockers": [],
        "why": baseline_reason,
        "planner_load_allowed": False,
        "planner_candidate": None,
        "raw_cross_asset_score_used": False,
        "recommended": winner is None,
    }
    return {
        "schema": "optedge_candidate_comparison_v1",
        "generated_at": datetime.now(UTC).isoformat(),
        "winner_id": winner_id,
        "candidate_count": len(candidates),
        "displayed_candidate_count": len(top),
        "rows": top + [baseline],
        "ranking_order": [
            "source_quote_freshness_and_provenance",
            "edge_eligibility",
            "validation_and_portfolio_blockers",
            "execution_quality",
            "slippage_adjusted_reward_risk",
            "catalyst_and_regime_support",
        ],
        "raw_cross_asset_scores_used": False,
        "automation_enabled": False,
        "broker_action_enabled": False,
        "notes": [
            "Each asset is shortlisted inside its own lane; raw asset scores are never compared across assets.",
            "Stale or unproven source/quote provenance remains visible but cannot load the planner.",
            "No trade is always shown as the zero-new-risk baseline.",
        ],
    }


def _market_cap_profile(row: pd.Series) -> dict[str, Any]:
    cap = _float_value(row.get("market_cap") or row.get("market_cap_f"), default=math.nan)
    if not math.isfinite(cap) or cap <= 0:
        return {
            "market_cap": None,
            "bucket": "unknown",
            "bonus": 0.0,
            "warning": "missing market cap",
        }
    if cap < 300_000_000:
        return {
            "market_cap": cap,
            "bucket": "micro",
            "bonus": 14.0,
            "warning": "micro-cap execution risk",
        }
    if cap < 2_000_000_000:
        return {"market_cap": cap, "bucket": "small", "bonus": 18.0, "warning": None}
    if cap < 10_000_000_000:
        return {"market_cap": cap, "bucket": "small-mid", "bonus": 14.0, "warning": None}
    if cap < 25_000_000_000:
        return {"market_cap": cap, "bucket": "mid", "bonus": 7.0, "warning": None}
    return {
        "market_cap": cap,
        "bucket": "large",
        "bonus": -10.0,
        "warning": "large-cap; less small-cap asymmetry",
    }


def _positive_component(value: Any, scale: float, cap: float) -> float:
    val = _float_value(value, default=0.0)
    return _clamp(val * scale, 0.0, cap)


def _swing_scout_components(row: pd.Series, asset: str) -> dict[str, Any]:
    cap_profile = _market_cap_profile(row)
    confidence = _float_value(row.get("confidence"), default=math.nan)
    readiness = _setup_readiness(row, asset)
    readiness_score = _float_value(readiness.get("readiness_score"), default=0.0)
    squeeze = (
        _positive_component(row.get("short_int_score"), 6.0, 12.0)
        + _positive_component(row.get("short_pct_of_float"), 55.0, 12.0)
        + _positive_component(
            _float_value(row.get("short_vol_ratio"), default=0.0) - 0.45, 18.0, 7.0
        )
        + _positive_component(row.get("dark_pool_score"), 5.0, 7.0)
        + _positive_component(row.get("uoa_score"), 5.0, 8.0)
    )
    attention = (
        _positive_component(row.get("social_score"), 8.0, 8.0)
        + _positive_component(row.get("gtrends_score"), 7.0, 8.0)
        + _positive_component(row.get("twitter_score"), 7.0, 8.0)
        + _positive_component(row.get("r_options_score"), 8.0, 8.0)
        + _positive_component(row.get("sentiment_delta"), 8.0, 6.0)
        + _positive_component(row.get("mentions"), 0.08, 5.0)
    )
    momentum = (
        _positive_component(row.get("tech_score"), 8.0, 8.0)
        + _positive_component(row.get("sector_rs_score"), 45.0, 9.0)
        + _positive_component(row.get("sector_flow_score"), 10.0, 6.0)
        + _positive_component(row.get("ticker_ret_20d") or row.get("ret_20d"), 45.0, 11.0)
        + _positive_component(row.get("rank_score"), 3.0, 10.0)
        + _positive_component(row.get("futures_score"), 18.0, 18.0)
    )
    value = (
        _positive_component(row.get("value_score"), 5.0, 12.0)
        + _positive_component(row.get("fcf_yield"), 40.0, 6.0)
        + _positive_component(row.get("rev_growth"), 18.0, 6.0)
        + _positive_component(row.get("fund_score"), 3.0, 6.0)
    )
    execution = 0.0
    if asset == "option":
        dte = _float_value(row.get("dte"), default=math.nan)
        spread = _float_value(row.get("spread_pct"), default=math.nan)
        contracts = _float_value(row.get("suggested_contracts"), default=0.0)
        if math.isfinite(dte) and dte >= MIN_SWING_OPTION_DTE:
            execution += 8.0
        if math.isfinite(spread):
            if spread <= 0.12:
                execution += 8.0
            elif spread <= 0.20:
                execution += 4.0
            elif spread > 0.30:
                execution -= 10.0
        if contracts > 0:
            execution += 7.0
    elif asset == "share":
        if _float_value(row.get("suggested_dollars"), default=0.0) > 0:
            execution += 7.0
    elif asset == "futures":
        if _float_value(row.get("suggested_contracts"), default=0.0) > 0:
            execution += 8.0
        if bool(row.get("using_micro")):
            execution += 4.0
        risk = _float_value(row.get("risk_dollars"), default=math.nan)
        reward = _float_value(row.get("reward_dollars"), default=math.nan)
        if math.isfinite(risk) and math.isfinite(reward) and risk > 0:
            execution += _clamp((reward / risk - 1.0) * 5.0, 0.0, 8.0)
    elif asset == "value":
        if str(row.get("value_bucket") or "").lower() in {"deep value", "value"}:
            execution += 5.0

    quality = _clamp((readiness_score - 55.0) * 0.35, 0.0, 16.0)
    confidence_component = (
        _clamp((confidence - 50.0) * 0.30, 0.0, 15.0) if math.isfinite(confidence) else 0.0
    )
    return {
        "market_cap_profile": cap_profile,
        "squeeze": round(squeeze, 2),
        "attention": round(attention, 2),
        "momentum": round(momentum, 2),
        "value": round(value, 2),
        "execution": round(execution, 2),
        "quality": round(quality, 2),
        "confidence": round(confidence_component, 2),
        "readiness": readiness,
    }


def _fmt_compact_number(value: Any, *, precision: int = 1) -> str | None:
    val = _float_value(value, default=math.nan)
    if not math.isfinite(val):
        return None
    if abs(val) >= 1_000_000_000:
        return f"{val / 1_000_000_000:.1f}B"
    if abs(val) >= 1_000_000:
        return f"{val / 1_000_000:.1f}M"
    if abs(val) >= 1_000:
        return f"{val / 1_000:.1f}K"
    return f"{val:.{precision}f}"


def _fmt_ratio_pct(value: Any, *, precision: int = 0) -> str | None:
    val = _float_value(value, default=math.nan)
    if not math.isfinite(val):
        return None
    return f"{val * 100:.{precision}f}%"


def _fmt_dollars(value: Any) -> str | None:
    val = _float_value(value, default=math.nan)
    if not math.isfinite(val):
        return None
    return f"${val:,.0f}" if abs(val) >= 100 else f"${val:,.2f}"


def _join_factor_parts(parts: list[str | None], fallback: str) -> str:
    clean = [part for part in parts if part]
    return ", ".join(clean[:4]) if clean else fallback


def _swing_factor_summary(factors: list[dict[str, Any]], limit: int = 3) -> str | None:
    names = [str(item.get("factor") or "").strip() for item in factors if item.get("factor")]
    return " + ".join(names[:limit]) if names else None


def _swing_factor_breakdown(
    row: pd.Series, asset: str, components: dict[str, Any]
) -> list[dict[str, Any]]:
    cap_profile = (
        components.get("market_cap_profile")
        if isinstance(components.get("market_cap_profile"), dict)
        else {}
    )
    readiness = components.get("readiness") if isinstance(components.get("readiness"), dict) else {}
    factors: list[dict[str, Any]] = []

    def add(factor: str, score: Any, detail: str, minimum: float = 0.1) -> None:
        score_val = _float_value(score, default=0.0)
        if score_val < minimum:
            return
        factors.append(
            {
                "factor": factor,
                "score": round(score_val, 2),
                "detail": detail[:160],
            }
        )

    if asset != "futures":
        cap_bonus = _float_value(cap_profile.get("bonus"), default=0.0)
        cap = _fmt_compact_number(cap_profile.get("market_cap"), precision=0)
        detail = _join_factor_parts(
            [
                str(cap_profile.get("bucket") or "unknown") + " cap",
                f"${cap}" if cap else None,
            ],
            "market cap profile",
        )
        add("Market cap", max(cap_bonus, 0.0), detail, minimum=0.1)

    add(
        "Squeeze",
        components.get("squeeze"),
        _join_factor_parts(
            [
                f"short float {_fmt_ratio_pct(row.get('short_pct_of_float'))}"
                if _fmt_ratio_pct(row.get("short_pct_of_float"))
                else None,
                f"short vol {_fmt_ratio_pct(row.get('short_vol_ratio'))}"
                if _fmt_ratio_pct(row.get("short_vol_ratio"))
                else None,
                f"short score {_fmt_compact_number(row.get('short_int_score'))}"
                if _fmt_compact_number(row.get("short_int_score"))
                else None,
                f"UOA {_fmt_compact_number(row.get('uoa_score'))}"
                if _fmt_compact_number(row.get("uoa_score"))
                else None,
                f"dark pool {_fmt_compact_number(row.get('dark_pool_score'))}"
                if _fmt_compact_number(row.get("dark_pool_score"))
                else None,
            ],
            "short interest or flow pressure",
        ),
    )
    add(
        "Attention",
        components.get("attention"),
        _join_factor_parts(
            [
                f"social {_fmt_compact_number(row.get('social_score'))}"
                if _fmt_compact_number(row.get("social_score"))
                else None,
                f"trends {_fmt_compact_number(row.get('gtrends_score'))}"
                if _fmt_compact_number(row.get("gtrends_score"))
                else None,
                f"twitter {_fmt_compact_number(row.get('twitter_score'))}"
                if _fmt_compact_number(row.get("twitter_score"))
                else None,
                f"mentions {_fmt_compact_number(row.get('mentions'), precision=0)}"
                if _fmt_compact_number(row.get("mentions"), precision=0)
                else None,
            ],
            "retail attention lift",
        ),
    )
    add(
        "Momentum",
        components.get("momentum"),
        _join_factor_parts(
            [
                f"tech {_fmt_compact_number(row.get('tech_score'))}"
                if _fmt_compact_number(row.get("tech_score"))
                else None,
                f"sector RS {_fmt_compact_number(row.get('sector_rs_score'))}"
                if _fmt_compact_number(row.get("sector_rs_score"))
                else None,
                f"20d {_fmt_ratio_pct(row.get('ticker_ret_20d') or row.get('ret_20d'))}"
                if _fmt_ratio_pct(row.get("ticker_ret_20d") or row.get("ret_20d"))
                else None,
                f"rank {_fmt_compact_number(row.get('rank_score'))}"
                if _fmt_compact_number(row.get("rank_score"))
                else None,
                f"futures {_fmt_compact_number(row.get('futures_score'))}"
                if _fmt_compact_number(row.get("futures_score"))
                else None,
            ],
            "price or macro momentum",
        ),
    )
    add(
        "Value",
        components.get("value"),
        _join_factor_parts(
            [
                f"value {_fmt_compact_number(row.get('value_score'))}"
                if _fmt_compact_number(row.get("value_score"))
                else None,
                f"FCF {_fmt_ratio_pct(row.get('fcf_yield'))}"
                if _fmt_ratio_pct(row.get("fcf_yield"))
                else None,
                f"growth {_fmt_ratio_pct(row.get('rev_growth'))}"
                if _fmt_ratio_pct(row.get("rev_growth"))
                else None,
                f"fund {_fmt_compact_number(row.get('fund_score'))}"
                if _fmt_compact_number(row.get("fund_score"))
                else None,
            ],
            "value or fundamental dislocation",
        ),
    )

    execution_parts: list[str | None]
    if asset == "option":
        execution_parts = [
            f"{int(_float_value(row.get('dte')))}d DTE"
            if math.isfinite(_float_value(row.get("dte"), default=math.nan))
            else None,
            f"spread {_fmt_ratio_pct(row.get('spread_pct'))}"
            if _fmt_ratio_pct(row.get("spread_pct"))
            else None,
            f"{_fmt_compact_number(row.get('suggested_contracts'), precision=0)} contract(s)"
            if _fmt_compact_number(row.get("suggested_contracts"), precision=0)
            else None,
        ]
    elif asset == "share":
        execution_parts = [
            f"size {_fmt_dollars(row.get('suggested_dollars'))}"
            if _fmt_dollars(row.get("suggested_dollars"))
            else None,
            f"EV {_fmt_ratio_pct(row.get('ev_pct'))}"
            if _fmt_ratio_pct(row.get("ev_pct"))
            else None,
        ]
    elif asset == "futures":
        reward = _float_value(row.get("reward_dollars"), default=math.nan)
        risk = _float_value(row.get("risk_dollars"), default=math.nan)
        rr = (
            reward / risk
            if math.isfinite(reward) and math.isfinite(risk) and risk > 0
            else math.nan
        )
        execution_parts = [
            str(row.get("contract") or row.get("micro_contract") or "").strip() or None,
            "micro" if bool(row.get("using_micro")) else None,
            f"{_fmt_compact_number(row.get('suggested_contracts'), precision=0)} contract(s)"
            if _fmt_compact_number(row.get("suggested_contracts"), precision=0)
            else None,
            f"R/R {rr:.1f}x" if math.isfinite(rr) else None,
        ]
    else:
        execution_parts = [str(row.get("value_bucket") or "").strip() or None]
    add(
        "Execution",
        components.get("execution"),
        _join_factor_parts(execution_parts, "sizing and execution quality"),
    )
    add(
        "Quality",
        components.get("quality"),
        _join_factor_parts(
            [
                str(readiness.get("readiness_label") or "").strip() or None,
                f"readiness {_fmt_compact_number(readiness.get('readiness_score'), precision=0)}"
                if _fmt_compact_number(readiness.get("readiness_score"), precision=0)
                else None,
            ],
            "setup readiness",
        ),
    )
    add(
        "Confidence",
        components.get("confidence"),
        _join_factor_parts(
            [
                f"confidence {_fmt_compact_number(row.get('confidence'), precision=0)}"
                if _fmt_compact_number(row.get("confidence"), precision=0)
                else None,
            ],
            "model confidence",
        ),
    )
    return sorted(
        factors, key=lambda item: _float_value(item.get("score"), default=0.0), reverse=True
    )[:5]


def _swing_scout_lane(row: pd.Series, asset: str, components: dict[str, Any]) -> str:
    if asset == "futures":
        return "futures_macro_swing"
    squeeze = _float_value(components.get("squeeze"))
    attention = _float_value(components.get("attention"))
    value = _float_value(components.get("value"))
    if asset == "option":
        if squeeze >= 14 or attention >= 12:
            return "small_cap_options_momentum"
        return "long_dated_option_swing"
    if asset == "value" or value >= 10:
        return "small_cap_value_dislocation"
    if squeeze >= 14:
        return "small_cap_squeeze_watch"
    if attention >= 12:
        return "retail_attention_swing"
    return "small_cap_share_swing"


def _swing_scout_reasons(
    row: pd.Series, asset: str, components: dict[str, Any]
) -> tuple[list[str], list[str]]:
    reasons: list[str] = []
    warnings: list[str] = []
    cap = components["market_cap_profile"]
    if asset != "futures":
        reasons.append(
            f"{cap['bucket']} cap" if cap.get("bucket") != "unknown" else "market cap unknown"
        )
        if cap.get("warning"):
            warnings.append(str(cap["warning"]))
    if _float_value(components.get("squeeze")) >= 12:
        reasons.append("short/squeeze pressure")
    if _float_value(components.get("attention")) >= 10:
        reasons.append("retail/attention lift")
    if _float_value(components.get("momentum")) >= 12:
        reasons.append("momentum confirmation")
    if _float_value(components.get("value")) >= 10:
        reasons.append("value/fundamental dislocation")
    if asset == "futures":
        reasons.append("futures/macro momentum")
    readiness = components.get("readiness") if isinstance(components.get("readiness"), dict) else {}
    warnings.extend(str(flag) for flag in (readiness.get("risk_flags") or [])[:4])
    if str(row.get("snapshot_freshness") or "").lower() == "stale":
        warnings.append("stale snapshot")
    if asset == "option":
        dte = _float_value(row.get("dte"), default=math.nan)
        if math.isfinite(dte) and dte < MIN_SWING_OPTION_DTE:
            warnings.append("below 90 DTE")
        spread = _float_value(row.get("spread_pct"), default=math.nan)
        if math.isfinite(spread) and spread > 0.20:
            warnings.append("wide option spread")
    return list(dict.fromkeys(reasons))[:6], list(dict.fromkeys(warnings))[:6]


def _swing_scout_review_state(record: dict[str, Any]) -> dict[str, Any]:
    score = _float_value(record.get("swing_scout_score"), default=0.0)
    readiness = str(record.get("readiness_label") or "").strip().lower()
    warnings = [str(item).lower() for item in (record.get("warnings") or []) if str(item).strip()]
    warning_penalty = min(30.0, 5.0 * len(warnings))
    if any("below 90 dte" in warning for warning in warnings):
        warning_penalty += 25.0
    if any("stale" in warning for warning in warnings):
        warning_penalty += 10.0
    if any("micro-cap execution risk" in warning for warning in warnings):
        warning_penalty += 5.0
    readiness_bonus = {
        "ready": 10.0,
        "review": 5.0,
        "caution": -5.0,
        "wait": -22.0,
    }.get(readiness, 0.0)
    conviction = int(round(_clamp(score + readiness_bonus - warning_penalty, 0.0, 100.0)))
    if conviction >= 85 and readiness != "wait":
        action = "review_now"
        label = "Review now"
    elif conviction >= 70 and readiness != "wait":
        action = "shortlist"
        label = "Shortlist"
    elif conviction >= 55:
        action = "watch"
        label = "Watch"
    else:
        action = "wait"
        label = "Wait"
    return {
        "review_action": action,
        "review_label": label,
        "conviction_score": conviction,
        "warning_count": len(warnings),
    }


def _swing_scout_record(row: pd.Series, asset: str, source_file: str | None) -> dict[str, Any]:
    components = _swing_scout_components(row, asset)
    cap_profile = components["market_cap_profile"]
    base = 34.0 if asset != "futures" else 42.0
    if asset != "futures":
        base += _float_value(cap_profile.get("bonus"))
    raw_score = (
        base
        + _float_value(components.get("squeeze"))
        + _float_value(components.get("attention"))
        + _float_value(components.get("momentum"))
        + _float_value(components.get("value"))
        + _float_value(components.get("execution"))
        + _float_value(components.get("quality"))
        + _float_value(components.get("confidence"))
    )
    reasons, warnings = _swing_scout_reasons(row, asset, components)
    readiness = components.get("readiness") if isinstance(components.get("readiness"), dict) else {}
    symbol = _setup_symbol(row, asset, OPPORTUNITY_SPECS[asset])
    setup = _setup_label(row, asset, symbol)
    factor_breakdown = _swing_factor_breakdown(row, asset, components)
    record = {
        "asset": asset,
        "ticker_or_symbol": symbol,
        "setup": setup,
        "lane": _swing_scout_lane(row, asset, components),
        "swing_scout_score": int(round(_clamp(raw_score, 0.0, 100.0))),
        "market_cap_bucket": cap_profile.get("bucket"),
        "market_cap": _clean_value(cap_profile.get("market_cap")),
        "squeeze_score": components.get("squeeze"),
        "attention_score": components.get("attention"),
        "momentum_score": components.get("momentum"),
        "value_score_component": components.get("value"),
        "execution_score": components.get("execution"),
        "readiness_score": readiness.get("readiness_score"),
        "readiness_label": readiness.get("readiness_label"),
        "confidence": _clean_value(row.get("confidence")),
        "rank_score": _clean_value(row.get("rank_score")),
        "trade_status": _clean_value(
            row.get("trade_status") or ("Trade" if bool(row.get("actionable")) else "Review")
        ),
        "entry_price": _setup_entry_price(row, asset),
        "stop_price": _clean_value(row.get("stop_price")),
        "target_price": _clean_value(row.get("target_price")),
        "size": _setup_size(row, asset),
        "dte": _clean_value(row.get("dte")),
        "expiry": _clean_value(row.get("expiry")),
        "spread_pct": _clean_value(row.get("spread_pct")),
        "short_pct_of_float": _clean_value(row.get("short_pct_of_float")),
        "short_vol_ratio": _clean_value(row.get("short_vol_ratio")),
        "social_score": _clean_value(row.get("social_score")),
        "gtrends_score": _clean_value(row.get("gtrends_score")),
        "tech_score": _clean_value(row.get("tech_score")),
        "futures_score": _clean_value(row.get("futures_score")),
        "ret_20d": _clean_value(row.get("ret_20d") or row.get("ticker_ret_20d")),
        "quality": _setup_quality(row, asset),
        "factor_breakdown": factor_breakdown,
        "factor_summary": _swing_factor_summary(factor_breakdown),
        "reasons": reasons,
        "warnings": warnings,
        "source_file": _clean_value(row.get("_source_file") or source_file),
        "snapshot_freshness": _clean_value(row.get("snapshot_freshness")),
        "snapshot_age_min": _clean_value(row.get("snapshot_age_min")),
    }
    record.update(_swing_scout_review_state(record))
    return record


def _swing_scout_query_text(row: dict[str, Any]) -> str:
    parts = [
        row.get("asset"),
        row.get("ticker_or_symbol"),
        row.get("setup"),
        row.get("lane"),
        row.get("market_cap_bucket"),
        row.get("trade_status"),
        row.get("quality"),
    ]
    parts.extend(row.get("reasons") or [])
    parts.extend(row.get("warnings") or [])
    return " ".join(str(part or "") for part in parts).lower()


def _market_structure_risk_maps(symbols: list[str]) -> dict[str, dict[str, Any]]:
    """Return market-structure risk context for live small-cap mover rows."""
    wanted = {str(symbol or "").strip().upper() for symbol in symbols if str(symbol or "").strip()}
    risk: dict[str, dict[str, Any]] = {
        symbol: {
            "score": 0.0,
            "penalty": 0.0,
            "warnings": [],
            "risk_flags": [],
            "active_halt": False,
            "recent_halt": False,
            "regsho_threshold": False,
            "short_sale_restricted": False,
        }
        for symbol in wanted
    }
    if not wanted:
        return risk

    def row_symbol(row: pd.Series) -> str:
        return str(row.get("symbol") or "").strip().upper()

    def add_warning(symbol: str, warning: str) -> None:
        if symbol not in risk:
            return
        warnings = risk[symbol].setdefault("warnings", [])
        if warning not in warnings:
            warnings.append(warning)

    def add_flag(symbol: str, flag: str) -> None:
        if symbol not in risk:
            return
        flags = risk[symbol].setdefault("risk_flags", [])
        if flag not in flags:
            flags.append(flag)

    def bump(symbol: str, score: float, penalty: float) -> None:
        if symbol not in risk:
            return
        risk[symbol]["score"] = max(_float_value(risk[symbol].get("score")), score)
        risk[symbol]["penalty"] = max(_float_value(risk[symbol].get("penalty")), penalty)

    try:
        halts = halt_rows_for_symbols(sorted(wanted), cache_age=60)
    except Exception:
        halts = pd.DataFrame()
    if isinstance(halts, pd.DataFrame) and not halts.empty:
        for _, halt in halts.iterrows():
            symbol = row_symbol(halt)
            if symbol not in risk:
                continue
            active = bool(halt.get("active_halt"))
            score = _float_value(halt.get("halt_risk_score"), default=96.0 if active else 72.0)
            if active:
                risk[symbol]["active_halt"] = True
                add_warning(symbol, "active trading halt")
                add_flag(symbol, "active_halt")
                bump(symbol, score, 45.0)
            else:
                risk[symbol]["recent_halt"] = True
                add_warning(symbol, "recent trading halt")
                add_flag(symbol, "recent_halt")
                bump(symbol, score, 16.0)

    try:
        thresholds = threshold_rows_for_symbols(sorted(wanted), cache_age=6 * 3600)
    except Exception:
        thresholds = pd.DataFrame()
    if isinstance(thresholds, pd.DataFrame) and not thresholds.empty:
        for _, threshold in thresholds.iterrows():
            symbol = row_symbol(threshold)
            if symbol not in risk:
                continue
            if bool(threshold.get("is_threshold")):
                risk[symbol]["regsho_threshold"] = True
                add_warning(symbol, "Reg SHO threshold list")
                add_flag(symbol, "regsho_threshold")
                bump(
                    symbol, _float_value(threshold.get("settlement_risk_score"), default=86.0), 12.0
                )

    try:
        circuits = circuit_rows_for_symbols(sorted(wanted), cache_age=30 * 60)
    except Exception:
        circuits = pd.DataFrame()
    if isinstance(circuits, pd.DataFrame) and not circuits.empty:
        for _, circuit in circuits.iterrows():
            symbol = row_symbol(circuit)
            if symbol not in risk:
                continue
            if bool(circuit.get("short_sale_restricted")):
                risk[symbol]["short_sale_restricted"] = True
                add_warning(symbol, "short-sale circuit breaker active")
                add_flag(symbol, "short_sale_restricted")
                bump(symbol, _float_value(circuit.get("ssr_risk_score"), default=82.0), 8.0)

    return risk


def _nasdaq_mover_scout_record(
    row: pd.Series,
    market_risk: dict[str, Any] | None = None,
) -> dict[str, Any]:
    symbol = str(row.get("symbol") or "").strip().upper()
    pct = _float_value(row.get("pct_change"), default=0.0)
    volume = _float_value(row.get("volume"), default=0.0)
    cap = _float_value(row.get("market_cap"), default=0.0)
    short_vol_ratio = _float_value(row.get("short_vol_ratio"), default=math.nan)
    dark_pool_score = _float_value(row.get("dark_pool_score"), default=math.nan)
    short_pressure_bonus = 0
    if math.isfinite(short_vol_ratio):
        if short_vol_ratio >= 0.60:
            short_pressure_bonus = 7
        elif short_vol_ratio >= 0.55:
            short_pressure_bonus = 4
        elif short_vol_ratio <= 0.35:
            short_pressure_bonus = -2
    direction = "upside momentum" if pct >= 0 else "downside volatility"
    reasons = [
        f"Nasdaq screener {direction}",
        f"{pct:+.1f}% move",
        f"{volume:,.0f} volume",
    ]
    if cap > 0:
        reasons.append(f"${cap / 1_000_000:.0f}M market cap")
    if math.isfinite(short_vol_ratio):
        reasons.append(f"FINRA short-volume {short_vol_ratio * 100:.0f}%")
    warnings = [
        "free/delayed screener row",
        "run focused scan before acting",
    ]
    if pct < 0:
        warnings.append("red mover: confirm reversal thesis")
    if math.isfinite(short_vol_ratio) and short_vol_ratio >= 0.60:
        warnings.append("heavy short-volume pressure")
    market_risk = market_risk if isinstance(market_risk, dict) else {}
    risk_score = _float_value(market_risk.get("score"), default=0.0)
    risk_penalty = _float_value(market_risk.get("penalty"), default=0.0)
    risk_warnings = [
        str(item).strip() for item in (market_risk.get("warnings") or []) if str(item).strip()
    ]
    risk_flags = [
        str(item).strip() for item in (market_risk.get("risk_flags") or []) if str(item).strip()
    ]
    warnings.extend(risk_warnings)
    base_score = (
        _float_value(row.get("nasdaq_mover_score"), default=0.0)
        + short_pressure_bonus
        - risk_penalty
    )
    factor_breakdown = [
        {
            "factor": "Momentum",
            "score": round(abs(pct), 2),
            "detail": f"{pct:+.1f}% move, {volume:,.0f} volume",
        },
    ]
    if math.isfinite(short_vol_ratio):
        factor_breakdown.append(
            {
                "factor": "Short volume",
                "score": round(max(short_pressure_bonus, 0), 2),
                "detail": f"FINRA short-volume {short_vol_ratio * 100:.0f}%",
            }
        )
    if cap > 0:
        factor_breakdown.append(
            {
                "factor": "Market cap",
                "score": 8.0 if cap < 2_000_000_000 else 3.0,
                "detail": f"${cap / 1_000_000:.0f}M market cap",
            }
        )
    if risk_score > 0:
        factor_breakdown.append(
            {
                "factor": "Market-structure risk",
                "score": -round(min(45.0, risk_penalty), 2),
                "detail": ", ".join(risk_warnings[:3]) or "Nasdaq market-structure warning",
            }
        )
    factor_breakdown = sorted(
        factor_breakdown,
        key=lambda item: _float_value(item.get("score"), default=0.0),
        reverse=True,
    )[:5]
    record = {
        "asset": "share",
        "ticker_or_symbol": symbol,
        "setup": f"{symbol} small-cap mover",
        "lane": "nasdaq_small_cap_mover",
        "swing_scout_score": int(round(_clamp(base_score, 0.0, 100.0))),
        "market_cap_bucket": _clean_value(row.get("market_cap_bucket")),
        "market_cap": _clean_value(row.get("market_cap")),
        "squeeze_score": _clean_value(
            round(max(short_pressure_bonus, 0), 2) if math.isfinite(short_vol_ratio) else None
        ),
        "attention_score": None,
        "momentum_score": _clean_value(abs(pct)),
        "value_score_component": None,
        "execution_score": None,
        "readiness_score": None,
        "readiness_label": "review",
        "confidence": None,
        "rank_score": None,
        "trade_status": "Review",
        "entry_price": _clean_value(row.get("last_price")),
        "stop_price": None,
        "target_price": None,
        "size": None,
        "dte": None,
        "expiry": None,
        "spread_pct": None,
        "short_pct_of_float": None,
        "short_vol_ratio": _clean_value(
            short_vol_ratio if math.isfinite(short_vol_ratio) else None
        ),
        "dark_pool_score": _clean_value(
            dark_pool_score if math.isfinite(dark_pool_score) else None
        ),
        "social_score": None,
        "gtrends_score": None,
        "tech_score": None,
        "futures_score": None,
        "ret_20d": None,
        "quality": "live-radar review",
        "pct_change": _clean_value(row.get("pct_change")),
        "volume": _clean_value(row.get("volume")),
        "sector": _clean_value(row.get("sector")),
        "industry": _clean_value(row.get("industry")),
        "name": _clean_value(row.get("name")),
        "market_structure_risk_score": _clean_value(round(risk_score, 2) if risk_score else None),
        "market_structure_risk_flags": risk_flags,
        "market_structure_warnings": risk_warnings,
        "active_halt": bool(market_risk.get("active_halt")),
        "recent_halt": bool(market_risk.get("recent_halt")),
        "regsho_threshold": bool(market_risk.get("regsho_threshold")),
        "short_sale_restricted": bool(market_risk.get("short_sale_restricted")),
        "factor_breakdown": factor_breakdown,
        "factor_summary": _swing_factor_summary(factor_breakdown),
        "reasons": reasons[:6],
        "warnings": warnings[:6],
        "source_file": "nasdaq_screener",
        "snapshot_freshness": "live_public_delayed",
        "snapshot_age_min": 0,
    }
    record.update(_swing_scout_review_state(record))
    if record["active_halt"]:
        record["readiness_label"] = "wait"
        record["trade_status"] = "Wait"
        record["review_action"] = "wait"
        record["review_label"] = "Wait"
        record["conviction_score"] = min(int(record.get("conviction_score") or 0), 40)
    return record


def _append_nasdaq_mover_scout_rows(
    rows: list[dict[str, Any]],
    *,
    asset: str,
    query_norm: str,
    lane: str,
    min_score: float,
    include_wait: bool,
    max_rows: int = 24,
) -> tuple[int, str | None]:
    if asset not in {"all", "share"}:
        return 0, None
    try:
        movers = small_cap_movers(max_rows=max_rows)
    except Exception:
        return 0, None
    if movers.empty:
        return 0, None
    mover_symbols = [
        str(symbol or "").strip().upper()
        for symbol in movers.get("symbol", pd.Series(dtype=str)).tolist()
        if str(symbol or "").strip()
    ]
    try:
        short_flow = dark_pool_engine.run(mover_symbols, lookback_days=3)
    except Exception:
        short_flow = pd.DataFrame()
    if (
        isinstance(short_flow, pd.DataFrame)
        and not short_flow.empty
        and "ticker" in short_flow.columns
    ):
        enrich_cols = [
            col
            for col in ("ticker", "short_vol_ratio", "short_vol", "total_vol", "dark_pool_score")
            if col in short_flow.columns
        ]
        if len(enrich_cols) > 1:
            movers = movers.merge(
                short_flow[enrich_cols].rename(columns={"ticker": "symbol"}),
                on="symbol",
                how="left",
            )
    market_risk = _market_structure_risk_maps(mover_symbols)
    added = 0
    seen_symbols = {str(row.get("ticker_or_symbol") or "").upper() for row in rows}
    for _, mover in movers.iterrows():
        symbol_key = str(mover.get("symbol") or "").strip().upper()
        record = _nasdaq_mover_scout_record(mover, market_risk.get(symbol_key))
        symbol = str(record.get("ticker_or_symbol") or "").upper()
        if not symbol or symbol in seen_symbols:
            continue
        if record["swing_scout_score"] < min_score:
            continue
        if not include_wait and str(record.get("readiness_label") or "").lower() == "wait":
            continue
        if lane != "all" and str(record.get("lane") or "").lower() != lane:
            continue
        if query_norm and query_norm not in _swing_scout_query_text(record):
            continue
        rows.append(record)
        seen_symbols.add(symbol)
        added += 1
    return added, "nasdaq_screener"


@_memoized_report
def build_swing_scout(
    data_dir: Path = DATA_DIR,
    limit: int = 18,
    asset: str = "all",
    query: str = "",
    lane: str = "all",
    min_score: float = 45.0,
    include_wait: bool = True,
    include_nasdaq_movers: bool = False,
) -> dict[str, Any]:
    """Surface speculative small/mid-cap and futures swing candidates from local free-factor outputs."""
    limit = max(1, min(int(limit or 18), 60))
    asset = str(asset or "all").strip().lower()
    if asset not in {"all", "option", "share", "value", "futures"}:
        asset = "all"
    lane = str(lane or "all").strip().lower()
    query_norm = str(query or "").strip().lower()
    min_score = _clamp(_float_value(min_score, default=45.0), 0.0, 100.0)
    rows: list[dict[str, Any]] = []
    asset_counts: dict[str, int] = {}
    source_files: dict[str, str | None] = {}
    reviewed_count = 0
    for asset_name in ("option", "share", "value", "futures"):
        if asset != "all" and asset_name != asset:
            continue
        spec = OPPORTUNITY_SPECS[asset_name]
        path = _latest_file(data_dir, spec["pattern"])
        source_file = path.name if path else None
        source_files[asset_name] = source_file
        df = _read_parquet(path)
        if df.empty:
            continue
        out = df.copy()
        out["asset"] = asset_name
        out["actionable"] = out.apply(_is_actionable, axis=1)
        reviewed_count += int(len(out))
        if asset_name == "option" and "dte" in out.columns:
            out = out[
                pd.to_numeric(out["dte"], errors="coerce").fillna(0.0) >= MIN_SWING_OPTION_DTE
            ]
        for _, row in out.iterrows():
            record = _swing_scout_record(row, asset_name, source_file)
            if record["swing_scout_score"] < min_score:
                continue
            if not include_wait and str(record.get("readiness_label") or "").lower() == "wait":
                continue
            if lane != "all" and str(record.get("lane") or "").lower() != lane:
                continue
            if query_norm and query_norm not in _swing_scout_query_text(record):
                continue
            rows.append(record)
            asset_counts[asset_name] = asset_counts.get(asset_name, 0) + 1
    nasdaq_added = 0
    nasdaq_source = None
    if include_nasdaq_movers:
        nasdaq_added, nasdaq_source = _append_nasdaq_mover_scout_rows(
            rows,
            asset=asset,
            query_norm=query_norm,
            lane=lane,
            min_score=min_score,
            include_wait=include_wait,
        )
        if nasdaq_added:
            asset_counts["share"] = asset_counts.get("share", 0) + nasdaq_added
            source_files["nasdaq_movers"] = nasdaq_source
    rows = sorted(
        rows,
        key=lambda row: (
            _float_value(row.get("swing_scout_score")),
            _float_value(row.get("readiness_score")),
            _float_value(row.get("confidence")),
        ),
        reverse=True,
    )[:limit]
    lane_counts: dict[str, int] = {}
    review_action_counts: dict[str, int] = {}
    for row in rows:
        lane_name = str(row.get("lane") or "unknown")
        lane_counts[lane_name] = lane_counts.get(lane_name, 0) + 1
        action_name = str(row.get("review_action") or "unknown")
        review_action_counts[action_name] = review_action_counts.get(action_name, 0) + 1
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "count": len(rows),
        "reviewed_count": reviewed_count,
        "rows": rows,
        "asset_counts": asset_counts,
        "lane_counts": lane_counts,
        "review_action_counts": review_action_counts,
        "sources": source_files,
        "min_option_dte": MIN_SWING_OPTION_DTE,
        "filters": {
            "asset": asset,
            "query": query,
            "lane": lane,
            "min_score": min_score,
            "include_wait": bool(include_wait),
            "include_nasdaq_movers": bool(include_nasdaq_movers),
            "limit": limit,
        },
        "notes": [
            "Swing scout is a read-only ranking of high-upside review candidates from existing Optedge snapshots.",
            "When enabled from the cockpit, Nasdaq's public screener adds a capped no-key small-cap mover radar.",
            "Equity-linked rows emphasize small/mid-cap asymmetry, short pressure, retail attention, momentum, value, and execution quality.",
            "Futures rows use the futures/macro momentum lane because market-cap logic does not apply to futures contracts.",
            "Options under 90 DTE are excluded from this scout; use the option-chain panel for exact contract review.",
        ],
    }


def _suggestion_text(row: dict[str, Any]) -> str:
    return " ".join(
        str(row.get(key) or "") for key in ("symbol", "label", "name", "query")
    ).lower()


def _add_suggestion(
    rows: list[dict[str, Any]],
    seen: set[tuple[str, str, str]],
    symbol: Any,
    label: str,
    kind: str,
    source: str,
    query: str | None = None,
    name: Any = None,
    score: Any = None,
    trade_status: Any = None,
) -> None:
    clean_symbol = str(symbol or "").strip().upper()
    clean_label = str(label or clean_symbol).strip()
    clean_query = str(query or clean_symbol).strip()
    if not clean_symbol or not clean_query:
        return
    key = (kind, clean_symbol, clean_query.upper())
    if key in seen:
        return
    seen.add(key)
    rows.append(
        {
            "symbol": clean_symbol,
            "label": clean_label,
            "kind": kind,
            "source": source,
            "query": clean_query,
            "name": _clean_value(name),
            "score": _clean_value(score),
            "trade_status": _clean_value(trade_status),
        }
    )


def _option_query_from_row(row: pd.Series | dict[str, Any]) -> str:
    ticker = (
        str(
            row.get("ticker")
            or row.get("symbol")
            or row.get("chain_symbol")
            or row.get("ticker_or_symbol")
            or ""
        )
        .strip()
        .upper()
    )
    expiry = str(
        row.get("expiry")
        or row.get("expiration_date")
        or row.get("lastTradeDateOrContractMonth")
        or ""
    ).strip()
    side_raw = (
        str(
            row.get("side")
            or row.get("option_side")
            or row.get("option_type")
            or row.get("right")
            or ""
        )
        .strip()
        .upper()
    )
    side = "C" if side_raw.startswith("C") else "P" if side_raw.startswith("P") else side_raw[:1]
    strike = row.get("strike", row.get("strike_price"))
    if not ticker or not expiry or not side or strike in (None, ""):
        return ticker
    try:
        strike_text = f"{float(strike):g}"
    except Exception:
        strike_text = str(strike)
    return f"{ticker} {expiry} {side} {strike_text}"


def _add_broker_snapshot_suggestions(
    rows: list[dict[str, Any]],
    seen: set[tuple[str, str, str]],
    data_dir: Path,
) -> None:
    snapshot = _read_json(data_dir / "robinhood_broker_snapshot.json")
    if not isinstance(snapshot, dict):
        return
    accounts = snapshot.get("accounts") if isinstance(snapshot.get("accounts"), list) else []
    direct_options = (
        snapshot.get("option_positions")
        if isinstance(snapshot.get("option_positions"), list)
        else []
    )
    direct_equities = (
        snapshot.get("equity_positions")
        if isinstance(snapshot.get("equity_positions"), list)
        else []
    )

    def add_option(raw: dict[str, Any], account_label: Any = None) -> None:
        symbol = (
            str(raw.get("chain_symbol") or raw.get("symbol") or raw.get("ticker") or "")
            .strip()
            .upper()
        )
        if not symbol:
            return
        side_raw = (
            str(raw.get("option_type") or raw.get("side") or raw.get("right") or "").strip().lower()
        )
        side = (
            "C"
            if side_raw.startswith("call") or side_raw == "c"
            else "P"
            if side_raw.startswith("put") or side_raw == "p"
            else side_raw.upper()
        )
        expiry = str(raw.get("expiration_date") or raw.get("expiry") or "").strip()
        strike = str(raw.get("strike_price") or raw.get("strike") or "").strip()
        qty = _float_value(raw.get("quantity") or raw.get("contracts"), default=None)
        qty_text = f"{qty:g}x " if qty is not None else ""
        contract = " ".join(part for part in [symbol, expiry, side, strike] if part)
        label = f"{symbol} broker {qty_text}{contract}".strip()
        _add_suggestion(
            rows,
            seen,
            symbol,
            label,
            "broker_option",
            "Robinhood broker snapshot",
            query=_option_query_from_row(raw) or symbol,
            name=account_label,
            score=1.2,
            trade_status="broker_open",
        )

    def add_equity(raw: dict[str, Any], account_label: Any = None) -> None:
        symbol = str(raw.get("symbol") or raw.get("ticker") or "").strip().upper()
        if not symbol:
            return
        qty = _float_value(raw.get("quantity") or raw.get("shares"), default=None)
        qty_text = f"{qty:g} shares" if qty is not None else "shares"
        _add_suggestion(
            rows,
            seen,
            symbol,
            f"{symbol} broker {qty_text}",
            "broker_equity",
            "Robinhood broker snapshot",
            query=symbol,
            name=account_label,
            score=1.15,
            trade_status="broker_open",
        )

    for raw in direct_options:
        if isinstance(raw, dict):
            add_option(raw)
    for raw in direct_equities:
        if isinstance(raw, dict):
            add_equity(raw)
    for account in accounts:
        if not isinstance(account, dict):
            continue
        account_label = (
            account.get("nickname") or account.get("label") or account.get("account_mask")
        )
        for raw in account.get("option_positions") or []:
            if isinstance(raw, dict):
                add_option(raw, account_label)
        for raw in account.get("equity_positions") or []:
            if isinstance(raw, dict):
                add_equity(raw, account_label)


def build_symbol_suggestions(
    data_dir: Path = DATA_DIR,
    query: str = "",
    limit: int = 16,
) -> dict[str, Any]:
    """Suggest local tickers/contracts from current Optedge artifacts."""
    query_norm = str(query or "").strip().lower()
    rows: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()

    for alias, (symbol, name) in sorted(COMMON_ALIASES.items()):
        _add_suggestion(
            rows,
            seen,
            symbol,
            f"{symbol} - {name}",
            "alias",
            "built-in aliases",
            query=symbol,
            name=name,
            score=0.25,
        )
        if alias != symbol.lower():
            _add_suggestion(
                rows,
                seen,
                symbol,
                f"{alias.title()} -> {symbol}",
                "alias",
                "built-in aliases",
                query=alias,
                name=name,
                score=0.2,
            )

    for asset_name, spec in OPPORTUNITY_SPECS.items():
        df = _read_parquet(_latest_file(data_dir, spec["pattern"]))
        if df.empty:
            continue
        symbol_col = str(spec["symbol_col"])
        if symbol_col not in df.columns:
            continue
        for _, row in df.head(600).iterrows():
            symbol = row.get(symbol_col)
            status = row.get("trade_status")
            score = _opportunity_score(row)
            if asset_name == "option":
                option_query = _option_query_from_row(row)
                side = str(row.get("side") or "").upper()[:1]
                label = f"{symbol} {side} {row.get('strike', '-')} {row.get('expiry', '-')}"
                _add_suggestion(
                    rows,
                    seen,
                    symbol,
                    label,
                    "option",
                    "latest options",
                    query=option_query,
                    score=score,
                    trade_status=status,
                )
            elif asset_name == "futures":
                name = row.get("name")
                direction = str(row.get("direction") or "").upper()
                contract = str(row.get("contract") or "")
                label = f"{symbol} {direction} {contract}".strip()
                if name:
                    label = f"{label} - {name}"
                _add_suggestion(
                    rows,
                    seen,
                    symbol,
                    label,
                    "futures",
                    "latest futures",
                    query=str(symbol or ""),
                    name=name,
                    score=score,
                    trade_status=status,
                )
            else:
                label = f"{symbol} {asset_name}"
                _add_suggestion(
                    rows,
                    seen,
                    symbol,
                    label,
                    asset_name,
                    f"latest {asset_name}",
                    query=str(symbol or ""),
                    score=score,
                    trade_status=status,
                )

    chain_df = _load_option_chain_shortlist(data_dir)
    if not chain_df.empty:
        for _, row in chain_df.head(800).iterrows():
            symbol = row.get("ticker")
            option_query = _option_query_from_row(row)
            side = str(row.get("side") or "").upper()[:1]
            grade = str(row.get("contract_grade") or "").strip().upper()
            readiness = row.get("readiness_score")
            label_bits = [
                str(symbol or "").strip().upper(),
                side,
                str(row.get("strike", "-")),
                str(row.get("expiry", "-")),
            ]
            label = " ".join(part for part in label_bits if part)
            details = []
            if grade:
                details.append(f"grade {grade}")
            if readiness not in (None, ""):
                details.append(f"ready {readiness}")
            if details:
                label = f"{label} ({', '.join(details)})"
            _add_suggestion(
                rows,
                seen,
                symbol,
                label,
                "chain_option",
                "saved option-chain shortlist",
                query=option_query,
                score=_opportunity_score(row),
                trade_status=row.get("trade_status") or row.get("readiness_label"),
            )

    for asset_name, filename in POSITION_FILES.items():
        raw = _read_json(data_dir / filename)
        if not isinstance(raw, list):
            continue
        for item in raw[:800]:
            if not isinstance(item, dict):
                continue
            normalized = _normalize_position(item, asset_name)
            symbol = normalized.get("ticker_or_symbol")
            label = normalized.get("position_label") or str(symbol or "")
            lookup_query = (
                _option_query_from_row(item) if asset_name == "option" else str(symbol or "")
            )
            _add_suggestion(
                rows,
                seen,
                symbol,
                label,
                f"open_{asset_name}",
                "open positions",
                query=lookup_query or str(symbol or ""),
                score=0.5,
                trade_status=normalized.get("trade_status"),
            )

    _add_broker_snapshot_suggestions(rows, seen, data_dir)

    for item in load_watchlist(data_dir).get("entries", []):
        _add_suggestion(
            rows,
            seen,
            item.get("symbol"),
            str(item.get("query") or item.get("symbol") or ""),
            "watchlist",
            "research watchlist",
            query=str(item.get("query") or item.get("symbol") or ""),
            name=item.get("name"),
            score=0.75,
        )

    if len(query_norm) >= 2:
        for item in sec_company_search(query, limit=limit, fetch_if_stale=False):
            _add_suggestion(
                rows,
                seen,
                item.get("symbol"),
                f"{item.get('symbol')} - {item.get('name') or 'SEC company'}",
                "sec",
                "SEC company tickers",
                query=str(item.get("symbol") or ""),
                name=item.get("name"),
                score=item.get("score"),
            )
        for item in nasdaq_symbol_search(query, limit=limit, fetch_if_stale=False):
            type_label = str(item.get("type") or "symbol").lower()
            _add_suggestion(
                rows,
                seen,
                item.get("symbol"),
                f"{item.get('symbol')} - {item.get('name') or 'Nasdaq symbol'}",
                "nasdaq",
                "Nasdaq Trader symbol directory",
                query=str(item.get("symbol") or ""),
                name=item.get("name"),
                score=item.get("score"),
                trade_status=type_label,
            )

    if query_norm:
        rows = [row for row in rows if query_norm in _suggestion_text(row)]

    def sort_key(row: dict[str, Any]) -> tuple[int, int, float, str]:
        text = _suggestion_text(row)
        symbol = str(row.get("symbol") or "").lower()
        prefix = (
            1
            if query_norm and (symbol.startswith(query_norm) or text.startswith(query_norm))
            else 0
        )
        exact = (
            1
            if query_norm
            and (symbol == query_norm or str(row.get("query") or "").lower() == query_norm)
            else 0
        )
        return (exact, prefix, _float_value(row.get("score")), str(row.get("symbol") or ""))

    rows = sorted(rows, key=sort_key, reverse=True)[:limit]
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "query": query,
        "count": len(rows),
        "rows": rows,
        "notes": [
            "Suggestions are built from local scan snapshots, saved chain shortlists, open positions, broker snapshots, watchlist entries, built-in aliases, SEC tickers, and Nasdaq Trader's free symbol directory.",
            "Selecting a suggestion only fills or runs local research; it does not place trades.",
        ],
    }


def _records_from_frame(df: pd.DataFrame, limit: int = 100) -> list[dict[str, Any]]:
    if df is None or df.empty:
        return []
    records: list[dict[str, Any]] = []
    for _, row in df.head(limit).iterrows():
        records.append({str(k): _clean_value(v) for k, v in row.to_dict().items()})
    return records


def _split_reason_values(value: Any) -> list[str]:
    if value is None:
        return []
    if isinstance(value, list):
        out: list[str] = []
        for item in value:
            out.extend(_split_reason_values(item))
        return out
    text = str(value).strip()
    if not text or text.lower() in {"nan", "none", "null"}:
        return []
    return [part.strip() for part in text.split(";") if part.strip()]


def _reason_counts_from_frame(df: pd.DataFrame, column: str = "reason_excluded") -> dict[str, int]:
    if df is None or df.empty or column not in df.columns:
        return {}
    counts: dict[str, int] = {}
    for value in df[column].tolist():
        for reason in _split_reason_values(value):
            counts[reason] = counts.get(reason, 0) + 1
    return dict(sorted(counts.items(), key=lambda item: (-item[1], item[0])))


def _top_reason_rows(reason_counts: dict[str, int], limit: int = 6) -> list[dict[str, Any]]:
    return [
        {"reason": reason, "count": count}
        for reason, count in list(reason_counts.items())[: max(1, int(limit or 6))]
    ]


def build_paper_candidates(
    data_dir: Path = DATA_DIR,
    max_new: int = 5,
    max_open: int = 30,
    include_watch: bool = False,
    allow_zero_size_placeholder: bool = False,
    asset: str = "all",
    dry_run: bool = False,
    write: bool = False,
    query: str = "",
) -> dict[str, Any]:
    """Build or write the compact external paper tracking candidate list."""
    df = build_external_orders(
        data_dir=data_dir,
        max_new=max_new,
        max_open=max_open,
        include_watch=include_watch,
        allow_zero_size_placeholder=allow_zero_size_placeholder,
        asset=asset,
        dry_run=dry_run,
        query=query,
    )
    paths: dict[str, str] = {}
    if write and not dry_run:
        csv_path, json_path = write_paper_outputs(df, data_dir)
        paths = {"csv": str(csv_path), "json": str(json_path)}
    selected_count = 0
    excluded_count = 0
    if not df.empty and "reason_excluded" in df.columns:
        excluded_mask = df["reason_excluded"].astype(str).str.len() > 0
        excluded_count = int(excluded_mask.sum())
        selected_count = int((~excluded_mask).sum())
    else:
        selected_count = int(len(df))
    reason_counts = _reason_counts_from_frame(df)
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "asset": asset,
        "query": query,
        "max_new": max_new,
        "max_open": max_open,
        "include_watch": include_watch,
        "allow_zero_size_placeholder": allow_zero_size_placeholder,
        "dry_run": dry_run,
        "wrote_files": bool(paths),
        "paths": paths,
        "count": int(len(df)),
        "selected_count": selected_count,
        "excluded_count": excluded_count,
        "rejection_reason_counts": reason_counts,
        "top_rejection_reasons": _top_reason_rows(reason_counts),
        "rows": _records_from_frame(df, limit=150),
        "notes": [
            "External paper candidates are a small filtered subset, not every internal signal.",
            "Use the filter box to preview candidates for one ticker, futures symbol, or option contract.",
            "This creates manual paper-tracking files only; no trades are placed.",
            "Dry-run review includes rejected rows and exclusion reasons.",
        ],
    }


def build_robinhood_agentic_queue_report(
    data_dir: Path = DATA_DIR,
    account_budget: float = 500.0,
    max_candidates: int = 5,
    max_orders: int = 2,
    min_dte: int = MIN_SWING_OPTION_DTE,
    min_confidence: float = 55.0,
    query: str = "",
    refresh_chain: bool = False,
    chain_preset: str = "auto",
    chain_symbols_limit: int = 6,
    chain_contracts_per_symbol: int = 4,
    execution_profile: str = SWING_EXECUTION_PROFILE.name,
    write: bool = False,
) -> dict[str, Any]:
    """Build or write the 90d+ option candidate queue for agent review."""
    queue = build_robinhood_queue(
        data_dir=data_dir,
        account_budget=account_budget,
        max_candidates=max_candidates,
        max_orders=max_orders,
        min_dte=min_dte,
        min_confidence=min_confidence,
        query=query,
        refresh_chain=refresh_chain,
        chain_preset=chain_preset,
        chain_symbols_limit=chain_symbols_limit,
        chain_contracts_per_symbol=chain_contracts_per_symbol,
        execution_profile=execution_profile,
    )
    try:
        cycle_packet = build_agentic_cycle_packet(queue, data_dir)
    except Exception as exc:
        cycle_packet = {
            "entry_gate": {
                "status": "unknown",
                "label": "Entry gate unavailable",
                "detail": str(exc)[:160],
                "new_entries_allowed_after_live_checks": False,
                "approval_required": True,
                "blockers": [str(exc)[:160]],
                "warnings": [],
            },
            "queue_summary": {},
            "entry_candidates": [],
            "review_only_entry_candidates": [],
        }
    paths: dict[str, str] = {}
    if write:
        queue_path, prompt_path = write_robinhood_queue_outputs(queue, data_dir)
        paths = {
            "queue": str(queue_path),
            "prompt": str(prompt_path),
            "cycle": str(data_dir / "robinhood_agentic_cycle.json"),
            "cycle_prompt": str(data_dir / "robinhood_agentic_cycle_prompt.md"),
        }
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "wrote_files": bool(paths),
        "paths": paths,
        "status": queue.get("status"),
        "execution_profile": queue.get("execution_profile"),
        "strategy_evidence_lane": queue.get("strategy_evidence_lane"),
        "account_budget": queue.get("account_budget"),
        "max_candidates": queue.get("max_candidates"),
        "max_orders_to_submit": queue.get("max_orders_to_submit"),
        "max_total_premium": queue.get("max_total_premium"),
        "max_premium_per_order": queue.get("max_premium_per_order"),
        "min_dte": queue.get("min_dte"),
        "min_confidence": queue.get("min_confidence"),
        "estimated_total_candidate_premium": queue.get("estimated_total_candidate_premium"),
        "chain_refresh": queue.get("chain_refresh") or {"attempted": False},
        "entry_gate": cycle_packet.get("entry_gate") or {},
        "gated_ready_to_submit_count": (
            (cycle_packet.get("queue_summary") or {}).get("gated_ready_to_submit_count")
        ),
        "review_only_entry_candidate_count": len(
            cycle_packet.get("review_only_entry_candidates") or []
        ),
        "decision_log": cycle_packet.get("decision_log") or {},
        "readiness": queue.get("readiness") or {},
        "diagnostics": queue.get("diagnostics") or {},
        "sec_offering_risks": queue.get("sec_offering_risks") or {},
        "rejection_reason_counts": queue.get("rejection_reason_counts") or {},
        "top_rejection_reasons": queue.get("top_rejection_reasons") or [],
        "candidate_count": len(queue.get("orders") or []),
        "rejected_count": len(queue.get("rejected") or []),
        "orders": queue.get("orders") or [],
        "rejected": (queue.get("rejected") or [])[:25],
        "notes": [
            "This is an explicit 3m+ swing or true-LEAPS evidence queue for external/manual review.",
            "It does not place trades or store broker credentials.",
            "The agent should verify live quotes, spread, positions, buying power, and current news.",
        ],
    }


def _agentic_option_side(value: Any) -> str:
    text = str(value or "").strip().lower()
    if text in {"c", "call", "calls"}:
        return "call"
    if text in {"p", "put", "puts"}:
        return "put"
    return text


def _agentic_expiry_key(value: Any) -> str:
    parsed = _parse_iso_utc(value)
    if parsed is not None:
        return parsed.date().isoformat()
    text = str(value or "").strip()
    return text[:10] if len(text) >= 10 else text


def _agentic_strike_key(value: Any) -> str:
    strike = _float_value(value, default=math.nan)
    if math.isfinite(strike):
        return f"{strike:g}"
    return str(value or "").strip()


def _agentic_contract_key(row: dict[str, Any]) -> str:
    symbol = (
        str(row.get("symbol") or row.get("ticker") or row.get("ticker_or_symbol") or "")
        .strip()
        .upper()
    )
    side = _agentic_option_side(
        row.get("option_side") or row.get("option_type") or row.get("right") or row.get("side")
    )
    expiry = _agentic_expiry_key(row.get("expiry") or row.get("expiration_date"))
    strike = _agentic_strike_key(row.get("strike") or row.get("strike_price"))
    return "|".join([symbol, side, expiry, strike])


def _agentic_direction_key(row: dict[str, Any]) -> str:
    symbol = (
        str(row.get("symbol") or row.get("ticker") or row.get("ticker_or_symbol") or "")
        .strip()
        .upper()
    )
    option_side = _agentic_option_side(
        row.get("option_side") or row.get("option_type") or row.get("right")
    )
    if option_side not in {"call", "put"}:
        candidate = _agentic_option_side(row.get("side"))
        option_side = candidate if candidate in {"call", "put"} else ""
    direction = str(row.get("direction") or row.get("position_type") or "").strip().lower()
    execution_side = str(row.get("side") or "").strip().lower()
    position_effect = str(row.get("position_effect") or "").strip().lower()
    if option_side:
        if "short" in direction:
            exposure = f"short_{option_side}"
        elif "long" in direction:
            exposure = f"long_{option_side}"
        elif position_effect == "open" and execution_side in {"buy", "sell"}:
            exposure = f"{'long' if execution_side == 'buy' else 'short'}_{option_side}"
        elif position_effect == "close" and execution_side in {"buy", "sell"}:
            exposure = f"{'short' if execution_side == 'buy' else 'long'}_{option_side}"
        else:
            # Optedge's supported candidate surface is long calls/puts; absent
            # contrary evidence, an option candidate/legacy position is long.
            exposure = f"long_{option_side}"
    else:
        exposure = direction
    return "|".join([symbol, exposure])


def _agentic_open_option_keys(open_positions: list[dict[str, Any]]) -> tuple[set[str], set[str]]:
    contract_keys: set[str] = set()
    direction_keys: set[str] = set()
    for raw in open_positions:
        if not isinstance(raw, dict):
            continue
        row = {
            "symbol": raw.get("symbol") or raw.get("ticker"),
            "option_side": raw.get("option_side") or raw.get("side"),
            "strike": raw.get("strike"),
            "expiry": raw.get("expiry"),
            "direction": raw.get("direction")
            or (f"long_{str(raw.get('option_side') or raw.get('side') or '').strip().lower()}"),
        }
        contract_key = _agentic_contract_key(row)
        direction_key = _agentic_direction_key(row)
        if contract_key.strip("|"):
            contract_keys.add(contract_key)
        if direction_key.strip("|"):
            direction_keys.add(direction_key)
    return contract_keys, direction_keys


def _agentic_ticket_preflight(
    ticket: dict[str, Any],
    *,
    contract_key: str,
    direction_key: str,
    ticket_freshness: str,
    queue_freshness: str,
    cycle_freshness: str,
    ticket_packet_freshness: str,
    entry_gate: dict[str, Any],
    blockers: list[str],
    paper_contract_keys: set[str],
    optedge_contract_keys: set[str],
    optedge_direction_keys: set[str],
    broker_working_contract_keys: set[str],
    account_readiness_rows: list[dict[str, Any]],
) -> dict[str, Any]:
    checks: list[dict[str, Any]] = []

    def add(level: str, label: str, detail: str) -> None:
        checks.append({"level": level, "label": label, "detail": detail})

    freshness_values = (queue_freshness, cycle_freshness, ticket_packet_freshness, ticket_freshness)
    if "missing" in freshness_values:
        add(
            "block",
            "Fresh packet",
            "Queue, cycle, and ticket timestamps must all be present before live review.",
        )
    elif "stale" in freshness_values:
        add(
            "block",
            "Fresh packet",
            "Queue, cycle, and ticket files must be refreshed before live review.",
        )
    elif (
        queue_freshness == "aging"
        or cycle_freshness == "aging"
        or ticket_packet_freshness == "aging"
        or ticket_freshness == "aging"
    ):
        add("warn", "Fresh packet", "Packet is aging; refresh if market conditions changed.")
    else:
        add("pass", "Fresh packet", "Queue, cycle, and ticket timestamps are fresh.")

    gate_status = str(entry_gate.get("status") or "").strip().lower()
    if gate_status == "blocked" or blockers:
        add(
            "block",
            "Entry gate",
            "Fresh entries are blocked by validation, guardrail, stale-data, or kill-switch checks.",
        )
    elif entry_gate.get("new_entries_allowed_after_live_checks") is True:
        add("pass", "Entry gate", "Local gate allows review after live broker/quote checks.")
    else:
        add("warn", "Entry gate", "Entry gate is not explicitly open; treat this as review-only.")

    missing = [
        name
        for name in ("symbol", "option_side", "strike", "expiry", "limit_price", "quantity")
        if ticket.get(name) in (None, "")
    ]
    if missing:
        add("block", "Contract fields", f"Missing required field(s): {', '.join(missing)}.")
    else:
        add(
            "pass",
            "Contract fields",
            "Exact symbol, side, strike, expiry, limit, and quantity are present.",
        )

    quantity = _float_value(ticket.get("quantity"), default=0.0)
    limit_price = _float_value(ticket.get("limit_price"), default=0.0)
    premium = _float_value(
        ticket.get("estimated_premium_dollars"),
        default=quantity * limit_price * 100.0 if quantity > 0 and limit_price > 0 else 0.0,
    )
    if quantity <= 0:
        add("block", "Order size", "Quantity must be positive.")
    elif premium <= 0:
        add("block", "Order size", "Estimated premium could not be calculated.")
    elif premium > 250:
        add(
            "warn",
            "Order size",
            f"Estimated premium ${premium:.0f} is above the usual $500-account half-budget cap.",
        )
    else:
        add("pass", "Order size", f"Estimated premium ${premium:.0f} fits the small-account cap.")

    funded_option_accounts = [
        row
        for row in account_readiness_rows
        if isinstance(row, dict)
        and row.get("agentic_allowed") is True
        and row.get("options_ready") is True
        and row.get("funded") is True
    ]
    buying_power_values = [
        _float_value(row.get("buying_power"), default=math.nan) for row in funded_option_accounts
    ]
    buying_power_values = [value for value in buying_power_values if math.isfinite(value)]
    if not funded_option_accounts:
        add(
            "block",
            "Account capacity",
            "No funded agentic-accessible options account is available in the broker snapshot.",
        )
    elif not buying_power_values:
        add(
            "block",
            "Account capacity",
            "Broker buying power is missing for the eligible options account.",
        )
    elif premium > max(buying_power_values) + 0.01:
        add(
            "block",
            "Account capacity",
            f"Estimated ${premium:.0f} debit exceeds every eligible account's snapshot buying power.",
        )
    else:
        add(
            "pass",
            "Account capacity",
            "At least one eligible account has enough snapshot buying power; refresh it live before review.",
        )

    expiry_dt = _parse_iso_utc(ticket.get("expiry"))
    dte = None
    if expiry_dt is not None:
        dte = (expiry_dt.date() - datetime.now(UTC).date()).days
    if dte is None:
        add("block", "Swing DTE", "Expiry could not be parsed.")
    elif dte < MIN_SWING_OPTION_DTE:
        add("block", "Swing DTE", f"{dte} DTE is below the {MIN_SWING_OPTION_DTE} DTE swing floor.")
    else:
        add("pass", "Swing DTE", f"{dte} DTE meets the {MIN_SWING_OPTION_DTE}+ DTE swing floor.")

    if contract_key in paper_contract_keys:
        add("warn", "Paper duplicate", "This exact contract is already tracked in local paper.")
    else:
        add("pass", "Paper duplicate", "No matching local paper contract is open.")
    if contract_key in optedge_contract_keys or direction_key in optedge_direction_keys:
        add(
            "warn",
            "Optedge duplicate",
            "Optedge already has matching contract or same-direction exposure.",
        )
    else:
        add("pass", "Optedge duplicate", "No matching local Optedge option exposure found.")
    if contract_key in broker_working_contract_keys:
        add(
            "block",
            "Working broker order",
            "Robinhood already has a working order for this exact contract.",
        )
    else:
        add(
            "pass",
            "Working broker order",
            "No matching working broker order appears in the fresh snapshot.",
        )

    if ticket.get("confirmation_required", True):
        add(
            "pass",
            "Confirmation",
            "Ticket is confirmation-required and has not been broker-submitted by this cockpit.",
        )
    else:
        add("block", "Confirmation", "Ticket is not marked confirmation-required.")

    if ticket.get("live_submit_allowed_by_this_script"):
        add(
            "block",
            "Execution mode",
            "Local ticket claims script live-submit is allowed; keep cockpit approval-gated.",
        )
    else:
        add("pass", "Execution mode", "Local script is not allowed to place broker orders.")

    mcp_plan = ticket.get("robinhood_mcp_review_plan")
    mcp_plan = mcp_plan if isinstance(mcp_plan, dict) else {}
    if not mcp_plan:
        add(
            "block",
            "MCP review plan",
            "Ticket is missing the structured Robinhood MCP review plan; rebuild tickets before live review.",
        )
    elif mcp_plan.get("review_tool") != "review_option_order":
        add(
            "block",
            "MCP review plan",
            "Ticket does not require review_option_order before broker placement.",
        )
    elif not mcp_plan.get("requires_explicit_user_confirmation_before_place"):
        add(
            "block",
            "MCP review plan",
            "Ticket MCP plan does not require explicit user confirmation before placement.",
        )
    elif mcp_plan.get("script_submits_live_orders"):
        add(
            "block",
            "MCP review plan",
            "Ticket MCP plan allows script-submitted live orders; keep workflow approval-gated.",
        )
    else:
        expected_plan = robinhood_mcp_option_review_plan(ticket)
        actual_lookup = (
            mcp_plan.get("contract_lookup")
            if isinstance(mcp_plan.get("contract_lookup"), dict)
            else {}
        )
        expected_lookup = (
            expected_plan.get("contract_lookup")
            if isinstance(expected_plan.get("contract_lookup"), dict)
            else {}
        )
        actual_args = (
            mcp_plan.get("review_arguments_template")
            if isinstance(mcp_plan.get("review_arguments_template"), dict)
            else {}
        )
        expected_args = (
            expected_plan.get("review_arguments_template")
            if isinstance(expected_plan.get("review_arguments_template"), dict)
            else {}
        )
        actual_leg = next(
            (row for row in (actual_args.get("legs") or []) if isinstance(row, dict)), {}
        )
        expected_leg = next(
            (row for row in (expected_args.get("legs") or []) if isinstance(row, dict)), {}
        )
        comparisons = {
            "place tool": (
                mcp_plan.get("place_tool_after_explicit_confirmation"),
                expected_plan.get("place_tool_after_explicit_confirmation"),
            ),
            "lookup symbol": (
                actual_lookup.get("chain_symbol"),
                expected_lookup.get("chain_symbol"),
            ),
            "lookup expiry": (
                actual_lookup.get("expiration_date"),
                expected_lookup.get("expiration_date"),
            ),
            "lookup strike": (
                _agentic_strike_key(actual_lookup.get("strike_price")),
                _agentic_strike_key(expected_lookup.get("strike_price")),
            ),
            "lookup type": (
                _agentic_option_side(actual_lookup.get("type")),
                _agentic_option_side(expected_lookup.get("type")),
            ),
            "review symbol": (actual_args.get("chain_symbol"), expected_args.get("chain_symbol")),
            "review underlying type": (
                actual_args.get("underlying_type"),
                expected_args.get("underlying_type"),
            ),
            "review quantity": (
                str(actual_args.get("quantity") or ""),
                str(expected_args.get("quantity") or ""),
            ),
            "review price": (
                _float_value(actual_args.get("price"), default=math.nan),
                _float_value(expected_args.get("price"), default=math.nan),
            ),
            "review type": (actual_args.get("type"), expected_args.get("type")),
            "review time in force": (
                actual_args.get("time_in_force"),
                expected_args.get("time_in_force"),
            ),
            "review market hours": (
                actual_args.get("market_hours"),
                expected_args.get("market_hours"),
            ),
            "account placeholder": (
                actual_args.get("account_number"),
                expected_args.get("account_number"),
            ),
            "leg option id placeholder": (
                actual_leg.get("option_id"),
                expected_leg.get("option_id"),
            ),
            "leg side": (actual_leg.get("side"), expected_leg.get("side")),
            "leg position effect": (
                actual_leg.get("position_effect"),
                expected_leg.get("position_effect"),
            ),
            "leg ratio": (
                str(actual_leg.get("ratio_quantity") or ""),
                str(expected_leg.get("ratio_quantity") or ""),
            ),
        }
        mismatches = []
        if len(actual_args.get("legs") or []) != 1:
            mismatches.append("leg count")
        for label, (actual_value, expected_value) in comparisons.items():
            if isinstance(actual_value, float) or isinstance(expected_value, float):
                if not (
                    isinstance(actual_value, (int, float))
                    and isinstance(expected_value, (int, float))
                    and math.isfinite(float(actual_value))
                    and math.isfinite(float(expected_value))
                    and abs(float(actual_value) - float(expected_value)) <= 0.011
                ):
                    mismatches.append(label)
            elif str(actual_value or "") != str(expected_value or ""):
                mismatches.append(label)
        if mismatches:
            add(
                "block",
                "MCP plan integrity",
                f"Embedded review plan disagrees with the ticket: {', '.join(mismatches)}.",
            )
        else:
            add(
                "pass",
                "MCP review plan",
                "Ticket fields reconcile to review_option_order, explicit confirmation, and approval-gated placement.",
            )

    block_count = sum(1 for row in checks if row["level"] == "block")
    warn_count = sum(1 for row in checks if row["level"] == "warn")
    status = "blocked" if block_count else "warn" if warn_count else "pass"
    return {
        "status": status,
        "block_count": block_count,
        "warn_count": warn_count,
        "checks": checks,
    }


def _agentic_open_option_marks(open_positions: list[dict[str, Any]]) -> dict[str, dict[str, Any]]:
    marks: dict[str, dict[str, Any]] = {}
    for raw in open_positions:
        if not isinstance(raw, dict):
            continue
        row = {
            "symbol": raw.get("symbol") or raw.get("ticker"),
            "option_side": raw.get("option_side") or raw.get("side"),
            "strike": raw.get("strike"),
            "expiry": raw.get("expiry"),
            "direction": raw.get("direction")
            or (f"long_{str(raw.get('option_side') or raw.get('side') or '').strip().lower()}"),
        }
        contract_key = _agentic_contract_key(row)
        if not contract_key.strip("|"):
            continue
        current_price = _float_value(
            raw.get("current_price", raw.get("current_mid", raw.get("last_price"))),
            default=math.nan,
        )
        marks[contract_key] = {
            "contract_key": contract_key,
            "current_price": current_price if math.isfinite(current_price) else None,
            "source": _clean_value(
                raw.get("last_reprice_source") or raw.get("source") or "optedge_open_positions"
            ),
            "latest_exit_pressure": _clean_value(raw.get("latest_exit_pressure")),
            "latest_exit_action": _clean_value(raw.get("latest_exit_action")),
            "reprice_failed_count": int(_float_value(raw.get("reprice_failed_count"), default=0.0)),
            "trade_status": _clean_value(raw.get("trade_status")),
            "research_guard_status": _clean_value(raw.get("research_guard_status")),
        }
    return marks


def _agentic_paper_book(
    active_paper: list[dict[str, Any]],
    open_positions: list[dict[str, Any]],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    marks = _agentic_open_option_marks(open_positions)
    rows: list[dict[str, Any]] = []
    total_entry = 0.0
    total_value = 0.0
    total_pnl = 0.0
    priced_count = 0
    needs_quote_count = 0
    review_count = 0
    pnl_values: list[float] = []
    now = datetime.now(UTC)

    for raw in active_paper[-50:]:
        if not isinstance(raw, dict):
            continue
        contract_key = _agentic_contract_key(raw)
        mark = marks.get(contract_key, {})
        quantity = max(0, int(_float_value(raw.get("quantity"), default=0.0)))
        entry_price = _float_value(
            raw.get("entry_price") or raw.get("paper_limit_price"), default=math.nan
        )
        current_price = _float_value(mark.get("current_price"), default=math.nan)
        entry_premium = (
            entry_price * quantity * 100.0
            if math.isfinite(entry_price) and quantity > 0
            else math.nan
        )
        current_value = (
            current_price * quantity * 100.0
            if math.isfinite(current_price) and quantity > 0
            else math.nan
        )
        pnl_pct = (
            ((current_price - entry_price) / entry_price)
            if (math.isfinite(entry_price) and entry_price > 0 and math.isfinite(current_price))
            else math.nan
        )
        pnl_dollars = (
            (current_value - entry_premium)
            if math.isfinite(current_value) and math.isfinite(entry_premium)
            else math.nan
        )
        stop_price = _float_value(raw.get("stop_price_reference"), default=math.nan)
        target_price = _float_value(raw.get("target_price_reference"), default=math.nan)
        opened_at = _parse_iso_utc(raw.get("opened_at"))
        age_days = (now - opened_at).total_seconds() / 86400.0 if opened_at else None
        expiry_dt = _parse_iso_utc(raw.get("expiry"))
        dte = (expiry_dt.date() - now.date()).days if expiry_dt else None

        if math.isfinite(entry_premium):
            total_entry += entry_premium
        if math.isfinite(current_value):
            total_value += current_value
        if math.isfinite(pnl_dollars):
            total_pnl += pnl_dollars
        if math.isfinite(pnl_pct):
            pnl_values.append(pnl_pct)

        if math.isfinite(current_price):
            priced_count += 1
            if math.isfinite(stop_price) and current_price <= stop_price:
                review_action = "stop_review"
                review_reason = "current mark is at or below paper stop reference"
            elif math.isfinite(target_price) and current_price >= target_price:
                review_action = "target_review"
                review_reason = "current mark is at or above paper target reference"
            elif dte is not None and dte < 14:
                review_action = "expiry_review"
                review_reason = "less than 14 DTE remains"
            elif mark.get("latest_exit_action") in {"watch", "tighten_stop", "close_early"}:
                review_action = "exit_review"
                review_reason = f"Optedge lifecycle action is {mark.get('latest_exit_action')}"
            else:
                review_action = "hold_review"
                review_reason = "priced and no paper stop/target trigger"
        else:
            needs_quote_count += 1
            review_action = "refresh_quote"
            review_reason = "no matching current Optedge option mark found"
        if review_action != "hold_review":
            review_count += 1

        rows.append(
            {
                "symbol": _clean_value(raw.get("symbol") or raw.get("ticker_or_symbol")),
                "contract": _clean_value(raw.get("contract")),
                "status": _clean_value(raw.get("status")),
                "option_side": _clean_value(raw.get("option_side")),
                "strike": _clean_value(raw.get("strike")),
                "expiry": _clean_value(raw.get("expiry")),
                "dte": _clean_value(dte),
                "quantity": quantity,
                "entry_price": _clean_value(entry_price if math.isfinite(entry_price) else None),
                "current_price": _clean_value(
                    current_price if math.isfinite(current_price) else None
                ),
                "pnl_pct": _clean_value(pnl_pct if math.isfinite(pnl_pct) else None),
                "pnl_dollars": _clean_value(pnl_dollars if math.isfinite(pnl_dollars) else None),
                "entry_premium_dollars": _clean_value(
                    entry_premium if math.isfinite(entry_premium) else None
                ),
                "current_value_dollars": _clean_value(
                    current_value if math.isfinite(current_value) else None
                ),
                "stop_price_reference": _clean_value(raw.get("stop_price_reference")),
                "target_price_reference": _clean_value(raw.get("target_price_reference")),
                "age_days": _clean_value(round(age_days, 2) if age_days is not None else None),
                "mark_source": _clean_value(mark.get("source")),
                "latest_exit_action": _clean_value(mark.get("latest_exit_action")),
                "latest_exit_pressure": _clean_value(mark.get("latest_exit_pressure")),
                "reprice_failed_count": _clean_value(mark.get("reprice_failed_count")),
                "review_action": review_action,
                "review_reason": review_reason,
                "paper_override_validation_gate": bool(raw.get("paper_override_validation_gate")),
                "swing_fit_label": _clean_value(raw.get("swing_fit_label")),
            }
        )

    summary = {
        "open_count": len(rows),
        "priced_count": priced_count,
        "needs_quote_count": needs_quote_count,
        "review_count": review_count,
        "entry_premium_dollars": _clean_value(round(total_entry, 2)),
        "current_value_dollars": _clean_value(round(total_value, 2) if priced_count else None),
        "unrealized_pnl_dollars": _clean_value(round(total_pnl, 2) if priced_count else None),
        "avg_pnl_pct": _clean_value(sum(pnl_values) / len(pnl_values) if pnl_values else None),
        "worst_pnl_pct": _clean_value(min(pnl_values) if pnl_values else None),
        "best_pnl_pct": _clean_value(max(pnl_values) if pnl_values else None),
    }
    return rows[-12:], summary


def _broker_snapshot_option_rows(
    snapshot: dict[str, Any],
) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    accounts = snapshot.get("accounts") if isinstance(snapshot.get("accounts"), list) else []
    direct_positions = (
        snapshot.get("option_positions")
        or snapshot.get("options_positions")
        or snapshot.get("positions")
        or []
    )
    rows: list[dict[str, Any]] = []
    if isinstance(direct_positions, list):
        for raw in direct_positions:
            state = (
                str(raw.get("state") or raw.get("status") or "open").strip().lower()
                if isinstance(raw, dict)
                else ""
            )
            quantity = (
                _float_value(
                    raw.get("signed_quantity", raw.get("quantity") or raw.get("contracts")),
                    default=0.0,
                )
                if isinstance(raw, dict)
                else 0.0
            )
            if (
                isinstance(raw, dict)
                and abs(quantity) > 0
                and state not in {"closed", "expired", "cancelled"}
            ):
                rows.append(dict(raw))
    for account_index, account in enumerate(accounts, start=1):
        if not isinstance(account, dict):
            continue
        account_positions = (
            account.get("option_positions")
            or account.get("options_positions")
            or account.get("positions")
            or []
        )
        if not isinstance(account_positions, list):
            continue
        account_label = (
            account.get("nickname")
            or account.get("label")
            or account.get("brokerage_account_type")
            or account.get("type")
            or "account"
        )
        for raw in account_positions:
            if not isinstance(raw, dict):
                continue
            state = str(raw.get("state") or raw.get("status") or "open").strip().lower()
            quantity = _float_value(
                raw.get("signed_quantity", raw.get("quantity") or raw.get("contracts")),
                default=0.0,
            )
            if abs(quantity) <= 0 or state in {"closed", "expired", "cancelled"}:
                continue
            row = dict(raw)
            row.setdefault("account_label", account_label)
            row.setdefault(
                "account_key",
                account.get("account_key") or f"snapshot_account_{account_index:03d}",
            )
            row.setdefault("account_mask", account.get("account_mask"))
            row.setdefault("account_agentic_allowed", account.get("agentic_allowed"))
            row.setdefault("account_option_level", account.get("option_level"))
            rows.append(row)
    deduped: list[dict[str, Any]] = []
    seen: set[tuple[Any, ...]] = set()
    for raw in rows:
        symbol = (
            str(
                raw.get("symbol")
                or raw.get("chain_symbol")
                or raw.get("ticker")
                or raw.get("ticker_or_symbol")
                or ""
            )
            .strip()
            .upper()
        )
        key = (
            raw.get("account_key")
            or raw.get("account_mask")
            or raw.get("account_label")
            or raw.get("account"),
            symbol,
            _agentic_option_side(
                raw.get("option_side")
                or raw.get("option_type")
                or raw.get("side")
                or raw.get("right")
            ),
            _agentic_expiry_key(raw.get("expiry") or raw.get("expiration_date")),
            _agentic_strike_key(raw.get("strike") or raw.get("strike_price")),
            str(raw.get("position_type") or raw.get("type") or "").strip().lower(),
            _clean_value(
                _float_value(
                    raw.get("signed_quantity", raw.get("quantity") or raw.get("contracts")),
                    default=0.0,
                )
            ),
        )
        if key in seen:
            continue
        seen.add(key)
        deduped.append(raw)
    return deduped, accounts


def _broker_option_record(raw: dict[str, Any]) -> dict[str, Any]:
    symbol = (
        str(
            raw.get("symbol")
            or raw.get("chain_symbol")
            or raw.get("ticker")
            or raw.get("ticker_or_symbol")
            or ""
        )
        .strip()
        .upper()
    )
    side = _agentic_option_side(
        raw.get("option_side") or raw.get("option_type") or raw.get("side") or raw.get("right")
    )
    expiry = _agentic_expiry_key(raw.get("expiry") or raw.get("expiration_date"))
    strike = _agentic_strike_key(raw.get("strike") or raw.get("strike_price"))
    quantity = _float_value(raw.get("quantity") or raw.get("contracts"), default=0.0)
    position_type = str(raw.get("position_type") or raw.get("type") or "").strip().lower()
    if position_type not in {"long", "short"}:
        direction_key = _agentic_direction_key(raw).split("|", 1)[-1]
        position_type = "short" if direction_key.startswith("short_") else "long"
    signed_quantity = _float_value(raw.get("signed_quantity"), default=math.nan)
    if not math.isfinite(signed_quantity):
        signed_quantity = -abs(quantity) if position_type == "short" else abs(quantity)
    row = {
        "symbol": symbol,
        "option_side": side,
        "strike": strike,
        "expiry": expiry,
        "quantity": _clean_value(quantity),
        "signed_quantity": _clean_value(signed_quantity),
        "position_type": position_type,
        "average_price": _clean_value(
            raw.get("average_price") or raw.get("avg_price") or raw.get("entry_price")
        ),
        "current_price": _clean_value(
            raw.get("current_price") or raw.get("mark_price") or raw.get("last_price")
        ),
        "account": _clean_value(
            raw.get("account_label") or raw.get("account") or raw.get("nickname")
        ),
        "account_key": _clean_value(raw.get("account_key")),
        "account_mask": _clean_value(raw.get("account_mask")),
        "agentic_allowed": _clean_value(
            raw.get("account_agentic_allowed") or raw.get("agentic_allowed")
        ),
        "option_level": _clean_value(raw.get("account_option_level") or raw.get("option_level")),
    }
    missing = [
        label
        for label, value in (
            ("symbol", symbol),
            ("side", side),
            ("strike", strike),
            ("expiry", expiry),
        )
        if value in ("", None)
    ]
    row["contract_key"] = _agentic_contract_key(row)
    row["missing_fields"] = missing
    row["contract"] = (
        f"{symbol} {expiry} {side.upper()} {strike}"
        if not missing
        else raw.get("contract") or raw.get("local_symbol") or symbol
    )
    return {k: _clean_value(v) for k, v in row.items()}


def _agentic_local_option_record(raw: dict[str, Any], source: str) -> dict[str, Any]:
    symbol = (
        str(raw.get("symbol") or raw.get("ticker") or raw.get("ticker_or_symbol") or "")
        .strip()
        .upper()
    )
    side = _agentic_option_side(raw.get("option_side") or raw.get("side"))
    expiry = _agentic_expiry_key(raw.get("expiry") or raw.get("expiration_date"))
    strike = _agentic_strike_key(raw.get("strike") or raw.get("strike_price"))
    quantity = _float_value(raw.get("quantity") or raw.get("suggested_contracts"), default=0.0)
    position_type = str(raw.get("position_type") or "").strip().lower()
    direction = str(raw.get("direction") or "").strip().lower()
    if position_type not in {"long", "short"}:
        position_type = "short" if "short" in direction or quantity < 0 else "long"
    signed_quantity = -abs(quantity) if position_type == "short" else abs(quantity)
    row = {
        "symbol": symbol,
        "option_side": side,
        "strike": strike,
        "expiry": expiry,
        "quantity": _clean_value(abs(quantity)),
        "signed_quantity": _clean_value(signed_quantity),
        "position_type": position_type,
        "account_key": _clean_value(raw.get("account_key")),
        "entry_price": _clean_value(raw.get("entry_price") or raw.get("paper_limit_price")),
        "current_price": _clean_value(
            raw.get("current_price") or raw.get("current_mid") or raw.get("last_price")
        ),
        "trade_status": _clean_value(raw.get("trade_status") or raw.get("status")),
        "latest_exit_action": _clean_value(raw.get("latest_exit_action")),
        "latest_exit_pressure": _clean_value(raw.get("latest_exit_pressure")),
        "source": source,
    }
    expiry_dt = _parse_iso_utc(expiry)
    row["dte"] = (expiry_dt.date() - datetime.now(UTC).date()).days if expiry_dt else None
    row["contract_key"] = _agentic_contract_key(row)
    row["contract"] = raw.get("contract") or f"{symbol} {expiry} {side.upper()} {strike}"
    return {k: _clean_value(v) for k, v in row.items()}


def _local_option_tracking_scope(raw: dict[str, Any]) -> str:
    """Separate broker-linked lifecycle state from research/paper positions."""
    explicit = (
        str(
            raw.get("tracking_scope")
            or raw.get("position_scope")
            or raw.get("execution_scope")
            or ""
        )
        .strip()
        .lower()
    )
    if explicit in {"broker", "broker_linked", "live", "robinhood", "robinhood_live"}:
        return "broker_linked"
    broker_identity = any(
        str(raw.get(field) or "").strip()
        for field in ("broker_position_id", "broker_order_id", "broker_fill_id")
    )
    if broker_identity and str(raw.get("account_key") or "").strip():
        return "broker_linked"
    return "research_lifecycle"


def _aggregate_option_records(
    records: list[dict[str, Any]],
    *,
    by_account: bool,
) -> list[dict[str, Any]]:
    """Aggregate signed quantity without merging distinct broker accounts."""
    groups: dict[tuple[str, str], dict[str, Any]] = {}
    passthrough: list[dict[str, Any]] = []
    for row in records:
        contract_key = str(row.get("contract_key") or "")
        if not contract_key.strip("|") or row.get("missing_fields"):
            passthrough.append(dict(row))
            continue
        account_key = str(row.get("account_key") or "") if by_account else ""
        key = (account_key, contract_key)
        signed_quantity = _float_value(row.get("signed_quantity"), default=math.nan)
        if not math.isfinite(signed_quantity):
            quantity = _float_value(row.get("quantity"), default=0.0)
            signed_quantity = (
                -abs(quantity) if row.get("position_type") == "short" else abs(quantity)
            )
        position_type = str(row.get("position_type") or "").strip().lower()
        if key not in groups:
            aggregate = dict(row)
            aggregate["signed_quantity"] = signed_quantity
            aggregate["quantity"] = abs(signed_quantity)
            aggregate["position_types"] = [position_type] if position_type else []
            aggregate["aggregate_row_count"] = 1
            groups[key] = aggregate
            continue
        aggregate = groups[key]
        aggregate["signed_quantity"] = (
            _float_value(aggregate.get("signed_quantity"), default=0.0) + signed_quantity
        )
        aggregate["quantity"] = abs(float(aggregate["signed_quantity"]))
        types = set(aggregate.get("position_types") or [])
        if position_type:
            types.add(position_type)
        aggregate["position_types"] = sorted(types)
        aggregate["aggregate_row_count"] = int(aggregate.get("aggregate_row_count") or 1) + 1
    output = list(groups.values()) + passthrough
    for row in output:
        types = list(row.get("position_types") or [])
        if len(types) > 1:
            row["position_type"] = "mixed"
        elif types:
            row["position_type"] = types[0]
        elif _float_value(row.get("signed_quantity"), default=0.0) < 0:
            row["position_type"] = "short"
        else:
            row["position_type"] = str(row.get("position_type") or "long")
    return output


def _account_options_ready(option_level: Any) -> bool:
    return str(option_level or "").strip().lower() in {"option_level_2", "option_level_3"}


def _broker_account_readiness(
    accounts: list[dict[str, Any]],
    *,
    strict_v2_portfolio: bool = False,
) -> dict[str, Any]:
    rows: list[dict[str, Any]] = []
    for account in accounts:
        if not isinstance(account, dict):
            continue
        # Broker permissions are typed attestations.  Do not let truthy strings
        # such as "false" become execution permission.
        agentic_allowed = account.get("agentic_allowed") is True
        state = str(account.get("state") or account.get("status") or "").strip().lower()
        if not state and isinstance(account.get("deactivated"), bool):
            state = "deactivated" if account.get("deactivated") else "active"
        active = state in {"active", "enabled", "open"}
        option_level = str(account.get("option_level") or "").strip()
        options_ready = _account_options_ready(option_level)
        portfolio = account.get("portfolio") if isinstance(account.get("portfolio"), dict) else {}
        explicit_buying_power = _float_value(portfolio.get("buying_power"), default=math.nan)
        explicit_unleveraged = _float_value(
            portfolio.get("unleveraged_buying_power"), default=math.nan
        )
        buying_power_values = (
            [explicit_buying_power, explicit_unleveraged]
            if strict_v2_portfolio
            else [
                _float_value(account.get("buying_power"), default=math.nan),
                explicit_buying_power,
                explicit_unleveraged,
            ]
        )
        buying_power_values = [value for value in buying_power_values if math.isfinite(value)]
        buying_power = min(buying_power_values) if buying_power_values else math.nan
        account_equity = _float_value(portfolio.get("total_value"), default=math.nan)
        if not strict_v2_portfolio and (not math.isfinite(account_equity) or account_equity <= 0):
            for value in (portfolio.get("equity"), portfolio.get("equity_value")):
                candidate = _float_value(value, default=math.nan)
                if math.isfinite(candidate) and candidate > 0:
                    account_equity = candidate
                    break
        explicit_buying_power_ready = math.isfinite(explicit_buying_power) and math.isfinite(
            explicit_unleveraged
        )
        portfolio_ready = (
            math.isfinite(account_equity)
            and account_equity > 0
            and (explicit_buying_power_ready if strict_v2_portfolio else bool(buying_power_values))
        )
        funded = portfolio_ready and math.isfinite(buying_power) and buying_power > 0
        if not active:
            status = "inactive"
            detail = "Account state is not explicitly active in the broker snapshot."
        elif strict_v2_portfolio and not portfolio_ready:
            status = "missing_portfolio"
            detail = "V2 readiness requires positive portfolio.total_value plus explicit buying and unleveraged buying power."
        elif agentic_allowed and options_ready and funded:
            status = "ready"
            detail = "Agentic-accessible, options-approved, and funded."
        elif agentic_allowed and options_ready:
            status = "needs_funding"
            detail = "Agentic-accessible and options-approved, but buying power is not positive in the snapshot."
        elif agentic_allowed:
            status = "needs_options"
            detail = "Agentic-accessible, but options approval is missing in the snapshot."
        elif options_ready:
            status = "needs_agentic_access"
            detail = "Options-approved, but this account is not marked agentic-accessible."
        else:
            status = "not_ready"
            detail = "Snapshot does not show agentic access or options approval."
        rows.append(
            {
                "account": _clean_value(
                    account.get("label")
                    or account.get("nickname")
                    or account.get("account_mask")
                    or account.get("account_number")
                ),
                "account_mask": _clean_value(account.get("account_mask")),
                "account_key": _clean_value(account.get("account_key")),
                "type": _clean_value(account.get("brokerage_account_type") or account.get("type")),
                "state": _clean_value(state),
                "active": active,
                "agentic_allowed": agentic_allowed,
                "option_level": _clean_value(option_level),
                "options_ready": options_ready,
                "buying_power": _clean_value(buying_power if math.isfinite(buying_power) else None),
                "account_equity": _clean_value(
                    account_equity if math.isfinite(account_equity) else None
                ),
                "funded": funded,
                "portfolio_ready": portfolio_ready,
                "status": status,
                "detail": detail,
            }
        )

    agentic_count = sum(1 for row in rows if row.get("agentic_allowed") is True)
    option_ready_count = sum(1 for row in rows if row.get("options_ready") is True)
    agentic_option_rows = [
        row
        for row in rows
        if row.get("agentic_allowed") is True and row.get("options_ready") is True
    ]
    active_agentic_option_rows = [row for row in agentic_option_rows if row.get("active") is True]
    funded_agentic_option_rows = [
        row for row in active_agentic_option_rows if row.get("funded") is True
    ]
    if funded_agentic_option_rows:
        status = "ready"
        label = "Agentic options ready"
        detail = "At least one agentic-accessible options account is funded."
    elif active_agentic_option_rows:
        status = "needs_funding"
        label = "Fund agentic options account"
        detail = (
            "Agentic options access is available, but buying power is not positive in the snapshot."
        )
    elif agentic_option_rows:
        status = "inactive_account"
        label = "Agentic options account inactive"
        detail = (
            "Agentic options permissions exist, but the snapshot does not show an active account."
        )
    elif agentic_count and option_ready_count:
        status = "split_permissions"
        label = "Split account permissions"
        detail = "One account is agentic-accessible and another is options-approved; no single account has both."
    elif agentic_count:
        status = "agentic_needs_options"
        label = "Agentic account needs options"
        detail = "An agentic-accessible account exists, but it is not options-approved."
    elif option_ready_count:
        status = "options_needs_agentic"
        label = "Options account needs agentic access"
        detail = "An options-approved account exists, but it is not accessible to this agent."
    else:
        status = "missing_ready_account"
        label = "No agentic options account"
        detail = "Snapshot does not show any account with both agentic access and options approval."
    return {
        "status": status,
        "label": label,
        "detail": detail,
        "rows": rows,
        "agentic_account_count": agentic_count,
        "option_ready_account_count": option_ready_count,
        "agentic_option_ready": bool(funded_agentic_option_rows),
        "funded_agentic_option_count": len(funded_agentic_option_rows),
    }


def _robinhood_mcp_capability_rows(
    account_readiness: dict[str, Any] | None,
) -> list[dict[str, Any]]:
    """Summarize Robinhood MCP capabilities separately from local execution policy."""
    readiness = account_readiness if isinstance(account_readiness, dict) else {}
    rows = readiness.get("rows") if isinstance(readiness.get("rows"), list) else []
    has_snapshot_accounts = bool(rows)
    has_agentic = bool(readiness.get("agentic_account_count"))
    has_funded_agentic_options = bool(readiness.get("funded_agentic_option_count"))
    funded_agentic_equity = any(
        row.get("active") is True
        and row.get("agentic_allowed") is True
        and row.get("funded") is True
        for row in rows
        if isinstance(row, dict)
    )
    readiness_label = str(readiness.get("label") or readiness.get("status") or "Unknown")

    def row(
        capability: str,
        tool_support: str,
        account_status: str,
        local_policy: str,
        note: str,
    ) -> dict[str, Any]:
        return {
            "capability": capability,
            "tool_support": tool_support,
            "account_status": account_status,
            "local_policy": local_policy,
            "note": note,
        }

    if not has_snapshot_accounts:
        unknown = "unknown until a fresh read-only broker snapshot is normalized"
        return [
            row(
                "Accounts / buying power",
                "read supported",
                unknown,
                "read-only",
                "Refresh the raw MCP snapshot before trusting readiness.",
            ),
            row(
                "Search / live saved scanners",
                "read supported",
                unknown,
                "read-only",
                "Resolves company names and runs saved Robinhood screeners against live market data.",
            ),
            row(
                "Fundamentals / earnings / equity history",
                "read supported",
                unknown,
                "read-only",
                "Adds broker-side company, catalyst, and trend checks to each candidate review.",
            ),
            row(
                "Positions / orders",
                "read supported",
                unknown,
                "read-only",
                "Useful for reconciliation and lifecycle audits.",
            ),
            row(
                "Broker realized P&L / trade history",
                "read supported",
                unknown,
                "read-only",
                "Keeps real broker outcomes separate from local simulated results.",
            ),
            row(
                "Option chains / contracts / quotes",
                "read supported",
                unknown,
                "read-only",
                "Useful for exact contract verification before a paper/live review.",
            ),
            row(
                "Option price history",
                "read supported",
                unknown,
                "read-only",
                "Adds recent contract-price behavior; interpolated bars should be ignored.",
            ),
            row(
                "Equity order review / placement",
                "write supported",
                unknown,
                "confirmation required",
                "Optedge does not auto-submit broker orders.",
            ),
            row(
                "Single-leg option review / placement",
                "write supported",
                unknown,
                "confirmation required",
                "Requires one account with agentic access, options approval, and funding.",
            ),
        ]

    equity_status = (
        "ready for review if funded"
        if funded_agentic_equity
        else (
            "agentic account exists but buying power is not positive"
            if has_agentic
            else "no agentic-accessible account"
        )
    )
    option_status = (
        "ready for review if user approves" if has_funded_agentic_options else readiness_label
    )
    return [
        row(
            "Accounts / buying power",
            "read supported",
            "available from snapshot",
            "read-only",
            "Use this to verify which account is agentic-accessible and funded.",
        ),
        row(
            "Search / live saved scanners",
            "read supported",
            "available through Robinhood MCP",
            "read-only",
            "Use search to resolve names and run_scan to compare live scanner matches with Optedge candidates.",
        ),
        row(
            "Fundamentals / earnings / equity history",
            "read supported",
            "available through Robinhood MCP",
            "read-only",
            "Useful for current company context, earnings timing, and trend confirmation.",
        ),
        row(
            "Positions / orders",
            "read supported",
            "available from snapshot or live MCP reads",
            "read-only",
            "Best used to reconcile Robinhood positions against Optedge local lifecycle state.",
        ),
        row(
            "Broker realized P&L / trade history",
            "read supported",
            "available through Robinhood MCP",
            "read-only",
            "Use broker outcomes as external evidence and keep them separate from local paper or forward-test P&L.",
        ),
        row(
            "Option chains / contracts / quotes",
            "read supported",
            "available through Robinhood MCP",
            "read-only",
            "Useful for confirming exact option IDs, strikes, expiries, bid/ask, and tradability.",
        ),
        row(
            "Option price history",
            "read supported",
            "available through Robinhood MCP",
            "read-only",
            "Use recent option bars as context only; ignore interpolated gap-fill bars and use quotes for the current mark.",
        ),
        row(
            "Equity order review / placement",
            "write supported",
            equity_status,
            "explicit approval required",
            "Review is allowed only on agentic-accessible accounts; live placement still needs confirmation.",
        ),
        row(
            "Single-leg option review / placement",
            "write supported",
            option_status,
            "explicit approval required",
            "Robinhood supports single-leg options here, but the account must be agentic, options-approved, and funded.",
        ),
        row(
            "Order cancellation",
            "write supported",
            option_status,
            "explicit approval required",
            "Cancellation is a real broker action and needs exact order review and confirmation.",
        ),
        row(
            "Option exercise",
            "not exposed by the connected MCP",
            "use Robinhood app/support",
            "outside Optedge",
            "Do not imply programmatic exercise support; use Robinhood's official exercise workflow.",
        ),
    ]


def build_broker_reconciliation(
    data_dir: Path = DATA_DIR,
    limit: int = 80,
    *,
    snapshot_override: dict[str, Any] | None = None,
) -> dict[str, Any]:
    """Compare local state with one optional, caller-frozen broker snapshot."""
    data_dir = Path(data_dir)
    snapshot_path = data_dir / "robinhood_broker_snapshot.json"
    snapshot = snapshot_override if snapshot_override is not None else _read_json(snapshot_path)
    snapshot_digest = hashlib.sha256(
        json.dumps(
            snapshot,
            sort_keys=True,
            separators=(",", ":"),
            default=str,
        ).encode("utf-8")
    ).hexdigest()
    open_positions = _read_json(data_dir / "open_positions.json")
    paper_positions = _read_json(data_dir / "agentic_paper_positions.json")
    open_positions = open_positions if isinstance(open_positions, list) else []
    paper_positions = paper_positions if isinstance(paper_positions, list) else []
    active_paper = [
        row
        for row in paper_positions
        if isinstance(row, dict) and str(row.get("status") or "").lower() != "closed"
    ]

    broker_linked_positions = [
        row
        for row in open_positions
        if isinstance(row, dict) and _local_option_tracking_scope(row) == "broker_linked"
    ]
    research_positions = [
        row
        for row in open_positions
        if isinstance(row, dict) and _local_option_tracking_scope(row) == "research_lifecycle"
    ]
    local_rows = _aggregate_option_records(
        [_agentic_local_option_record(row, "optedge") for row in broker_linked_positions],
        by_account=True,
    )
    research_rows = _aggregate_option_records(
        [_agentic_local_option_record(row, "research") for row in research_positions],
        by_account=False,
    )
    research_expired_count = sum(
        1
        for row in research_rows
        if math.isfinite(_float_value(row.get("dte"), default=math.nan))
        and _float_value(row.get("dte"), default=math.nan) < 0
    )
    research_active_count = len(research_rows) - research_expired_count
    paper_rows = _aggregate_option_records(
        [
            _agentic_local_option_record(row, "paper")
            for row in active_paper
            if isinstance(row, dict)
        ],
        by_account=True,
    )
    paper_keys = {
        str(row.get("contract_key"))
        for row in paper_rows
        if str(row.get("contract_key") or "").strip("|")
    }

    if not isinstance(snapshot, dict) or not snapshot:
        empty_readiness = _broker_account_readiness([])
        return {
            "generated_at": datetime.now(UTC).isoformat(),
            "status": "missing_snapshot",
            "label": "Broker snapshot missing",
            "snapshot_path": str(snapshot_path),
            "snapshot_digest_sha256": snapshot_digest,
            "snapshot_exists": False,
            "snapshot_age": "missing",
            "snapshot_age_minutes": None,
            "broker_option_count": 0,
            "optedge_option_count": len(local_rows),
            "research_lifecycle_option_count": len(research_rows),
            "research_lifecycle_active_count": research_active_count,
            "research_lifecycle_expired_count": research_expired_count,
            "paper_option_count": len(paper_rows),
            "matched_count": 0,
            "broker_only_count": 0,
            "local_only_count": len(local_rows),
            "paper_only_count": len(paper_rows),
            "missing_contract_fields_count": 0,
            "quantity_mismatch_count": 0,
            "type_mismatch_count": 0,
            "account_scope_mismatch_count": 0,
            "agentic_account_count": 0,
            "option_ready_account_count": 0,
            "agentic_option_ready": False,
            "agentic_readiness_status": empty_readiness.get("status"),
            "agentic_readiness_label": empty_readiness.get("label"),
            "agentic_readiness_detail": empty_readiness.get("detail"),
            "funded_agentic_option_count": 0,
            "working_option_order_count": 0,
            "unresolved_working_option_order_count": 0,
            "working_option_order_contract_keys": [],
            "working_option_orders": [],
            "normalization_ready": False,
            "normalization_blocker_count": 0,
            "normalization_blockers": [],
            "snapshot_schema": None,
            "raw_bundle_schema": None,
            "execution_capture_ready": False,
            "account_readiness_rows": [],
            "robinhood_mcp_capabilities": _robinhood_mcp_capability_rows(empty_readiness),
            "rows": [],
            "warnings": [
                "Add data/robinhood_broker_snapshot.json before trusting live Robinhood reconciliation."
            ],
            "notes": [
                "This reconciliation is local/offline and does not connect to a broker.",
                "A broker snapshot should contain current option positions with symbol, side, strike, expiry, and quantity.",
                "Research and paper lifecycle rows are not broker holdings and are reported separately.",
            ],
        }

    snapshot_age = _iso_age_minutes(snapshot.get("generated_at"))
    broker_raw_rows, accounts = _broker_snapshot_option_rows(snapshot)
    broker_rows = _aggregate_option_records(
        [_broker_option_record(row) for row in broker_raw_rows if isinstance(row, dict)],
        by_account=True,
    )
    terminal_option_order_states = {
        "filled",
        "cancelled",
        "canceled",
        "rejected",
        "failed",
        "voided",
        "expired",
        "partially_filled_rest_cancelled",
    }
    raw_option_orders = (
        snapshot.get("option_orders") if isinstance(snapshot.get("option_orders"), list) else []
    )
    working_option_orders: list[dict[str, Any]] = []
    working_option_order_keys: set[str] = set()
    for raw_order in raw_option_orders:
        if not isinstance(raw_order, dict):
            continue
        state = str(raw_order.get("state") or raw_order.get("status") or "").strip().lower()
        if state in terminal_option_order_states:
            continue
        record = _broker_option_record(raw_order)
        record["state"] = state
        record["order_id"] = _clean_value(raw_order.get("order_id") or raw_order.get("id"))
        key = str(record.get("contract_key") or "")
        if not record.get("missing_fields") and key.strip("|"):
            working_option_order_keys.add(key)
        working_option_orders.append(record)
    unresolved_working_option_order_count = sum(
        1 for row in working_option_orders if row.get("missing_fields")
    )
    broker_keys = {
        str(row.get("contract_key"))
        for row in broker_rows
        if not row.get("missing_fields") and str(row.get("contract_key") or "").strip("|")
    }
    broker_by_contract: dict[str, list[dict[str, Any]]] = {}
    local_by_contract: dict[str, list[dict[str, Any]]] = {}
    for row in broker_rows:
        broker_by_contract.setdefault(str(row.get("contract_key") or ""), []).append(row)
    for row in local_rows:
        local_by_contract.setdefault(str(row.get("contract_key") or ""), []).append(row)
    rows: list[dict[str, Any]] = []
    matched_count = 0
    broker_only_count = 0
    missing_contract_fields_count = 0
    quantity_mismatch_count = 0
    type_mismatch_count = 0
    account_scope_mismatch_count = 0
    consumed_local_ids: set[int] = set()
    for row in broker_rows:
        key = str(row.get("contract_key") or "")
        missing = row.get("missing_fields") if isinstance(row.get("missing_fields"), list) else []
        candidates = local_by_contract.get(key) or []
        broker_account_key = str(row.get("account_key") or "")
        exact_account_candidates = [
            candidate
            for candidate in candidates
            if broker_account_key and str(candidate.get("account_key") or "") == broker_account_key
        ]
        unscoped_candidates = [
            candidate for candidate in candidates if not str(candidate.get("account_key") or "")
        ]
        local_match_row: dict[str, Any] | None = None
        scope_ambiguous = False
        if len(exact_account_candidates) == 1:
            local_match_row = exact_account_candidates[0]
        elif len(broker_by_contract.get(key) or []) == 1 and len(unscoped_candidates) == 1:
            local_match_row = unscoped_candidates[0]
        elif candidates:
            scope_ambiguous = True
            consumed_local_ids.update(id(candidate) for candidate in candidates)
        if local_match_row is not None:
            consumed_local_ids.add(id(local_match_row))
        in_optedge = local_match_row is not None
        in_paper = key in paper_keys
        if missing:
            status = "broker_missing_contract_fields"
            missing_contract_fields_count += 1
        elif scope_ambiguous:
            status = "account_scope_mismatch"
            account_scope_mismatch_count += 1
        elif in_optedge:
            broker_type = str(row.get("position_type") or "").strip().lower()
            local_type = str(local_match_row.get("position_type") or "").strip().lower()
            broker_signed = _float_value(row.get("signed_quantity"), default=math.nan)
            local_signed = _float_value(local_match_row.get("signed_quantity"), default=math.nan)
            if broker_type != local_type or (
                math.isfinite(broker_signed)
                and math.isfinite(local_signed)
                and (broker_signed < 0) != (local_signed < 0)
            ):
                status = "position_type_mismatch"
                type_mismatch_count += 1
            elif not (
                math.isfinite(broker_signed)
                and math.isfinite(local_signed)
                and abs(broker_signed - local_signed) <= 1e-9
            ):
                status = "quantity_mismatch"
                quantity_mismatch_count += 1
            else:
                status = "matched"
                matched_count += 1
        else:
            status = "broker_only_paper_overlap" if in_paper else "broker_only"
            broker_only_count += 1
        rows.append(
            {
                "status": status,
                "source": "broker",
                "contract": row.get("contract"),
                "symbol": row.get("symbol"),
                "option_side": row.get("option_side"),
                "strike": row.get("strike"),
                "expiry": row.get("expiry"),
                "quantity": row.get("quantity"),
                "signed_quantity": row.get("signed_quantity"),
                "position_type": row.get("position_type"),
                "account": row.get("account"),
                "account_key": row.get("account_key"),
                "account_mask": row.get("account_mask"),
                "local_quantity": local_match_row.get("quantity") if local_match_row else None,
                "local_signed_quantity": local_match_row.get("signed_quantity")
                if local_match_row
                else None,
                "local_position_type": local_match_row.get("position_type")
                if local_match_row
                else None,
                "average_price": row.get("average_price"),
                "current_price": row.get("current_price"),
                "local_match": (
                    "both"
                    if in_optedge and in_paper
                    else "optedge"
                    if in_optedge
                    else "paper_reference_only"
                    if in_paper
                    else "-"
                ),
                "missing_fields": ", ".join(missing),
            }
        )

    local_only_count = 0
    local_expired_count = 0
    for row in local_rows:
        key = str(row.get("contract_key") or "")
        if id(row) in consumed_local_ids:
            continue
        dte = _float_value(row.get("dte"), default=math.nan)
        is_expired = math.isfinite(dte) and dte < 0
        if is_expired:
            local_expired_count += 1
        else:
            local_only_count += 1
        rows.append(
            {
                "status": "local_expired" if is_expired else "local_only",
                "source": "optedge",
                "contract": row.get("contract"),
                "symbol": row.get("symbol"),
                "option_side": row.get("option_side"),
                "strike": row.get("strike"),
                "expiry": row.get("expiry"),
                "dte": row.get("dte"),
                "quantity": row.get("quantity"),
                "signed_quantity": row.get("signed_quantity"),
                "position_type": row.get("position_type"),
                "account_key": row.get("account_key"),
                "trade_status": row.get("trade_status"),
                "latest_exit_action": row.get("latest_exit_action"),
                "latest_exit_pressure": row.get("latest_exit_pressure"),
                "local_match": "-",
            }
        )

    paper_only_count = 0
    paper_expired_count = 0
    for row in paper_rows:
        key = str(row.get("contract_key") or "")
        if key in broker_keys:
            continue
        dte = _float_value(row.get("dte"), default=math.nan)
        is_expired = math.isfinite(dte) and dte < 0
        if is_expired:
            paper_expired_count += 1
        else:
            paper_only_count += 1
        rows.append(
            {
                "status": "paper_expired" if is_expired else "paper_only",
                "source": "paper",
                "contract": row.get("contract"),
                "symbol": row.get("symbol"),
                "option_side": row.get("option_side"),
                "strike": row.get("strike"),
                "expiry": row.get("expiry"),
                "dte": row.get("dte"),
                "quantity": row.get("quantity"),
                "trade_status": row.get("trade_status"),
                "local_match": "-",
            }
        )

    snapshot_schema = str(snapshot.get("schema") or "")
    raw_bundle_schema = str(snapshot.get("raw_bundle_schema") or "")
    trusted_capture_provenance = (
        snapshot_schema == SNAPSHOT_SCHEMA and raw_bundle_schema == RAW_BUNDLE_SCHEMA
    )
    account_readiness = _broker_account_readiness(
        accounts,
        strict_v2_portfolio=raw_bundle_schema == RAW_BUNDLE_SCHEMA,
    )
    option_ready_accounts = [
        row
        for row in accounts
        if isinstance(row, dict) and _account_options_ready(row.get("option_level"))
    ]
    agentic_accounts = [
        row for row in accounts if isinstance(row, dict) and row.get("agentic_allowed") is True
    ]
    agentic_option_ready = bool(account_readiness.get("agentic_option_ready"))
    warnings: list[str] = []
    normalization_blockers = [
        str(value) for value in (snapshot.get("normalization_blockers") or []) if str(value).strip()
    ]
    reported_account_readiness = dict(account_readiness)
    if not trusted_capture_provenance:
        reported_account_readiness.update(
            {
                "status": "capture_untrusted",
                "label": "Trusted V2 broker capture required",
                "detail": (
                    f"Manual review requires snapshot schema {SNAPSHOT_SCHEMA} normalized from "
                    f"raw bundle schema {RAW_BUNDLE_SCHEMA}."
                ),
                "agentic_option_ready": False,
                "funded_agentic_option_count": 0,
            }
        )
    elif normalization_blockers:
        reported_account_readiness.update(
            {
                "status": "capture_incomplete",
                "label": "Broker capture incomplete",
                "detail": "Required account-scoped reads or pagination evidence are incomplete.",
                "agentic_option_ready": False,
                "funded_agentic_option_count": 0,
            }
        )
    warnings.extend(normalization_blockers)
    if not trusted_capture_provenance:
        warnings.append(str(reported_account_readiness["detail"]))
    if agentic_accounts and not agentic_option_ready:
        warnings.append("Agentic account snapshot does not show options approval.")
    if option_ready_accounts and not agentic_option_ready:
        warnings.append(
            "An options-approved account exists, but it is not marked agentic in the snapshot."
        )
    if account_readiness.get("status") != "ready":
        warnings.append(
            str(
                account_readiness.get("detail")
                or account_readiness.get("label")
                or "Agentic options account is not ready."
            )
        )
    if snapshot_age is None:
        warnings.append("Broker snapshot timestamp is missing.")
    elif snapshot_age > AGENTIC_STALE_MINUTES:
        warnings.append(f"Broker snapshot is stale ({_short_age_label(snapshot_age)} old).")
    if broker_only_count:
        warnings.append(
            f"{broker_only_count} broker option position(s) are not tracked by Optedge or local paper."
        )
    if local_only_count:
        warnings.append(
            f"{local_only_count} local Optedge option position(s) are not in the broker snapshot."
        )
    if local_expired_count:
        warnings.append(
            f"{local_expired_count} expired Optedge option position(s) are still open locally."
        )
    if research_rows:
        warnings.append(
            f"{len(research_rows)} Optedge research lifecycle option row(s) are tracked separately from broker holdings."
        )
    if paper_only_count:
        warnings.append(
            f"{paper_only_count} agentic paper option position(s) are tracked separately from broker holdings."
        )
    if paper_expired_count:
        warnings.append(
            f"{paper_expired_count} expired paper option position(s) are still open locally."
        )
    if missing_contract_fields_count:
        warnings.append(
            f"{missing_contract_fields_count} broker row(s) need strike/side/expiry details to match exactly."
        )
    if quantity_mismatch_count:
        warnings.append(
            f"{quantity_mismatch_count} broker/local option position(s) have different aggregate signed quantities."
        )
    if type_mismatch_count:
        warnings.append(
            f"{type_mismatch_count} broker/local option position(s) disagree on long/short type."
        )
    if account_scope_mismatch_count:
        warnings.append(
            f"{account_scope_mismatch_count} option position(s) cannot be reconciled to one stable account key."
        )
    if unresolved_working_option_order_count:
        warnings.append(
            f"{unresolved_working_option_order_count} nonterminal broker option order(s) cannot be matched to an exact contract."
        )

    if (
        broker_only_count
        or local_only_count
        or local_expired_count
        or missing_contract_fields_count
        or quantity_mismatch_count
        or type_mismatch_count
        or account_scope_mismatch_count
        or unresolved_working_option_order_count
        or normalization_blockers
    ):
        status = "mismatch"
        label = "Broker/local mismatch"
    elif not broker_rows and not local_rows:
        status = "empty"
        label = "No broker-linked option positions"
    elif warnings:
        status = "review"
        label = "Broker sync review"
    else:
        status = "synced"
        label = "Broker/local synced"

    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "status": status,
        "label": label,
        "snapshot_path": str(snapshot_path),
        "snapshot_digest_sha256": snapshot_digest,
        "snapshot_exists": True,
        "snapshot_generated_at": _clean_value(snapshot.get("generated_at")),
        "snapshot_age": _short_age_label(snapshot_age),
        "snapshot_age_minutes": round(snapshot_age, 1) if snapshot_age is not None else None,
        "broker_option_count": len(broker_rows),
        "optedge_option_count": len(local_rows),
        "research_lifecycle_option_count": len(research_rows),
        "research_lifecycle_active_count": research_active_count,
        "research_lifecycle_expired_count": research_expired_count,
        "paper_option_count": len(paper_rows),
        "matched_count": matched_count,
        "broker_only_count": broker_only_count,
        "local_only_count": local_only_count,
        "paper_only_count": paper_only_count,
        "local_expired_count": local_expired_count,
        "paper_expired_count": paper_expired_count,
        "missing_contract_fields_count": missing_contract_fields_count,
        "quantity_mismatch_count": quantity_mismatch_count,
        "type_mismatch_count": type_mismatch_count,
        "account_scope_mismatch_count": account_scope_mismatch_count,
        "agentic_account_count": len(agentic_accounts),
        "option_ready_account_count": len(option_ready_accounts),
        "agentic_option_ready": reported_account_readiness.get("agentic_option_ready"),
        "agentic_readiness_status": reported_account_readiness.get("status"),
        "agentic_readiness_label": reported_account_readiness.get("label"),
        "agentic_readiness_detail": reported_account_readiness.get("detail"),
        "funded_agentic_option_count": reported_account_readiness.get(
            "funded_agentic_option_count"
        ),
        "working_option_order_count": len(working_option_orders),
        "unresolved_working_option_order_count": unresolved_working_option_order_count,
        "working_option_order_contract_keys": sorted(working_option_order_keys),
        "working_option_orders": working_option_orders[:50],
        "normalization_ready": not normalization_blockers,
        "normalization_blocker_count": len(normalization_blockers),
        "normalization_blockers": normalization_blockers[:10],
        "snapshot_schema": snapshot_schema or None,
        "raw_bundle_schema": raw_bundle_schema or None,
        "execution_capture_ready": trusted_capture_provenance and not normalization_blockers,
        "account_readiness_rows": account_readiness.get("rows") or [],
        "robinhood_mcp_capabilities": _robinhood_mcp_capability_rows(reported_account_readiness),
        "warnings": warnings[:10],
        "rows": rows[: max(1, min(int(limit or 80), 250))],
        "notes": [
            "This is a local reconciliation view; it does not submit, cancel, or replace broker orders.",
            "Only explicitly broker-linked local rows participate in broker reconciliation; research and paper lifecycle rows are reported separately.",
            "Use it to make sure live Robinhood positions match broker-linked Optedge state before reviewing new entries or exits.",
        ],
    }


def normalize_robinhood_broker_snapshot_file(
    data_dir: Path = DATA_DIR,
    *,
    dry_run: bool = False,
) -> dict[str, Any]:
    """Normalize the local raw read-only Robinhood snapshot for cockpit use."""
    data_dir = Path(data_dir)
    raw_path = data_dir / "robinhood_mcp_snapshot_raw.json"
    output_path = data_dir / "robinhood_broker_snapshot.json"
    if not raw_path.exists():
        return {
            "ok": False,
            "error": "raw snapshot missing",
            "raw_path": str(raw_path),
            "output_path": str(output_path),
            "notes": [
                "Save read-only Robinhood MCP account/position/order data to data/robinhood_mcp_snapshot_raw.json first.",
                "This action does not connect to Robinhood or place broker orders.",
            ],
        }
    raw = _read_json(raw_path)
    if raw is None:
        return {
            "ok": False,
            "error": "raw snapshot is not valid JSON",
            "raw_path": str(raw_path),
            "output_path": str(output_path),
        }
    try:
        snapshot = normalize_broker_snapshot(raw)
    except Exception as exc:
        return {
            "ok": False,
            "error": f"could not normalize snapshot: {exc}",
            "raw_path": str(raw_path),
            "output_path": str(output_path),
        }
    counts = snapshot.get("counts") if isinstance(snapshot.get("counts"), dict) else {}
    result = {
        "ok": True,
        "dry_run": bool(dry_run),
        "raw_path": str(raw_path),
        "output_path": str(output_path),
        "counts": counts,
        "summary": {
            "accounts": counts.get("accounts", 0),
            "option_positions": counts.get("option_positions", 0),
            "equity_positions": counts.get("equity_positions", 0),
            "option_orders": counts.get("option_orders", 0),
            "equity_orders": counts.get("equity_orders", 0),
        },
        "does_not_place_orders": True,
        "notes": [
            "Normalized local read-only broker snapshot for cockpit reconciliation.",
            "No broker connection or broker order action was performed.",
        ],
    }
    if dry_run:
        result["snapshot_preview"] = {
            "schema": snapshot.get("schema"),
            "generated_at": snapshot.get("generated_at"),
            "counts": counts,
        }
        return result
    output_path.parent.mkdir(parents=True, exist_ok=True)
    output_path.write_text(
        json.dumps(snapshot, indent=2, sort_keys=True, default=str), encoding="utf-8"
    )
    result["equity_ledger_update"] = append_account_equity_ledgers(
        snapshot,
        default_account_equity_ledger_dir(data_dir),
    )
    result["broker_reconciliation"] = build_broker_reconciliation(data_dir)
    return result


def build_agentic_autopilot_status(data_dir: Path = DATA_DIR) -> dict[str, Any]:
    """Summarize the manual Robinhood research/paper state for the cockpit."""
    data_dir = Path(data_dir)
    queue = _read_json(data_dir / "robinhood_agentic_queue.json")
    cycle = _read_json(data_dir / "robinhood_agentic_cycle.json")
    tickets_blob = _read_json(data_dir / "robinhood_live_order_tickets.json")
    paper_positions = _read_json(data_dir / "agentic_paper_positions.json")
    open_positions = _read_json(data_dir / "open_positions.json")
    queue = queue if isinstance(queue, dict) else {}
    cycle = cycle if isinstance(cycle, dict) else {}
    tickets = tickets_blob.get("tickets") if isinstance(tickets_blob, dict) else []
    tickets = tickets if isinstance(tickets, list) else []
    paper_positions = paper_positions if isinstance(paper_positions, list) else []
    open_positions = open_positions if isinstance(open_positions, list) else []

    active_paper = [
        row
        for row in paper_positions
        if isinstance(row, dict) and str(row.get("status") or "").lower() != "closed"
    ]
    paper_contract_keys, paper_direction_keys = _agentic_open_option_keys(active_paper)
    optedge_contract_keys, optedge_direction_keys = _agentic_open_option_keys(open_positions)
    broker_reconciliation = build_broker_reconciliation(data_dir)
    entry_gate = cycle.get("entry_gate") if isinstance(cycle.get("entry_gate"), dict) else {}
    hard_pause_reasons = (
        cycle.get("hard_pause_reasons") if isinstance(cycle.get("hard_pause_reasons"), list) else []
    )
    gate_blockers = (
        entry_gate.get("blockers") if isinstance(entry_gate.get("blockers"), list) else []
    )
    gate_warnings = (
        entry_gate.get("warnings") if isinstance(entry_gate.get("warnings"), list) else []
    )
    queue_age = _iso_age_minutes(queue.get("generated_at"))
    cycle_age = _iso_age_minutes(cycle.get("generated_at"))
    ticket_packet_generated_at = (
        tickets_blob.get("generated_at") if isinstance(tickets_blob, dict) else None
    )
    ticket_packet_age = _iso_age_minutes(ticket_packet_generated_at)
    queue_freshness = _agentic_freshness(queue_age)
    cycle_freshness = _agentic_freshness(cycle_age)
    ticket_packet_freshness = _agentic_freshness(ticket_packet_age)
    kill_switch = (data_dir / "agentic_trading_disabled.flag").exists()
    blockers = []
    if kill_switch:
        blockers.append("kill-switch file is present")
    if tickets:
        blockers.append(
            "legacy live-ticket artifacts are deprecated and cannot be executed; rebuild one packet in Trade Desk"
        )
    if tickets and not queue:
        blockers.append("agentic queue file is missing for staged live-ticket review")
    elif queue and queue_freshness == "missing":
        blockers.append("agentic queue timestamp is missing")
    elif queue_freshness == "stale":
        blockers.append(f"agentic queue is stale ({_short_age_label(queue_age)} old)")
    if tickets and not cycle:
        blockers.append("agentic cycle file is missing for staged live-ticket review")
    elif cycle and cycle_freshness == "missing":
        blockers.append("agentic cycle timestamp is missing")
    elif cycle_freshness == "stale":
        blockers.append(f"agentic cycle is stale ({_short_age_label(cycle_age)} old)")
    if tickets and ticket_packet_freshness == "missing":
        blockers.append("live ticket packet timestamp is missing")
    elif tickets and ticket_packet_freshness == "stale":
        blockers.append(f"live ticket packet is stale ({_short_age_label(ticket_packet_age)} old)")
    blockers.extend(str(x) for x in hard_pause_reasons if str(x).strip())
    blockers.extend(str(x) for x in gate_blockers if str(x).strip())
    broker_status = str(broker_reconciliation.get("status") or "")
    if tickets and broker_status == "missing_snapshot":
        blockers.append("broker snapshot is missing for staged live-ticket reconciliation")
    elif tickets and broker_status == "mismatch":
        blockers.append("broker/local position mismatch must be reviewed before live-ticket action")
    if tickets:
        broker_snapshot_age = broker_reconciliation.get("snapshot_age_minutes")
        broker_readiness_status = (
            str(broker_reconciliation.get("agentic_readiness_status") or "").strip().lower()
        )
        funded_agentic_options = int(
            _float_value(
                broker_reconciliation.get("funded_agentic_option_count"),
                default=0.0,
            )
        )
        if broker_snapshot_age is None:
            blockers.append("broker snapshot timestamp is missing for staged live-ticket review")
        elif float(broker_snapshot_age) > AGENTIC_STALE_MINUTES:
            blockers.append(
                f"broker snapshot is stale ({_short_age_label(float(broker_snapshot_age))} old)"
            )
        if broker_readiness_status != "ready" or funded_agentic_options <= 0:
            readiness_label = str(
                broker_reconciliation.get("agentic_readiness_label")
                or broker_readiness_status
                or "not ready"
            )
            blockers.append(
                f"broker account is not funded and agentic-options ready ({readiness_label})"
            )
    freshness_warnings = []
    if queue_freshness == "aging":
        freshness_warnings.append(f"agentic queue is aging ({_short_age_label(queue_age)} old)")
    if cycle_freshness == "aging":
        freshness_warnings.append(f"agentic cycle is aging ({_short_age_label(cycle_age)} old)")
    if tickets and ticket_packet_freshness == "aging":
        freshness_warnings.append(
            f"live ticket packet is aging ({_short_age_label(ticket_packet_age)} old)"
        )
    if not tickets and broker_status in {"missing_snapshot", "mismatch", "review"}:
        freshness_warnings.extend(str(x) for x in (broker_reconciliation.get("warnings") or [])[:3])

    ticket_rows = []
    preflight_rows = []
    broker_working_contract_keys = {
        str(value)
        for value in (broker_reconciliation.get("working_option_order_contract_keys") or [])
        if str(value).strip("|")
    }
    account_readiness_rows = (
        broker_reconciliation.get("account_readiness_rows")
        if isinstance(broker_reconciliation.get("account_readiness_rows"), list)
        else []
    )
    for ticket in tickets[-20:]:
        if not isinstance(ticket, dict):
            continue
        contract_key = _agentic_contract_key(ticket)
        direction_key = _agentic_direction_key(ticket)
        paper_tracked = contract_key in paper_contract_keys
        optedge_duplicate = (
            contract_key in optedge_contract_keys or direction_key in optedge_direction_keys
        )
        ticket_age = _iso_age_minutes(ticket.get("generated_at") or ticket_packet_generated_at)
        ticket_freshness = _agentic_freshness(ticket_age)
        status = (
            "paper_tracked"
            if paper_tracked
            else "stale"
            if ticket_freshness == "stale"
            else "blocked"
            if blockers
            else "confirmation_required"
        )
        preflight = _agentic_ticket_preflight(
            ticket,
            contract_key=contract_key,
            direction_key=direction_key,
            ticket_freshness=ticket_freshness,
            queue_freshness=queue_freshness,
            cycle_freshness=cycle_freshness,
            ticket_packet_freshness=ticket_packet_freshness,
            entry_gate=entry_gate,
            blockers=blockers,
            paper_contract_keys=paper_contract_keys,
            optedge_contract_keys=optedge_contract_keys,
            optedge_direction_keys=optedge_direction_keys,
            broker_working_contract_keys=broker_working_contract_keys,
            account_readiness_rows=account_readiness_rows,
        )
        mcp_plan = ticket.get("robinhood_mcp_review_plan")
        mcp_plan = mcp_plan if isinstance(mcp_plan, dict) else {}
        contract_lookup = (
            mcp_plan.get("contract_lookup")
            if isinstance(mcp_plan.get("contract_lookup"), dict)
            else {}
        )
        mcp_review_status = (
            "ready"
            if (
                mcp_plan.get("review_tool") == "review_option_order"
                and mcp_plan.get("requires_explicit_user_confirmation_before_place")
                and not mcp_plan.get("script_submits_live_orders")
            )
            else "missing"
            if not mcp_plan
            else "review"
        )
        for check in preflight["checks"]:
            preflight_rows.append(
                {
                    "contract": _clean_value(ticket.get("contract")),
                    "level": check.get("level"),
                    "check": check.get("label"),
                    "detail": check.get("detail"),
                }
            )
        ticket_rows.append(
            {
                "status": status,
                "symbol": _clean_value(ticket.get("symbol")),
                "contract": _clean_value(ticket.get("contract")),
                "option_side": _clean_value(ticket.get("option_side")),
                "strike": _clean_value(ticket.get("strike")),
                "expiry": _clean_value(ticket.get("expiry")),
                "quantity": _clean_value(ticket.get("quantity")),
                "limit_price": _clean_value(ticket.get("limit_price")),
                "estimated_premium_dollars": _clean_value(ticket.get("estimated_premium_dollars")),
                "entry_gate_status": _clean_value(ticket.get("entry_gate_status")),
                "confirmation_required": bool(ticket.get("confirmation_required", True)),
                "paper_tracked": paper_tracked,
                "optedge_duplicate": optedge_duplicate,
                "preflight_status": preflight["status"],
                "preflight_blocks": preflight["block_count"],
                "preflight_warnings": preflight["warn_count"],
                "freshness": ticket_freshness,
                "age": _short_age_label(ticket_age),
                "swing_fit_label": _clean_value(ticket.get("swing_fit_label")),
                "confidence": _clean_value(ticket.get("confidence")),
                "rank_score": _clean_value(ticket.get("rank_score")),
                "mcp_review_status": mcp_review_status,
                "mcp_review_tool": _clean_value(mcp_plan.get("review_tool")),
                "mcp_place_tool": _clean_value(
                    mcp_plan.get("place_tool_after_explicit_confirmation")
                ),
                "mcp_lookup_symbol": _clean_value(contract_lookup.get("chain_symbol")),
                "mcp_lookup_expiry": _clean_value(contract_lookup.get("expiration_date")),
                "mcp_lookup_type": _clean_value(contract_lookup.get("type")),
            }
        )

    ticket_preflight_blocks = sum(1 for row in preflight_rows if row.get("level") == "block")
    ticket_preflight_warnings = sum(1 for row in preflight_rows if row.get("level") == "warn")
    if kill_switch:
        status = "disabled"
        tone = "bad"
        label = "Kill switch active"
        detail = "No local paper or live review entries should be taken until the kill switch is removed."
    elif cycle.get("hard_pause"):
        status = "paused"
        tone = "bad"
        label = "Hard pause"
        detail = "Cycle packet has hard-pause reasons that must be cleared first."
    elif any("stale" in str(reason).lower() for reason in blockers):
        status = "stale"
        tone = "bad"
        label = "Refresh required"
        detail = "Agentic queue, cycle, or ticket data is too old for live review."
    elif str(entry_gate.get("status") or "").lower() == "blocked":
        status = "blocked"
        tone = "warn"
        label = "Entry gate blocked"
        detail = "Fresh live entries are review-only until validation/risk blockers clear."
    elif ticket_rows:
        status = "blocked"
        tone = "bad"
        label = "Legacy ticket blocked"
        detail = "Legacy staged-ticket files are inspection-only. Build one fresh, expiring packet in Trade Desk."
    elif queue.get("status") == "ready":
        status = "queue_ready"
        tone = "review"
        label = "Manual shortlist ready"
        detail = (
            "Research candidates exist; choose one and rebuild it in Trade Desk after live checks."
        )
    else:
        status = "idle"
        tone = "neutral"
        label = "No staged ticket"
        detail = "Refresh the research-only Robinhood shortlist after the latest scan."

    decision = build_agentic_decision_journal(data_dir, limit=10)
    decision_recent_count = int(_float_value(decision.get("recent_count"), default=0.0))
    decision_debt_reasons: list[str] = []
    if decision_recent_count == 0:
        if ticket_rows:
            decision_debt_reasons.append(
                "staged live ticket has not been recorded as reviewed, skipped, or paper-tracked"
            )
        if active_paper:
            decision_debt_reasons.append(
                "local paper position has not been recorded as held, closed, or reviewed"
            )
        if queue.get("orders"):
            decision_debt_reasons.append(
                "agentic queue candidate has not been recorded in the local decision journal"
            )
        elif cycle.get("review_only_entry_candidates"):
            decision_debt_reasons.append(
                "review-only entry candidate has not been recorded in the local decision journal"
            )
    decision_log_needed = bool(decision_debt_reasons)
    if decision_log_needed:
        freshness_warnings.append(
            "local decision journal has no recent review rows for current queue/ticket/paper state"
        )

    next_actions = []
    if status == "disabled":
        next_actions.append(
            {
                "label": "Review kill switch",
                "action": "review_kill_switch",
                "detail": "Remove agentic_trading_disabled.flag only after you intentionally want local paper/review flow back on.",
            }
        )
    if status == "stale":
        next_actions.append(
            {
                "label": "Refresh manual review packet",
                "action": "refresh_autopilot_packet",
                "detail": "Rebuild the research-only queue and cycle packet from the latest Optedge scan.",
            }
        )
    if status in {"idle", "queue_ready"}:
        next_actions.append(
            {
                "label": "Refresh manual shortlist",
                "action": "build_autopilot_packet",
                "detail": "Write the research-only queue/cycle, then choose one candidate for Trade Desk.",
            }
        )
    if str(entry_gate.get("status") or "").lower() == "blocked":
        next_actions.append(
            {
                "label": "Review validation blockers",
                "action": "review_validation",
                "detail": "Keep fresh entries blocked until drawdown, win-rate, and guardrail warnings improve.",
            }
        )
    if broker_status in {"missing_snapshot", "mismatch", "review"}:
        next_actions.append(
            {
                "label": "Review broker sync",
                "action": "review_broker_sync",
                "detail": "Compare broker positions with Optedge/local paper before any new entry or exit action.",
            }
        )
    if decision_log_needed:
        next_actions.append(
            {
                "label": "Log local decision",
                "action": "log_decision",
                "detail": "Record reviewed, skipped, held, or closed so the next cycle knows what actually happened.",
            }
        )
    if ticket_rows:
        next_actions.append(
            {
                "label": "Remove legacy ticket",
                "action": "review_ticket",
                "detail": "Treat the staged file as inspection-only and rebuild from Trade Desk; never execute it.",
            }
        )
    if active_paper:
        next_actions.append(
            {
                "label": "Review paper position",
                "action": "review_paper_book",
                "detail": "Compare local paper entry against latest exit pressure and decide hold/skip/close in the journal.",
            }
        )

    paper_book_rows, paper_book_summary = _agentic_paper_book(active_paper, open_positions)

    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "status": status,
        "tone": tone,
        "label": label,
        "detail": detail,
        "queue_status": _clean_value(queue.get("status")),
        "queue_generated_at": _clean_value(queue.get("generated_at")),
        "cycle_generated_at": _clean_value(cycle.get("generated_at")),
        "queue_age_minutes": round(queue_age, 1) if queue_age is not None else None,
        "cycle_age_minutes": round(cycle_age, 1) if cycle_age is not None else None,
        "ticket_packet_age_minutes": round(ticket_packet_age, 1)
        if ticket_packet_age is not None
        else None,
        "queue_freshness": queue_freshness,
        "cycle_freshness": cycle_freshness,
        "ticket_packet_freshness": ticket_packet_freshness,
        "queue_age": _short_age_label(queue_age),
        "cycle_age": _short_age_label(cycle_age),
        "ticket_packet_age": _short_age_label(ticket_packet_age),
        "entry_gate_status": _clean_value(entry_gate.get("status")),
        "entry_gate_label": _clean_value(entry_gate.get("label")),
        "fresh_entries_allowed": (
            entry_gate.get("new_entries_allowed_after_live_checks") is True and not blockers
        ),
        "auto_submit_allowed": bool(cycle.get("auto_submit_allowed")),
        "hard_pause": bool(cycle.get("hard_pause")),
        "kill_switch": kill_switch,
        "candidate_count": len(queue.get("orders") or []),
        "review_only_entry_candidate_count": len(cycle.get("review_only_entry_candidates") or []),
        "manual_review_candidate_count": len(cycle.get("manual_review_candidates") or []),
        "gated_entry_candidate_count": len(cycle.get("entry_candidates") or []),
        "live_ticket_count": len(tickets),
        "paper_open_count": len(active_paper),
        "paper_book_summary": paper_book_summary,
        "broker_reconciliation_status": broker_reconciliation.get("status"),
        "broker_reconciliation_label": broker_reconciliation.get("label"),
        "broker_snapshot_age": broker_reconciliation.get("snapshot_age"),
        "broker_option_count": broker_reconciliation.get("broker_option_count"),
        "broker_matched_count": broker_reconciliation.get("matched_count"),
        "broker_only_count": broker_reconciliation.get("broker_only_count"),
        "local_only_count": broker_reconciliation.get("local_only_count"),
        "research_lifecycle_option_count": broker_reconciliation.get(
            "research_lifecycle_option_count"
        ),
        "research_lifecycle_active_count": broker_reconciliation.get(
            "research_lifecycle_active_count"
        ),
        "research_lifecycle_expired_count": broker_reconciliation.get(
            "research_lifecycle_expired_count"
        ),
        "paper_only_count": broker_reconciliation.get("paper_only_count"),
        "local_expired_count": broker_reconciliation.get("local_expired_count"),
        "paper_expired_count": broker_reconciliation.get("paper_expired_count"),
        "broker_missing_contract_fields_count": broker_reconciliation.get(
            "missing_contract_fields_count"
        ),
        "agentic_option_ready": broker_reconciliation.get("agentic_option_ready"),
        "agentic_readiness_status": broker_reconciliation.get("agentic_readiness_status"),
        "agentic_readiness_label": broker_reconciliation.get("agentic_readiness_label"),
        "agentic_readiness_detail": broker_reconciliation.get("agentic_readiness_detail"),
        "funded_agentic_option_count": broker_reconciliation.get("funded_agentic_option_count"),
        "decision_recent_count": decision_recent_count,
        "decision_log_needed": decision_log_needed,
        "decision_debt_reasons": decision_debt_reasons[:6],
        "blockers": blockers[:10],
        "warnings": (freshness_warnings + [str(x) for x in gate_warnings if str(x).strip()])[:10],
        "next_actions": next_actions[:5],
        "files": {
            "paper_positions": str(data_dir / "agentic_paper_positions.json"),
            "paper_orders": str(data_dir / "agentic_paper_orders.jsonl"),
            "live_tickets": str(data_dir / "robinhood_live_order_tickets.json"),
            "queue": str(data_dir / "robinhood_agentic_queue.json"),
            "cycle": str(data_dir / "robinhood_agentic_cycle.json"),
            "decision_log": str(data_dir / "robinhood_agentic_decisions.jsonl"),
        },
        "tickets": ticket_rows,
        "ticket_preflight": preflight_rows[:80],
        "ticket_preflight_block_count": ticket_preflight_blocks,
        "ticket_preflight_warn_count": ticket_preflight_warnings,
        "paper_positions": paper_book_rows,
        "manual_review_candidates": (cycle.get("manual_review_candidates") or [])[:5],
        "broker_reconciliation": broker_reconciliation,
        "broker_reconciliation_rows": broker_reconciliation.get("rows") or [],
        "account_readiness_rows": broker_reconciliation.get("account_readiness_rows") or [],
        "robinhood_mcp_capabilities": broker_reconciliation.get("robinhood_mcp_capabilities") or [],
        "recent_decisions": decision.get("rows") or [],
        "notes": [
            "Local paper simulation may update automatically; it never starts a Codex task or submits a broker order.",
            "Legacy live-ticket files are blocked; only Trade Desk can build a fresh one-order review packet.",
        ],
    }


def build_agentic_decision_journal(data_dir: Path = DATA_DIR, limit: int = 25) -> dict[str, Any]:
    """Return the local Robinhood/Codex review decision journal."""
    summary = decision_log_summary(data_dir, limit=limit)
    rows = summary.get("latest") if isinstance(summary.get("latest"), list) else []
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "path": summary.get("path"),
        "exists": summary.get("exists"),
        "recent_count": summary.get("recent_count"),
        "action_counts": summary.get("action_counts") or {},
        "allowed_decisions": summary.get("allowed_decisions") or [],
        "rows": [{k: _clean_value(v) for k, v in row.items()} for row in rows],
        "notes": summary.get("notes")
        or [
            "This journal records local review outcomes only.",
            "It is not broker confirmation and does not place trades.",
        ],
    }


def record_agentic_decision(decision: dict[str, Any], data_dir: Path = DATA_DIR) -> dict[str, Any]:
    """Append one local Robinhood/Codex review decision and return the refreshed journal."""
    decision = decision if isinstance(decision, dict) else {}
    try:
        queue = build_robinhood_queue(
            data_dir=data_dir, account_budget=500, min_dte=MIN_SWING_OPTION_DTE
        )
        packet = build_agentic_cycle_packet(queue, data_dir)
        gate = packet.get("entry_gate") if isinstance(packet.get("entry_gate"), dict) else {}
    except Exception:
        gate = {}
    enriched = dict(decision)
    enriched.setdefault("entry_gate_status", gate.get("status"))
    enriched.setdefault("source", "local_cockpit")
    append_agent_decision(enriched, data_dir=data_dir)
    out = build_agentic_decision_journal(data_dir)
    out["ok"] = True
    out["message"] = "Decision logged locally."
    return out


def build_opportunities(
    data_dir: Path = DATA_DIR,
    asset: str = "all",
    query: str = "",
    status: str = "all",
    min_confidence: float = 0.0,
    limit: int = 80,
) -> dict[str, Any]:
    selected = list(OPPORTUNITY_SPECS) if asset == "all" else [asset]
    query_norm = str(query or "").strip().upper()
    status_norm = str(status or "all").strip().lower()
    rows: list[pd.DataFrame] = []
    sources: dict[str, str | None] = {}

    for asset_name in selected:
        spec = OPPORTUNITY_SPECS.get(asset_name)
        if spec is None:
            continue
        path = _latest_file(data_dir, spec["pattern"])
        sources[asset_name] = path.name if path else None
        df = _read_parquet(path)
        if df.empty:
            continue
        out = df.copy()
        out["asset"] = asset_name
        out["actionable"] = out.apply(_is_actionable, axis=1)
        out["_opportunity_score"] = out.apply(_opportunity_score, axis=1)
        if "confidence" in out.columns:
            out = out[
                pd.to_numeric(out["confidence"], errors="coerce").fillna(0.0) >= min_confidence
            ]
        elif min_confidence > 0:
            out = out.iloc[0:0]
        if query_norm:
            symbol_col = str(spec["symbol_col"])
            symbol_match = (
                out[symbol_col]
                .astype(str)
                .str.upper()
                .str.contains(query_norm, na=False, regex=False)
                if symbol_col in out.columns
                else pd.Series(False, index=out.index)
            )
            headline_match = (
                out["top_headline"]
                .astype(str)
                .str.upper()
                .str.contains(query_norm, na=False, regex=False)
                if "top_headline" in out.columns
                else pd.Series(False, index=out.index)
            )
            out = out[symbol_match | headline_match]
        if status_norm == "actionable":
            out = out[out["actionable"]]
        elif status_norm != "all" and "trade_status" in out.columns:
            out = out[out["trade_status"].astype(str).str.lower() == status_norm]
        rows.append(out)

    if rows:
        combined = pd.concat(rows, ignore_index=True, sort=False)
        combined = combined.sort_values("_opportunity_score", ascending=False, kind="mergesort")
    else:
        combined = pd.DataFrame()

    records = []
    for asset_name in OPPORTUNITY_SPECS:
        part = (
            combined[combined["asset"] == asset_name]
            if "asset" in combined.columns
            else pd.DataFrame()
        )
        records.extend(_opportunity_records(part, asset_name, limit))
    records = sorted(
        records,
        key=lambda r: _float_value(
            r.get("rank_score")
            or r.get("fused_score")
            or r.get("futures_score")
            or r.get("value_score")
        ),
        reverse=True,
    )
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "asset": asset,
        "query": query,
        "status": status,
        "min_confidence": min_confidence,
        "count": len(records[:limit]),
        "sources": sources,
        "rows": records[:limit],
        "notes": [
            "Explorer reads the latest local top_* parquet snapshots.",
            "Actionable excludes Watch/Skip where sizing fields are present.",
            "This is research output only; no orders are placed.",
        ],
    }


@_memoized_report
def build_positions(
    data_dir: Path = DATA_DIR,
    asset: str = "all",
    query: str = "",
    status: str = "all",
    limit: int = 250,
) -> dict[str, Any]:
    selected = list(POSITION_FILES) if asset == "all" else [asset]
    query_norm = str(query or "").strip().upper()
    status_norm = str(status or "all").strip().lower()
    rows: list[dict[str, Any]] = []
    sources: dict[str, str | None] = {}

    for asset_name in selected:
        filename = POSITION_FILES.get(asset_name)
        if not filename:
            continue
        path = data_dir / filename
        raw = _read_json(path)
        sources[asset_name] = filename if path.exists() else None
        if not isinstance(raw, list):
            continue
        for item in raw:
            if isinstance(item, dict):
                rows.append(_normalize_position(item, asset_name))

    rows = _dedupe_position_rows(rows)
    if query_norm:
        rows = [
            row
            for row in rows
            if query_norm in str(row.get("ticker_or_symbol") or "").upper()
            or query_norm in str(row.get("position_label") or "").upper()
        ]
    if status_norm == "attention":
        rows = [row for row in rows if row.get("attention")]
    elif status_norm in {"active", "expired"}:
        rows = [row for row in rows if row.get("lifecycle_state") == status_norm]
    elif status_norm != "all":
        rows = [
            row
            for row in rows
            if str(row.get("trade_status") or "").strip().lower() == status_norm
            or str(row.get("latest_exit_action") or "").strip().lower() == status_norm
        ]
    rows = sorted(rows, key=_position_sort_key, reverse=True)
    limited = rows[:limit]
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "asset": asset,
        "query": query,
        "status": status,
        "count": len(limited),
        "total_before_limit": len(rows),
        "sources": sources,
        "rows": limited,
        "notes": [
            "Position monitor reads current open position state only.",
            "Attention means high exit pressure, repeated repricing trouble, or a large unrealized drawdown.",
            "This is research output only; no orders are placed.",
        ],
    }


def build_position_hygiene(data_dir: Path = DATA_DIR, limit: int = 120) -> dict[str, Any]:
    """Build a non-destructive cleanup/reconciliation plan for local position state."""
    data_dir = Path(data_dir)
    limit = max(1, min(int(limit or 120), 500))
    reconciliation = build_broker_reconciliation(data_dir, limit=500)
    open_positions = _read_json(data_dir / "open_positions.json")
    open_positions = open_positions if isinstance(open_positions, list) else []
    rows: list[dict[str, Any]] = []
    counts: dict[str, int] = {}

    def add(row: dict[str, Any]) -> None:
        status = str(row.get("status") or "unknown")
        counts[status] = counts.get(status, 0) + 1
        rows.append({k: _clean_value(v) for k, v in row.items()})

    for raw in reconciliation.get("rows") or []:
        if not isinstance(raw, dict):
            continue
        status = str(raw.get("status") or "")
        if status == "local_expired":
            add(
                {
                    "status": "local_expired",
                    "severity": "cleanup",
                    "action": "close_or_archive_expired_local_record",
                    "contract": raw.get("contract"),
                    "symbol": raw.get("symbol"),
                    "expiry": raw.get("expiry"),
                    "dte": raw.get("dte"),
                    "reason": "Option is past expiry but still appears in open_positions.json.",
                    "safe_next_step": "Run a fresh scan/reprice or review then move to closed history; do not treat as live exposure.",
                    "source": "open_positions.json",
                }
            )
        elif status == "broker_only":
            add(
                {
                    "status": "broker_only",
                    "severity": "broker_review",
                    "action": "import_or_mark_unmanaged_broker_position",
                    "contract": raw.get("contract"),
                    "symbol": raw.get("symbol"),
                    "expiry": raw.get("expiry"),
                    "quantity": raw.get("quantity"),
                    "reason": "Broker snapshot has an option position not tracked by Optedge or local paper.",
                    "safe_next_step": "Decide whether to import into local tracking or mark as unmanaged before new entries.",
                    "source": "robinhood_broker_snapshot.json",
                }
            )
        elif status == "local_only":
            add(
                {
                    "status": "local_only",
                    "severity": "sync_review",
                    "action": "verify_local_position_against_broker",
                    "contract": raw.get("contract"),
                    "symbol": raw.get("symbol"),
                    "expiry": raw.get("expiry"),
                    "dte": raw.get("dte"),
                    "latest_exit_action": raw.get("latest_exit_action"),
                    "latest_exit_pressure": raw.get("latest_exit_pressure"),
                    "reason": "Optedge says this is open, but the broker snapshot does not show it.",
                    "safe_next_step": "Confirm whether this was only a research recommendation, paper-only, or missing from broker snapshot.",
                    "source": "open_positions.json",
                }
            )
        elif status == "paper_only":
            add(
                {
                    "status": "paper_only",
                    "severity": "paper_review",
                    "action": "review_local_paper_position",
                    "contract": raw.get("contract"),
                    "symbol": raw.get("symbol"),
                    "expiry": raw.get("expiry"),
                    "dte": raw.get("dte"),
                    "reason": "Local paper book has a position that is not in the broker snapshot.",
                    "safe_next_step": "Log held/closed/skipped in the local decision journal.",
                    "source": "agentic_paper_positions.json",
                }
            )

    existing_contracts = {str(row.get("contract") or "") for row in rows}
    for pos in open_positions:
        if not isinstance(pos, dict):
            continue
        local_record = _agentic_local_option_record(pos, "optedge")
        contract = local_record.get("contract")
        dte = _float_value(local_record.get("dte"), default=math.nan)
        if math.isfinite(dte) and dte < 0:
            if str(contract or "") not in existing_contracts:
                add(
                    {
                        "status": "local_expired",
                        "severity": "cleanup",
                        "action": "close_or_archive_expired_local_record",
                        "contract": contract,
                        "symbol": local_record.get("symbol"),
                        "expiry": local_record.get("expiry"),
                        "dte": dte,
                        "reason": "Research lifecycle option is past expiry but still appears in open_positions.json.",
                        "safe_next_step": "Move it to closed research history; do not treat it as live broker exposure.",
                        "source": "open_positions.json",
                    }
                )
                existing_contracts.add(str(contract or ""))
            continue
        if str(contract or "") in existing_contracts:
            continue
        fail_count = int(_float_value(pos.get("reprice_failed_count"), default=0.0))
        latest_pressure = _float_value(pos.get("latest_exit_pressure"), default=0.0)
        if fail_count >= 20 or latest_pressure >= 60:
            add(
                {
                    "status": "repricing_or_exit_pressure",
                    "severity": "review",
                    "action": "refresh_quote_or_exit_review",
                    "contract": contract,
                    "symbol": pos.get("ticker") or pos.get("symbol"),
                    "expiry": pos.get("expiry"),
                    "reprice_failed_count": fail_count,
                    "latest_exit_action": pos.get("latest_exit_action"),
                    "latest_exit_pressure": _clean_value(pos.get("latest_exit_pressure")),
                    "reason": "Open position has repeated repricing trouble or elevated exit pressure.",
                    "safe_next_step": "Refresh quote/chain and log a hold, close, or stop update decision.",
                    "source": "open_positions.json",
                }
            )

    severity_rank = {
        "broker_review": 5,
        "cleanup": 4,
        "sync_review": 3,
        "paper_review": 2,
        "review": 1,
    }
    rows = sorted(
        rows,
        key=lambda row: (
            severity_rank.get(str(row.get("severity") or ""), 0),
            -_float_value(row.get("dte"), default=9999.0),
            str(row.get("contract") or ""),
        ),
        reverse=True,
    )
    plan_path = data_dir / "position_hygiene_plan.json"
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "status": "needs_review" if rows else "clean",
        "plan_path": str(plan_path),
        "open_option_count": len(open_positions),
        "broker_reconciliation_status": reconciliation.get("status"),
        "broker_option_count": reconciliation.get("broker_option_count"),
        "broker_only_count": reconciliation.get("broker_only_count"),
        "local_only_count": reconciliation.get("local_only_count"),
        "research_lifecycle_option_count": reconciliation.get("research_lifecycle_option_count"),
        "local_expired_count": counts.get("local_expired", 0),
        "paper_only_count": reconciliation.get("paper_only_count"),
        "paper_expired_count": reconciliation.get("paper_expired_count"),
        "action_count": len(rows),
        "counts": counts,
        "rows": rows[:limit],
        "notes": [
            "This is a review plan only; it does not delete, move, close, or place broker orders.",
            "Expired local positions should be closed by the lifecycle tracker on the next scan/reprice pass.",
            "Broker-only rows should be imported or marked unmanaged before trusting live-ticket actions.",
        ],
    }


def write_position_hygiene_plan(data_dir: Path = DATA_DIR) -> dict[str, Any]:
    report = build_position_hygiene(data_dir, limit=500)
    path = Path(report["plan_path"])
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(report, indent=2, sort_keys=True), encoding="utf-8")
    report["wrote_file"] = True
    report["path"] = str(path)
    return report


def _hygiene_backup_path(path: Path, asof: datetime) -> Path:
    stamp = asof.strftime("%Y%m%d_%H%M%S")
    base = path.with_name(f"{path.stem}.hygiene_backup_{stamp}{path.suffix}")
    candidate = base
    index = 1
    while candidate.exists():
        candidate = path.with_name(f"{path.stem}.hygiene_backup_{stamp}_{index:02d}{path.suffix}")
        index += 1
    return candidate


def _option_is_expired_for_hygiene(position: dict[str, Any], asof: datetime) -> bool:
    if not isinstance(position, dict):
        return False
    expiry_value = position.get("expiry") or position.get("expiration_date")
    expiry_dt = _parse_iso_utc(expiry_value)
    if expiry_dt is None:
        return False
    if isinstance(expiry_value, str) and "T" not in expiry_value:
        return asof.date() > expiry_dt.date()
    return asof >= expiry_dt


def _option_hygiene_close_row(
    position: dict[str, Any],
    asof: datetime,
    expiry_valuations: dict[str, dict[str, Any]] | None = None,
) -> dict[str, Any]:
    from backtest.positions import build_expired_close_row

    closed = build_expired_close_row(position, asof, expiry_valuations)
    contract = _agentic_local_option_record(position, "optedge").get("contract")
    closed.update(
        {
            "asset": position.get("asset") or "option",
            "hygiene_applied_at": asof.isoformat(),
            "hygiene_source": "position_hygiene",
            "hygiene_contract": contract,
            "hygiene_exit_price_source": closed.get("expiry_close_price_source"),
            "hygiene_note": (
                "Moved from open_positions.json by local hygiene because the option expiry "
                "date is in the past. Expiration value is source-labeled and unresolved "
                "outcomes do not receive fabricated P&L."
            ),
        }
    )
    return {k: _clean_value(v) for k, v in closed.items()}


def _atomic_json_list_write(path: Path, rows: list[Any]) -> None:
    temp = path.with_suffix(path.suffix + ".tmp")
    temp.write_text(json.dumps(rows, indent=2, sort_keys=True), encoding="utf-8")
    temp.replace(path)
    verified = _read_json(path)
    if not isinstance(verified, list) or verified != rows:
        raise OSError(f"atomic JSON verification failed for {path.name}")


def _restore_file_bytes(path: Path, original: bytes | None) -> None:
    if original is None:
        path.unlink(missing_ok=True)
        return
    temp = path.with_suffix(path.suffix + ".rollback.tmp")
    temp.write_bytes(original)
    temp.replace(path)


def apply_position_hygiene(
    data_dir: Path = DATA_DIR,
    *,
    apply: bool = False,
    limit: int = 120,
    history_fetcher: Any = None,
    fetch_expiry_history: bool = True,
) -> dict[str, Any]:
    """Preview or apply safe local cleanup for expired option records."""
    data_dir = Path(data_dir)
    limit = max(1, min(int(limit or 120), 500))
    asof = datetime.now(UTC)
    open_path = data_dir / "open_positions.json"
    closed_path = data_dir / "closed_positions.json"
    open_rows_raw = _read_json(open_path)
    closed_rows_raw = _read_json(closed_path)
    invalid_state = []
    if open_path.exists() and not isinstance(open_rows_raw, list):
        invalid_state.append(f"{open_path.name} exists but is not a valid JSON list")
    if closed_path.exists() and not isinstance(closed_rows_raw, list):
        invalid_state.append(f"{closed_path.name} exists but is not a valid JSON list")
    if invalid_state:
        return {
            "generated_at": asof.isoformat(),
            "status": "blocked",
            "apply": bool(apply),
            "wrote_files": False,
            "open_path": str(open_path),
            "closed_path": str(closed_path),
            "backup_paths": [],
            "error": "; ".join(invalid_state),
            "rows": [],
            "notes": [
                "Repair or restore the malformed lifecycle file before hygiene can continue."
            ],
        }
    open_rows = open_rows_raw if isinstance(open_rows_raw, list) else []
    closed_rows = closed_rows_raw if isinstance(closed_rows_raw, list) else []

    expired_positions: list[dict[str, Any]] = []
    still_open: list[dict[str, Any]] = []
    for position in open_rows:
        if isinstance(position, dict) and _option_is_expired_for_hygiene(position, asof):
            expired_positions.append(position)
        else:
            still_open.append(position)

    expiry_valuations: dict[str, dict[str, Any]] = {}
    if expired_positions and fetch_expiry_history:
        try:
            from backtest.option_expiry import resolve_expiry_valuations

            expiry_valuations = resolve_expiry_valuations(
                expired_positions,
                asof=asof,
                history_fetcher=history_fetcher,
                option_history_path=data_dir / "robinhood_option_history_snapshot.json",
            )
        except Exception:
            expiry_valuations = {}

    expired_rows = [
        _option_hygiene_close_row(position, asof, expiry_valuations)
        for position in expired_positions
    ]
    preview_rows: list[dict[str, Any]] = []
    for position, closed in zip(expired_positions, expired_rows, strict=False):
        record = _agentic_local_option_record(position, "optedge")
        preview_rows.append(
            {
                "contract": record.get("contract"),
                "symbol": record.get("symbol"),
                "expiry": record.get("expiry"),
                "dte": record.get("dte"),
                "entry_price": _clean_value(position.get("entry_price")),
                "exit_price": closed.get("exit_price"),
                "pnl_pct": closed.get("pnl_pct"),
                "exit_reason": closed.get("exit_reason"),
                "price_source": closed.get("expiry_close_price_source"),
                "underlying_price": closed.get("expiry_underlying_price"),
                "underlying_price_date": closed.get("expiry_underlying_price_date"),
                "outcome_quality": closed.get("outcome_quality"),
                "validation_eligible": closed.get("validation_eligible"),
                "action": "move_to_closed_positions"
                if apply
                else "preview_move_to_closed_positions",
                "note": closed.get("hygiene_note"),
            }
        )

    from backtest.positions import merge_closed_rows

    merged_closed, added_closed, duplicate_count = merge_closed_rows(
        closed_rows,
        expired_rows,
    )
    source_counts: dict[str, int] = {}
    for row in expired_rows:
        source = str(row.get("expiry_close_price_source") or "unknown")
        source_counts[source] = source_counts.get(source, 0) + 1
    unresolved_count = sum(1 for row in expired_rows if row.get("exit_price") is None)

    backup_paths: list[str] = []
    wrote_files = False
    apply_error: str | None = None
    if apply and expired_rows:
        data_dir.mkdir(parents=True, exist_ok=True)
        originals = {
            open_path: open_path.read_bytes() if open_path.exists() else None,
            closed_path: closed_path.read_bytes() if closed_path.exists() else None,
        }
        for path in (open_path, closed_path):
            if path.exists():
                backup = _hygiene_backup_path(path, asof)
                shutil.copy2(path, backup)
                backup_paths.append(str(backup))
        try:
            # Commit history first so an expired row is never removed from the
            # open book without a durable outcome record.
            _atomic_json_list_write(closed_path, merged_closed)
            _atomic_json_list_write(open_path, still_open)
            wrote_files = True
        except Exception as exc:
            apply_error = f"Lifecycle transaction failed and was rolled back: {exc}"
            rollback_errors: list[str] = []
            for path, original in originals.items():
                try:
                    _restore_file_bytes(path, original)
                except Exception as rollback_exc:
                    rollback_errors.append(f"{path.name}: {rollback_exc}")
            if rollback_errors:
                raise RuntimeError(
                    apply_error + "; rollback also failed: " + "; ".join(rollback_errors)
                ) from exc

    validation_refreshed = False
    if wrote_files and data_dir.resolve() == DATA_DIR.resolve():
        try:
            from reports.validation_report import write_report

            write_report(scope="current_model")
            validation_refreshed = True
        except Exception:
            validation_refreshed = False

    report = {
        "generated_at": asof.isoformat(),
        "status": (
            "applied"
            if wrote_files
            else "failed"
            if apply_error
            else "preview"
            if expired_rows
            else "clean"
        ),
        "apply": bool(apply),
        "wrote_files": wrote_files,
        "error": apply_error,
        "open_path": str(open_path),
        "closed_path": str(closed_path),
        "backup_paths": backup_paths,
        "open_before": len(open_rows),
        "open_after": len(still_open) if wrote_files else len(open_rows),
        "closed_before": len(closed_rows),
        "closed_after": len(merged_closed) if wrote_files else len(closed_rows),
        "projected_closed_after": len(merged_closed),
        "expired_to_close_count": len(expired_rows),
        "new_closed_count": len(added_closed),
        "deduped_existing_closed_count": duplicate_count,
        "unresolved_expiry_count": unresolved_count,
        "expiry_price_source_counts": source_counts,
        "validation_refreshed": validation_refreshed,
        "rows": preview_rows[:limit],
        "notes": [
            "Only expired local option records are eligible for this cleanup.",
            "Preview mode does not modify files.",
            "Apply mode backs up open_positions.json and closed_positions.json before writing.",
            "Expiration value prefers the underlying expiration-session close, then an exact broker option bar.",
            "Unresolved expiration values move out of open state but keep P&L null and validation-ineligible.",
            "This does not place broker orders or claim a broker close.",
        ],
    }
    if apply and not expired_rows:
        report["notes"].append(
            "No expired local option records were found, so no files were changed."
        )
    return report


def _exit_review_symbol(row: dict[str, Any]) -> str:
    return str(row.get("ticker") or row.get("symbol") or row.get("ticker_or_symbol") or "-").upper()


def _exit_review_position_key(row: dict[str, Any]) -> str:
    position_id = str(row.get("position_id") or "").strip()
    if position_id:
        return position_id
    return f"{row.get('asset') or 'unknown'}:{row.get('ticker_or_symbol') or '-'}"


def _exit_action_priority(action: Any) -> int:
    clean = str(action or "").strip().lower()
    if clean in {"hard_stop", "expired"}:
        return 100
    if clean in {"hard_target", "close_early"}:
        return 90
    if clean == "tighten_stop":
        return 75
    if clean == "watch":
        return 55
    if clean == "hold":
        return 20
    return 30


def _read_exit_review_rows(data_dir: Path = DATA_DIR) -> list[dict[str, Any]]:
    path = Path(data_dir) / "exit_reviews.jsonl"
    if not path.exists() or not path.is_file():
        return []
    rows: list[dict[str, Any]] = []
    try:
        lines = path.read_text(encoding="utf-8-sig", errors="replace").splitlines()
    except Exception:
        return []
    for line in lines:
        clean = line.strip()
        if not clean:
            continue
        try:
            row = json.loads(clean)
        except Exception:
            continue
        if isinstance(row, dict):
            rows.append(row)
    return rows


def build_exit_review_summary(
    data_dir: Path = DATA_DIR,
    asset: str = "all",
    query: str = "",
    limit: int = 80,
) -> dict[str, Any]:
    """Summarize dynamic exit-review decisions logged by the lifecycle trackers."""
    asset_norm = str(asset or "all").strip().lower()
    if asset_norm not in {"all", "option", "share", "futures"}:
        asset_norm = "all"
    query_norm = str(query or "").strip().upper()
    limit = max(1, min(int(limit or 80), 500))
    raw_rows = _read_exit_review_rows(data_dir)
    rows: list[dict[str, Any]] = []

    for raw in raw_rows:
        row_asset = str(raw.get("asset") or "unknown").strip().lower()
        symbol = _exit_review_symbol(raw)
        if asset_norm != "all" and row_asset != asset_norm:
            continue
        position_id = str(raw.get("position_id") or "")
        if query_norm and query_norm not in symbol and query_norm not in position_id.upper():
            continue
        reasons = raw.get("reasons") if isinstance(raw.get("reasons"), list) else []
        row = {
            "timestamp": _clean_value(raw.get("timestamp")),
            "asset": row_asset,
            "ticker_or_symbol": symbol,
            "position_id": _clean_value(raw.get("position_id")),
            "action": _clean_value(raw.get("action") or "unknown"),
            "exit_pressure": _clean_value(raw.get("exit_pressure")),
            "current_pnl_pct": _clean_value(raw.get("current_pnl_pct")),
            "current_pnl_dollars": _clean_value(raw.get("current_pnl_dollars")),
            "current_price": _clean_value(raw.get("current_price")),
            "old_stop": _clean_value(raw.get("old_stop")),
            "new_stop": _clean_value(raw.get("new_stop")),
            "old_target": _clean_value(raw.get("old_target")),
            "new_target": _clean_value(raw.get("new_target")),
            "entry_confidence": _clean_value(raw.get("entry_confidence")),
            "current_confidence": _clean_value(raw.get("current_confidence")),
            "used_learned_policy": bool(raw.get("used_learned_policy", False)),
            "policy_version": _clean_value(raw.get("policy_version")),
            "reasons": [_clean_value(reason) for reason in reasons[:6]],
            "reasons_text": "; ".join(str(reason) for reason in reasons[:4] if reason) or "-",
        }
        rows.append(row)

    rows = sorted(rows, key=lambda row: str(row.get("timestamp") or ""), reverse=True)
    action_counts: dict[str, int] = {}
    asset_counts: dict[str, int] = {}
    symbol_rollup: dict[str, dict[str, Any]] = {}
    latest_by_position: dict[str, dict[str, Any]] = {}
    pressures: list[float] = []
    learned_count = 0
    high_pressure_count = 0
    for row in rows:
        action = str(row.get("action") or "unknown")
        row_asset = str(row.get("asset") or "unknown")
        symbol = str(row.get("ticker_or_symbol") or "-").upper()
        pressure = _float_value(row.get("exit_pressure"), default=math.nan)
        action_counts[action] = action_counts.get(action, 0) + 1
        asset_counts[row_asset] = asset_counts.get(row_asset, 0) + 1
        if row.get("used_learned_policy"):
            learned_count += 1
        if math.isfinite(pressure):
            pressures.append(pressure)
            if pressure >= 80:
                high_pressure_count += 1
        sym = symbol_rollup.setdefault(
            symbol,
            {
                "ticker_or_symbol": symbol,
                "asset": row_asset,
                "review_count": 0,
                "latest_action": action,
                "latest_timestamp": row.get("timestamp"),
                "max_exit_pressure": None,
                "latest_reasons": row.get("reasons_text"),
            },
        )
        sym["review_count"] += 1
        current_max = _float_value(sym.get("max_exit_pressure"), default=math.nan)
        if math.isfinite(pressure) and (not math.isfinite(current_max) or pressure > current_max):
            sym["max_exit_pressure"] = pressure
        if str(row.get("timestamp") or "") >= str(sym.get("latest_timestamp") or ""):
            sym["latest_action"] = action
            sym["latest_timestamp"] = row.get("timestamp")
            sym["latest_reasons"] = row.get("reasons_text")
            sym["asset"] = row_asset
        position_key = _exit_review_position_key(row)
        current = latest_by_position.get(position_key)
        if current is None or str(row.get("timestamp") or "") >= str(
            current.get("timestamp") or ""
        ):
            latest_by_position[position_key] = dict(row, decision_key=position_key)

    by_symbol = sorted(
        symbol_rollup.values(),
        key=lambda row: (
            _float_value(row.get("max_exit_pressure"), default=0.0),
            int(row.get("review_count") or 0),
            str(row.get("latest_timestamp") or ""),
        ),
        reverse=True,
    )[:15]
    current_decisions = []
    for row in latest_by_position.values():
        action = str(row.get("action") or "unknown")
        decision = {
            "decision_key": _clean_value(row.get("decision_key")),
            "timestamp": _clean_value(row.get("timestamp")),
            "asset": _clean_value(row.get("asset")),
            "ticker_or_symbol": _clean_value(row.get("ticker_or_symbol")),
            "position_id": _clean_value(row.get("position_id")),
            "latest_action": _clean_value(action),
            "exit_pressure": _clean_value(row.get("exit_pressure")),
            "current_pnl_pct": _clean_value(row.get("current_pnl_pct")),
            "current_pnl_dollars": _clean_value(row.get("current_pnl_dollars")),
            "current_price": _clean_value(row.get("current_price")),
            "old_stop": _clean_value(row.get("old_stop")),
            "new_stop": _clean_value(row.get("new_stop")),
            "used_learned_policy": bool(row.get("used_learned_policy", False)),
            "policy_version": _clean_value(row.get("policy_version")),
            "reasons_text": _clean_value(row.get("reasons_text")),
            "decision_priority": _exit_action_priority(action),
        }
        current_decisions.append(decision)
    current_decisions = sorted(
        current_decisions,
        key=lambda row: (
            _exit_action_priority(row.get("latest_action")),
            _float_value(row.get("exit_pressure"), default=0.0),
            str(row.get("timestamp") or ""),
        ),
        reverse=True,
    )
    current_action_counts: dict[str, int] = {}
    for row in current_decisions:
        action = str(row.get("latest_action") or "unknown")
        current_action_counts[action] = current_action_counts.get(action, 0) + 1
    avg_pressure = (sum(pressures) / len(pressures)) if pressures else None
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "asset": asset_norm,
        "query": query,
        "source": "exit_reviews.jsonl"
        if (Path(data_dir) / "exit_reviews.jsonl").exists()
        else None,
        "count": len(rows[:limit]),
        "total_before_limit": len(rows),
        "action_counts": action_counts,
        "asset_counts": asset_counts,
        "high_pressure_count": high_pressure_count,
        "learned_policy_count": learned_count,
        "current_decision_count": len(current_decisions),
        "current_high_pressure_count": sum(
            _float_value(row.get("exit_pressure"), default=0.0) >= 80 for row in current_decisions
        ),
        "current_action_counts": current_action_counts,
        "avg_exit_pressure": _clean_value(
            round(avg_pressure, 2) if avg_pressure is not None else None
        ),
        "latest_timestamp": rows[0].get("timestamp") if rows else None,
        "by_symbol": [{k: _clean_value(v) for k, v in row.items()} for row in by_symbol],
        "current_decisions": [
            {k: _clean_value(v) for k, v in row.items()} for row in current_decisions[:25]
        ],
        "rows": [{k: _clean_value(v) for k, v in row.items()} for row in rows[:limit]],
        "notes": [
            "Exit reviews are local lifecycle decisions logged after every scan.",
            "Hard stops, targets, and expirations still take priority over dynamic review actions.",
            "This panel is decision support only and does not place trades.",
        ],
    }


def _history_close_series(df: pd.DataFrame) -> pd.Series:
    if df is None or df.empty or "Close" not in df.columns:
        return pd.Series(dtype="float64")
    close = pd.to_numeric(df["Close"], errors="coerce").dropna()
    return close[close > 0]


def _history_last_date(df: pd.DataFrame, close: pd.Series) -> str | None:
    if close.empty:
        return None
    idx = close.index[-1]
    if hasattr(idx, "date"):
        try:
            return str(idx.date())
        except Exception:
            pass
    if df is not None and not df.empty and "Date" in df.columns:
        try:
            return str(df.loc[idx, "Date"])
        except Exception:
            try:
                return str(df["Date"].dropna().iloc[-1])
            except Exception:
                return None
    return None


def _period_return(close: pd.Series, periods: int) -> float | None:
    if len(close) <= periods:
        return None
    end = _float_value(close.iloc[-1], default=math.nan)
    start = _float_value(close.iloc[-1 - periods], default=math.nan)
    if not (math.isfinite(end) and math.isfinite(start)) or start <= 0:
        return None
    return (end / start) - 1.0


def _realized_vol_20d(close: pd.Series) -> float | None:
    if len(close) < 22:
        return None
    returns = close.pct_change().dropna().tail(20)
    if returns.empty:
        return None
    vol = float(returns.std()) * math.sqrt(252.0)
    return vol if math.isfinite(vol) else None


def _market_trend_label(ret_5d: float | None, ret_20d: float | None) -> str:
    r5 = ret_5d if ret_5d is not None else 0.0
    r20 = ret_20d if ret_20d is not None else 0.0
    if r5 > 0.01 and r20 > 0.02:
        return "uptrend"
    if r5 < -0.01 and r20 < -0.02:
        return "downtrend"
    if r20 > 0.02:
        return "constructive"
    if r20 < -0.02:
        return "weak"
    return "mixed"


def _market_pulse_row(spec: dict[str, Any], history: pd.DataFrame) -> dict[str, Any]:
    close = _history_close_series(history)
    if close.empty:
        return {
            "symbol": spec["symbol"],
            "label": spec["label"],
            "kind": spec["kind"],
            "status": "missing",
            "trend": "unknown",
            "note": "No free history returned.",
        }
    ret_5d = _period_return(close, 5)
    ret_20d = _period_return(close, 20)
    ret_60d = _period_return(close, 60)
    vol_20d = _realized_vol_20d(close)
    trend = _market_trend_label(ret_5d, ret_20d)
    last_date = _history_last_date(history, close)
    return {
        "symbol": spec["symbol"],
        "label": spec["label"],
        "kind": spec["kind"],
        "status": "ok",
        "last_close": _clean_value(round(_float_value(close.iloc[-1]), 4)),
        "ret_5d": _clean_value(ret_5d),
        "ret_20d": _clean_value(ret_20d),
        "ret_60d": _clean_value(ret_60d),
        "vol_20d": _clean_value(vol_20d),
        "trend": trend,
        "rows": int(len(close)),
        "last_date": last_date,
    }


def _sector_strength_score(
    ret_20d: float | None,
    ret_60d: float | None,
    vol_20d: float | None,
) -> float:
    r20 = ret_20d if ret_20d is not None and math.isfinite(ret_20d) else 0.0
    r60 = ret_60d if ret_60d is not None and math.isfinite(ret_60d) else 0.0
    vol = vol_20d if vol_20d is not None and math.isfinite(vol_20d) else 0.0
    return (0.65 * r20) + (0.35 * r60) - (0.10 * vol)


def _sector_pulse_row(spec: dict[str, Any], history: pd.DataFrame) -> dict[str, Any]:
    close = _history_close_series(history)
    if close.empty:
        return {
            "symbol": spec["symbol"],
            "sector": spec["sector"],
            "group": spec["group"],
            "status": "missing",
            "trend": "unknown",
            "note": "No free history returned.",
        }
    ret_5d = _period_return(close, 5)
    ret_20d = _period_return(close, 20)
    ret_60d = _period_return(close, 60)
    vol_20d = _realized_vol_20d(close)
    trend = _market_trend_label(ret_5d, ret_20d)
    last_date = _history_last_date(history, close)
    strength = _sector_strength_score(ret_20d, ret_60d, vol_20d)
    return {
        "symbol": spec["symbol"],
        "sector": spec["sector"],
        "group": spec["group"],
        "status": "ok",
        "last_close": _clean_value(round(_float_value(close.iloc[-1]), 4)),
        "ret_5d": _clean_value(ret_5d),
        "ret_20d": _clean_value(ret_20d),
        "ret_60d": _clean_value(ret_60d),
        "vol_20d": _clean_value(vol_20d),
        "trend": trend,
        "strength_score": _clean_value(round(strength, 4)),
        "rows": int(len(close)),
        "last_date": last_date,
    }


def _relative_return(numerator: pd.Series, denominator: pd.Series, periods: int) -> float | None:
    if len(numerator) <= periods or len(denominator) <= periods:
        return None
    n0 = _float_value(numerator.iloc[-1 - periods], default=math.nan)
    n1 = _float_value(numerator.iloc[-1], default=math.nan)
    d0 = _float_value(denominator.iloc[-1 - periods], default=math.nan)
    d1 = _float_value(denominator.iloc[-1], default=math.nan)
    if not all(math.isfinite(v) and v > 0 for v in (n0, n1, d0, d1)):
        return None
    return (n1 / n0) / (d1 / d0) - 1.0


def _breadth_signal_label(score: float) -> str:
    if score >= 0.015:
        return "supportive"
    if score <= -0.015:
        return "warning"
    return "neutral"


def _breadth_pulse_row(
    spec: dict[str, Any],
    histories: dict[str, pd.DataFrame],
) -> dict[str, Any]:
    numerator_symbol = str(spec["numerator"])
    denominator_symbol = str(spec["denominator"])
    numerator = _history_close_series(histories.get(numerator_symbol, pd.DataFrame()))
    denominator = _history_close_series(histories.get(denominator_symbol, pd.DataFrame()))
    if numerator.empty or denominator.empty:
        return {
            "label": spec["label"],
            "pair": f"{numerator_symbol}/{denominator_symbol}",
            "kind": spec["kind"],
            "status": "missing",
            "signal": "unknown",
            "note": "One or both free histories were unavailable.",
        }

    rel_5d = _relative_return(numerator, denominator, 5)
    rel_20d = _relative_return(numerator, denominator, 20)
    rel_60d = _relative_return(numerator, denominator, 60)
    raw_score = (
        0.15 * (rel_5d if rel_5d is not None and math.isfinite(rel_5d) else 0.0)
        + 0.55 * (rel_20d if rel_20d is not None and math.isfinite(rel_20d) else 0.0)
        + 0.30 * (rel_60d if rel_60d is not None and math.isfinite(rel_60d) else 0.0)
    )
    orientation = -1.0 if str(spec.get("bullish_when")) == "negative" else 1.0
    score = raw_score * orientation
    last_date = _history_last_date(histories.get(numerator_symbol, pd.DataFrame()), numerator)
    return {
        "label": spec["label"],
        "pair": f"{numerator_symbol}/{denominator_symbol}",
        "kind": spec["kind"],
        "status": "ok",
        "signal": _breadth_signal_label(score),
        "breadth_score": _clean_value(round(score, 4)),
        "relative_5d": _clean_value(rel_5d),
        "relative_20d": _clean_value(rel_20d),
        "relative_60d": _clean_value(rel_60d),
        "bullish_when": spec.get("bullish_when"),
        "description": spec.get("description"),
        "rows": int(min(len(numerator), len(denominator))),
        "last_date": last_date,
    }


def _breadth_regime_label(score: float, rows: list[dict[str, Any]]) -> str:
    supportive = sum(row.get("signal") == "supportive" for row in rows)
    warnings = sum(row.get("signal") == "warning" for row in rows)
    if score >= 0.025 and supportive >= warnings + 2:
        return "broad_risk_on"
    if score <= -0.025 or warnings > supportive:
        return "narrow_or_defensive"
    if supportive > warnings:
        return "selective_risk_on"
    return "mixed"


def _parse_cboe_put_call_csv(text: str, source: dict[str, Any]) -> dict[str, Any]:
    lines = [line for line in str(text or "").splitlines() if line.strip()]
    header_idx = next(
        (idx for idx, line in enumerate(lines) if line.upper().startswith("DATE,")), None
    )
    if header_idx is None:
        return {
            "key": source.get("key"),
            "label": source.get("label"),
            "status": "missing",
            "signal": "unknown",
            "note": "Cboe CSV header not found.",
        }
    try:
        df = pd.read_csv(io.StringIO("\n".join(lines[header_idx:])))
    except Exception as exc:
        return {
            "key": source.get("key"),
            "label": source.get("label"),
            "status": "error",
            "signal": "unknown",
            "note": f"Cboe CSV parse failed: {exc}",
        }
    if df.empty or "P/C Ratio" not in df.columns:
        return {
            "key": source.get("key"),
            "label": source.get("label"),
            "status": "missing",
            "signal": "unknown",
            "note": "Cboe CSV contained no put/call rows.",
        }
    call_col = "CALLS" if "CALLS" in df.columns else "CALL" if "CALL" in df.columns else ""
    put_col = "PUTS" if "PUTS" in df.columns else "PUT" if "PUT" in df.columns else ""
    date = pd.to_datetime(df["DATE"], errors="coerce")
    ratio = pd.to_numeric(df["P/C Ratio"], errors="coerce")
    calls = (
        pd.to_numeric(df[call_col], errors="coerce")
        if call_col
        else pd.Series(index=df.index, dtype="float64")
    )
    puts = (
        pd.to_numeric(df[put_col], errors="coerce")
        if put_col
        else pd.Series(index=df.index, dtype="float64")
    )
    clean = pd.DataFrame({"date": date, "pc_ratio": ratio, "calls": calls, "puts": puts}).dropna(
        subset=["date", "pc_ratio"]
    )
    clean = clean[clean["pc_ratio"] > 0].sort_values("date")
    if clean.empty:
        return {
            "key": source.get("key"),
            "label": source.get("label"),
            "status": "missing",
            "signal": "unknown",
            "note": "No valid Cboe put/call observations.",
        }
    latest = clean.iloc[-1]
    recent = clean.tail(20)
    ratio_latest = _float_value(latest["pc_ratio"], default=math.nan)
    avg_5d = float(clean["pc_ratio"].tail(5).mean()) if len(clean) >= 5 else None
    avg_20d = float(recent["pc_ratio"].mean()) if len(recent) else None
    pct_vs_20d = ((ratio_latest / avg_20d) - 1.0) if avg_20d and avg_20d > 0 else None
    signal = _cboe_put_call_signal(str(source.get("key") or ""), ratio_latest, avg_20d)
    return {
        "key": source.get("key"),
        "label": source.get("label"),
        "status": "ok",
        "signal": signal,
        "latest_date": str(pd.Timestamp(latest["date"]).date()),
        "pc_ratio": _clean_value(round(ratio_latest, 4)),
        "avg_5d": _clean_value(round(avg_5d, 4) if avg_5d is not None else None),
        "avg_20d": _clean_value(round(avg_20d, 4) if avg_20d is not None else None),
        "pct_vs_20d": _clean_value(round(pct_vs_20d, 4) if pct_vs_20d is not None else None),
        "calls": _clean_value(
            int(latest["calls"])
            if math.isfinite(_float_value(latest["calls"], default=math.nan))
            else None
        ),
        "puts": _clean_value(
            int(latest["puts"])
            if math.isfinite(_float_value(latest["puts"], default=math.nan))
            else None
        ),
        "rows": int(len(clean)),
        "source": "cboe_put_call_ratio_csv",
        "quality": "informational_delayed",
    }


def _cboe_put_call_signal(key: str, ratio: float, avg_20d: float | None) -> str:
    if not math.isfinite(ratio):
        return "unknown"
    high = 1.10 if key != "equity" else 0.85
    low = 0.70 if key != "equity" else 0.55
    if ratio >= high:
        return "defensive_hedging"
    if ratio <= low:
        return "call_demand_high"
    if avg_20d and avg_20d > 0:
        if ratio >= avg_20d * 1.15:
            return "hedging_rising"
        if ratio <= avg_20d * 0.85:
            return "call_demand_rising"
    return "balanced"


def _fetch_cboe_put_call_snapshot(
    source: dict[str, Any], cache_age: int = 6 * 3600
) -> dict[str, Any]:
    key = f"cboe_put_call_ratio:{source.get('key')}"
    cached = data_provider.cache_get(key, cache_age)
    if isinstance(cached, dict) and cached:
        return cached
    request = Request(
        str(source.get("url")),
        headers={
            "User-Agent": "Mozilla/5.0 Optedge research cockpit",
            "Accept": "text/csv,*/*",
        },
    )
    with urlopen(request, timeout=12) as response:
        text = response.read().decode("utf-8", "replace")
    parsed = _parse_cboe_put_call_csv(text, source)
    data_provider.cache_put(key, parsed)
    return parsed


def _cboe_put_call_stale(row: dict[str, Any], max_age_days: int = 10) -> bool:
    if row.get("status") != "ok":
        return True
    date_text = str(row.get("latest_date") or "")
    try:
        latest = pd.to_datetime(date_text, utc=True).date()
    except Exception:
        return True
    age_days = (datetime.now(UTC).date() - latest).days
    return age_days > max_age_days


def _parse_cboe_daily_put_call_ratios(text: str) -> dict[str, float]:
    search_text = str(text or "").replace('\\"', '"')
    patterns = {
        "total": r'"name"\s*:\s*"TOTAL PUT/CALL RATIO"\s*,\s*"value"\s*:\s*"([0-9.]+)"',
        "index": r'"name"\s*:\s*"INDEX PUT/CALL RATIO"\s*,\s*"value"\s*:\s*"([0-9.]+)"',
        "equity": r'"name"\s*:\s*"EQUITY PUT/CALL RATIO"\s*,\s*"value"\s*:\s*"([0-9.]+)"',
    }
    out: dict[str, float] = {}
    for key, pattern in patterns.items():
        match = re.search(pattern, search_text)
        if not match:
            continue
        value = _float_value(match.group(1), default=math.nan)
        if math.isfinite(value) and value > 0:
            out[key] = value
    return out


def _fetch_cboe_daily_put_call_ratios(cache_age: int = 30 * 60) -> dict[str, float]:
    cached = data_provider.cache_get("cboe_daily_put_call_ratios", cache_age)
    if isinstance(cached, dict) and cached:
        return {str(k): float(v) for k, v in cached.items()}
    request = Request(
        CBOE_DAILY_STATS_URL,
        headers={
            "User-Agent": "Mozilla/5.0 Optedge research cockpit",
            "Accept": "text/html,*/*",
        },
    )
    with urlopen(request, timeout=12) as response:
        text = response.read().decode("utf-8", "replace")
    out = _parse_cboe_daily_put_call_ratios(text)
    if out:
        data_provider.cache_put("cboe_daily_put_call_ratios", out)
    return out


def _daily_put_call_row(source: dict[str, Any], ratio: float, note: str) -> dict[str, Any]:
    return {
        "key": source.get("key"),
        "label": source.get("label"),
        "status": "ok",
        "signal": _cboe_put_call_signal(str(source.get("key") or ""), ratio, None),
        "latest_date": str(datetime.now(UTC).date()),
        "pc_ratio": _clean_value(round(ratio, 4)),
        "avg_5d": None,
        "avg_20d": None,
        "pct_vs_20d": None,
        "calls": None,
        "puts": None,
        "rows": None,
        "source": "cboe_daily_market_statistics",
        "quality": "informational_delayed",
        "note": note,
    }


def _options_sentiment_regime(rows: list[dict[str, Any]]) -> str:
    ok_rows = [row for row in rows if row.get("status") == "ok"]
    if not ok_rows:
        return "unknown"
    defensive = sum(
        str(row.get("signal")) in {"defensive_hedging", "hedging_rising"} for row in ok_rows
    )
    call_demand = sum(
        str(row.get("signal")) in {"call_demand_high", "call_demand_rising"} for row in ok_rows
    )
    if defensive >= 2:
        return "defensive_hedging"
    if call_demand >= 2:
        return "call_demand_high"
    if defensive > call_demand:
        return "hedging_rising"
    if call_demand > defensive:
        return "call_demand_rising"
    return "balanced"


def build_options_sentiment(data_dir: Path = DATA_DIR) -> dict[str, Any]:
    """Build Cboe market-wide options sentiment from no-key statistics."""
    del data_dir
    rows: list[dict[str, Any]] = []
    warnings: list[str] = []
    daily_ratios: dict[str, float] = {}
    for source in CBOE_PUT_CALL_SOURCES:
        try:
            row = _fetch_cboe_put_call_snapshot(source)
        except Exception as exc:
            row = {
                "key": source.get("key"),
                "label": source.get("label"),
                "status": "error",
                "signal": "unknown",
                "note": str(exc)[:180],
            }
        if _cboe_put_call_stale(row):
            try:
                if not daily_ratios:
                    daily_ratios = _fetch_cboe_daily_put_call_ratios()
                ratio = daily_ratios.get(str(source.get("key")))
                if ratio is not None:
                    row = _daily_put_call_row(
                        source,
                        ratio,
                        "Archive CSV was stale or unavailable; using Cboe daily market statistics.",
                    )
                else:
                    row["status"] = "stale" if row.get("status") == "ok" else row.get("status")
                    row["note"] = (
                        f"{row.get('note') or 'Archive snapshot stale'}; daily fallback unavailable."[
                            :220
                        ]
                    )
            except Exception as exc:
                row["status"] = "stale" if row.get("status") == "ok" else row.get("status")
                row["note"] = (
                    f"{row.get('note') or 'Archive snapshot stale'}; daily fallback failed: {exc}"[
                        :220
                    ]
                )
        rows.append({k: _clean_value(v) for k, v in row.items()})
        if row.get("status") != "ok":
            warnings.append(f"{source.get('label')} put/call unavailable.")
    ok_count = sum(1 for row in rows if row.get("status") == "ok")
    by_key = {str(row.get("key")): row for row in rows}
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "source": "Cboe market statistics and put/call ratio CSV",
        "status": "ok" if ok_count else "missing",
        "regime": _options_sentiment_regime(rows),
        "coverage": f"{ok_count}/{len(CBOE_PUT_CALL_SOURCES)}",
        "total_pc": by_key.get("total", {}).get("pc_ratio"),
        "equity_pc": by_key.get("equity", {}).get("pc_ratio"),
        "index_pc": by_key.get("index", {}).get("pc_ratio"),
        "rows": rows,
        "warnings": warnings,
        "notes": [
            "Cboe put/call ratios are market-wide options sentiment context.",
            "Data is informational/delayed and should not be treated as an execution quote.",
        ],
    }


def _risk_score_from_market_rows(rows: list[dict[str, Any]]) -> float:
    total_weight = 0.0
    score = 0.0
    weights = {
        str(item["symbol"]).upper(): _float_value(item.get("risk_weight"))
        for item in MARKET_PULSE_SYMBOLS
    }
    for row in rows:
        if row.get("status") != "ok":
            continue
        symbol = str(row.get("symbol") or "").upper()
        weight = weights.get(symbol, 0.0)
        ret_20d = _float_value(row.get("ret_20d"), default=math.nan)
        if not math.isfinite(ret_20d) or weight == 0:
            continue
        clipped = max(-0.08, min(0.08, ret_20d)) / 0.08
        score += clipped * weight
        total_weight += abs(weight)
    return score / total_weight if total_weight else 0.0


def _market_regime_label(score: float, rows: list[dict[str, Any]]) -> str:
    vix_row = next((row for row in rows if row.get("symbol") == "^VIX"), None)
    vix_20d = _float_value(vix_row.get("ret_20d"), default=0.0) if vix_row else 0.0
    if score >= 0.30 and vix_20d < 0.15:
        return "risk_on"
    if score <= -0.25 or vix_20d > 0.20:
        return "risk_off"
    if score >= 0.10:
        return "constructive"
    if score <= -0.10:
        return "defensive"
    return "mixed"


def build_market_pulse(data_dir: Path = DATA_DIR, period: str = "6mo") -> dict[str, Any]:
    """Build a free no-key market regime snapshot for swing-trade context."""
    rows: list[dict[str, Any]] = []
    warnings: list[str] = []
    for spec in MARKET_PULSE_SYMBOLS:
        try:
            history = data_provider.get_history(
                spec["symbol"], period=period, interval="1d", cache_age=1800
            )
            row = _market_pulse_row(spec, history)
        except Exception as exc:
            row = {
                "symbol": spec["symbol"],
                "label": spec["label"],
                "kind": spec["kind"],
                "status": "error",
                "trend": "unknown",
                "note": str(exc)[:160],
            }
        rows.append(row)
        if row.get("status") != "ok":
            warnings.append(f"{row['symbol']} history unavailable.")

    risk_score = _risk_score_from_market_rows(rows)
    regime = _market_regime_label(risk_score, rows)
    leaders = sorted(
        [row for row in rows if row.get("status") == "ok"],
        key=lambda row: _float_value(row.get("ret_20d"), default=-999.0),
        reverse=True,
    )[:3]
    laggards = sorted(
        [row for row in rows if row.get("status") == "ok"],
        key=lambda row: _float_value(row.get("ret_20d"), default=999.0),
    )[:3]
    options_sentiment = build_options_sentiment(data_dir)
    warnings.extend(options_sentiment.get("warnings") or [])
    return {
        "generated_at": datetime.now(UTC).isoformat(),
        "period": period,
        "regime": regime,
        "risk_score": _clean_value(round(risk_score, 4)),
        "coverage": f"{sum(1 for row in rows if row.get('status') == 'ok')}/{len(rows)}",
        "options_sentiment": options_sentiment,
        "rows": [{k: _clean_value(v) for k, v in row.items()} for row in rows],
        "leaders": [{k: _clean_value(v) for k, v in row.items()} for row in leaders],
        "laggards": [{k: _clean_value(v) for k, v in row.items()} for row in laggards],
        "warnings": warnings,
        "notes": [
            "Market Pulse uses free/no-key historical price providers through data_provider.get_history.",
            "It gives regime context for swing-trade review; it is not a trading signal by itself.",
            "VIX and ETF proxies may be delayed or unavailable depending on the free source.",
        ],
    }


