def _loopback_request_host(value: Any) -> bool:
    raw = str(value or "").strip()
    if not raw:
        return False
    parsed = urlparse(f"//{raw}")
    return str(parsed.hostname or "").lower() in {"127.0.0.1", "localhost", "::1"}


def _post_request_rejection(headers: Any) -> str | None:
    """Fail closed for every local mutation request."""
    host = str(headers.get("Host") or "").strip().lower()
    if not _loopback_request_host(host):
        return "The request Host is not an allowed loopback address."
    content_type = str(headers.get("Content-Type") or "").split(";", 1)[0].strip().lower()
    if content_type != "application/json":
        return "Content-Type must be application/json."
    supplied = str(headers.get("X-Optedge-CSRF") or "")
    if not supplied or not secrets.compare_digest(supplied, COCKPIT_CSRF_TOKEN):
        return "Missing or invalid local mutation token. Reload the cockpit."
    origin = str(headers.get("Origin") or "").strip()
    if origin:
        parsed = urlparse(origin)
        if (
            parsed.scheme not in {"http", "https"}
            or not _loopback_request_host(parsed.netloc)
            or parsed.netloc.lower() != host
        ):
            return "Cross-origin mutation requests are not allowed."
    return None


def _build_and_save_lookup_report(symbol: str, data_dir: Path) -> dict[str, Any]:
    """Run and persist one interactive lookup after the HTTP mutation gate."""
    report = lookup_symbol(
        symbol,
        data_dir,
        **rich_lookup_kwargs(),
    )
    try:
        paths = save_lookup(report, data_dir)
        archive_rel = str(paths["archive_html"].relative_to(data_dir))
        latest_rel = str(paths["html"].relative_to(data_dir))
        report["saved_lookup"] = {
            "html_path": str(paths["html"]),
            "json_path": str(paths["json"]),
            "archive_html_path": str(paths["archive_html"]),
            "archive_json_path": str(paths["archive_json"]),
            "history_path": str(paths["history"]),
            "report_url": _lookup_report_url(archive_rel),
            "latest_report_url": _lookup_report_url(latest_rel),
        }
    except Exception as exc:
        report["saved_lookup"] = {
            "error": f"lookup result was not saved: {str(exc)[:160]}",
        }
    return report


def _robinhood_connection_unavailable_status() -> dict[str, Any]:
    """Return a stable, non-secret status when the local connector is absent."""
    return {
        "schema": "optedge_robinhood_connection_manager_v1",
        "connection_state": "error",
        "connect_pending": False,
        "authorization_url_ready": False,
        "last_error_code": "client_unavailable",
        "status_probe_error_code": None,
        "loop_thread_alive": False,
        "loop_thread_count": 0,
        "shutdown": False,
        "automatic_retry_enabled": False,
        "background_polling_enabled": False,
        "generic_tool_call_exposed": False,
        "placement_api_exposed": False,
        "account_data_persisted": False,
        "client": {},
    }


def _robinhood_oauth_page(*, accepted: bool, detail: str) -> bytes:
    """Build a static callback page that never echoes OAuth query material."""
    title = (
        "Robinhood authorization received" if accepted else "Robinhood authorization not accepted"
    )
    tone = "#20c997" if accepted else "#ffb84d"
    safe_detail = html_escape(str(detail or ""))
    return f"""<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="referrer" content="no-referrer"><title>{title}</title>
<style>body{{margin:0;background:#090b0b;color:#eef4f1;font:16px/1.5 system-ui,sans-serif}}main{{max-width:680px;margin:10vh auto;padding:30px;border:1px solid #26302d;border-radius:18px;background:#111514}}h1{{color:{tone};font-size:26px}}a{{display:inline-block;margin-top:18px;padding:10px 14px;border-radius:9px;background:#20c997;color:#07100d;text-decoration:none;font-weight:700}}p{{color:#bac7c1}}</style>
</head><body><main><h1>{title}</h1><p>{safe_detail}</p><p>No order was reviewed, submitted, or placed.</p><a href="/">Return to Optedge</a></main>
<script>history.replaceState({{}}, '', '/oauth/robinhood/callback');</script></body></html>""".encode()


class CockpitHandler(BaseHTTPRequestHandler):
    data_dir = DATA_DIR
    robinhood_connection_manager: RobinhoodConnectionManager | None = None
    robinhood_option_execution_service: RobinhoodOptionExecutionService | None = None

    def _send(self, status: int, body: bytes, content_type: str) -> None:
        self.send_response(status)
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(len(body)))
        self.send_header("Cache-Control", "no-store")
        self.send_header("Referrer-Policy", "no-referrer")
        self.send_header("X-Content-Type-Options", "nosniff")
        self.end_headers()
        self.wfile.write(body)

    def _send_json(self, obj: Any, status: int = 200) -> None:
        self._send(status, _json_bytes(obj), "application/json; charset=utf-8")

    def _send_file(self, path: Path, content_type: str | None = None) -> None:
        if not path.exists() or not path.is_file():
            self._send(404, b"Not found", "text/plain; charset=utf-8")
            return
        if content_type is None:
            content_type = mimetypes.guess_type(path.name)[0] or "application/octet-stream"
        self._send(200, path.read_bytes(), content_type)

    def do_GET(self) -> None:  # noqa: N802 - stdlib handler API
        if not _loopback_request_host(self.headers.get("Host")):
            self._send(421, b"Loopback Host required", "text/plain; charset=utf-8")
            return
        parsed = urlparse(self.path)
        if parsed.path == "/":
            self._send(200, render_cockpit_html().encode("utf-8"), "text/html; charset=utf-8")
            return
        if parsed.path == "/auth/robinhood/authorize":
            manager = self.robinhood_connection_manager
            if manager is None:
                self._send(
                    503,
                    _robinhood_oauth_page(
                        accepted=False,
                        detail="The local Robinhood connector is unavailable. Return to Optedge and review status.",
                    ),
                    "text/html; charset=utf-8",
                )
                return
            try:
                location = manager.authorization_url_for_browser()
                if "\r" in location or "\n" in location:
                    raise RobinhoodConnectionError("authorization_url_invalid")
            except Exception:
                self._send(
                    409,
                    _robinhood_oauth_page(
                        accepted=False,
                        detail="Robinhood approval is not ready. Return to Optedge, refresh connection status once, and try again.",
                    ),
                    "text/html; charset=utf-8",
                )
                return
            self.send_response(302)
            self.send_header("Location", location)
            self.send_header("Cache-Control", "no-store")
            self.send_header("Referrer-Policy", "no-referrer")
            self.send_header("X-Content-Type-Options", "nosniff")
            self.send_header("Content-Length", "0")
            self.end_headers()
            return
        if parsed.path == "/oauth/robinhood/callback":
            manager = self.robinhood_connection_manager
            if manager is None:
                self._send(
                    503,
                    _robinhood_oauth_page(
                        accepted=False,
                        detail="The local Robinhood connector is unavailable. Start a new connection from Optedge.",
                    ),
                    "text/html; charset=utf-8",
                )
                return
            callback_url = manager.callback_uri
            if parsed.query:
                callback_url = f"{callback_url}?{parsed.query}"
            try:
                manager.submit_oauth_callback(callback_url)
            except Exception:
                self._send(
                    400,
                    _robinhood_oauth_page(
                        accepted=False,
                        detail="The callback was invalid, expired, denied, or already used. Start a new connection from Optedge.",
                    ),
                    "text/html; charset=utf-8",
                )
                return
            self._send(
                200,
                _robinhood_oauth_page(
                    accepted=True,
                    detail="Return to Optedge and refresh connection status once. The OAuth exchange will finish in the existing bounded connection attempt.",
                ),
                "text/html; charset=utf-8",
            )
            return
        if parsed.path == "/api/robinhood-connection":
            manager = self.robinhood_connection_manager
            self._send_json(
                manager.status()
                if manager is not None
                else _robinhood_connection_unavailable_status()
            )
            return
        if parsed.path == "/api/summary":
            self._send_json(build_summary(self.data_dir))
            return
        if parsed.path == "/api/trade-desk":
            self._send_json(build_trade_desk(self.data_dir))
            return
        if parsed.path == "/api/edge-lab":
            self._send_json(build_edge_lab_report(self.data_dir))
            return
        if parsed.path == "/api/command-center":
            self._send_json(build_command_center(self.data_dir))
